const SEGMENTED_CONTROL_SELECTORS = [
  ".queue-view-tabs",
  ".database-library-tabs",
  ".database-sample-view-tabs",
  ".admin-section-tabs",
  ".project-management-tabs",
];

let segmentedControlFrame = 0;

function syncSegmentedControls(root = document) {
  const scope = root instanceof Element || root instanceof Document ? root : document;
  if (scope instanceof Element && scope.matches(SEGMENTED_CONTROL_SELECTORS.join(","))) {
    updateSegmentedControlIndicator(scope);
  }
  scope.querySelectorAll(SEGMENTED_CONTROL_SELECTORS.join(",")).forEach(updateSegmentedControlIndicator);
}

function scheduleSegmentedControlsSync(root = document) {
  if (segmentedControlFrame) {
    window.cancelAnimationFrame(segmentedControlFrame);
  }
  segmentedControlFrame = window.requestAnimationFrame(() => {
    segmentedControlFrame = 0;
    syncSegmentedControls(root);
  });
}

function updateSegmentedControlIndicator(container) {
  if (!(container instanceof HTMLElement)) return;
  const active = Array.from(container.children).find((item) => (
    item instanceof HTMLElement
    && item.matches(".active, [aria-selected='true']")
    && item.offsetParent !== null
  ));
  if (!(active instanceof HTMLElement)) return;
  const containerRect = container.getBoundingClientRect();
  const activeRect = active.getBoundingClientRect();
  if (!containerRect.width || !activeRect.width) return;
  container.style.setProperty("--segment-x", `${activeRect.left - containerRect.left}px`);
  container.style.setProperty("--segment-w", `${activeRect.width}px`);
  container.classList.add("segment-ready");
}

window.addEventListener("resize", () => scheduleSegmentedControlsSync());
window.addEventListener("beforeunload", (event) => {
  if (!state.virusReportTemplateDirty) return;
  event.preventDefault();
  event.returnValue = "";
});

function bindImeSafeInput(input, onCommit) {
  if (!(input instanceof HTMLInputElement) || typeof onCommit !== "function") return;
  input.addEventListener("compositionstart", () => {
    input.dataset.imeComposing = "1";
  });
  input.addEventListener("compositionend", () => {
    input.dataset.imeComposing = "0";
    onCommit(input);
  });
  input.addEventListener("input", (event) => {
    if (event.isComposing || input.dataset.imeComposing === "1") return;
    onCommit(input);
  });
  input.addEventListener("keydown", (event) => {
    if (input.dataset.imeComposing === "1" || event.isComposing) return;
    if (event.key === "Enter") {
      event.preventDefault();
      onCommit(input);
      return;
    }
    if (event.key === "Escape" && input.value) {
      event.preventDefault();
      input.value = "";
      onCommit(input);
    }
  });
}

function renderTableFilterInput({
  value = "",
  placeholder = "筛选",
  dataName = "",
  dataValue = "",
  clearDataName = "",
  extraAttrs = "",
} = {}) {
  const currentValue = String(value ?? "");
  const hasFilter = Boolean(currentValue.trim());
  const dataAttr = dataName ? ` ${dataName}="${escapeHtml(dataValue)}"` : "";
  const clearAttr = clearDataName ? ` ${clearDataName}="${escapeHtml(dataValue)}"` : "";
  return `
    <div class="table-filter-wrap ${hasFilter ? "has-filter" : ""}">
      <input
        class="queue-table-filter-input"
        type="text"
        value="${escapeHtml(currentValue)}"
        placeholder="${escapeHtml(placeholder)}"
        autocomplete="off"
        spellcheck="false"${dataAttr}${extraAttrs ? ` ${extraAttrs}` : ""}
      >
      ${clearDataName ? `
        <button
          class="table-filter-clear-button ${hasFilter ? "" : "is-hidden"}"
          type="button"
          title="清空筛选"
          aria-label="清空筛选"${clearAttr}
        >×</button>
      ` : ""}
    </div>
  `;
}

