function renderOperationResult(target, {
  title = "操作已完成",
  status = "success",
  message = "",
  metrics = [],
  details = [],
  dismissible = false,
  dismissLabel = "关闭提示",
} = {}) {
  if (!(target instanceof HTMLElement)) return;
  const normalizedStatus = ["success", "warning", "error", "pending"].includes(status) ? status : "success";
  const metricItems = Array.isArray(metrics) ? metrics.filter(Boolean) : [];
  const detailItems = Array.isArray(details) ? details.filter(Boolean) : [];
  target.className = `operation-result-card operation-result-${normalizedStatus}`;
  target.innerHTML = `
    <div class="operation-result-topline">
      <div class="operation-result-head">
        <span>${escapeHtml(normalizedStatus === "pending" ? "处理中" : normalizedStatus === "error" ? "未完成" : normalizedStatus === "warning" ? "需要关注" : "已完成")}</span>
        <strong>${escapeHtml(title)}</strong>
        ${message ? `<p>${escapeHtml(message)}</p>` : ""}
      </div>
      ${dismissible ? `
        <button class="operation-result-dismiss" type="button" aria-label="${escapeHtml(dismissLabel)}">
          ${escapeHtml(dismissLabel)}
        </button>
      ` : ""}
    </div>
    ${metricItems.length ? `
      <div class="operation-result-metrics">
        ${metricItems.map((item) => `
          <article>
            <span>${escapeHtml(item.label || "")}</span>
            <strong>${escapeHtml(String(item.value ?? "-"))}</strong>
          </article>
        `).join("")}
      </div>
    ` : ""}
    ${detailItems.length ? `
      <ul class="operation-result-details">
        ${detailItems.map((item) => `<li>${escapeHtml(String(item))}</li>`).join("")}
      </ul>
    ` : ""}
  `;
  if (dismissible) {
    target.querySelector(".operation-result-dismiss")?.addEventListener("click", () => {
      target.className = "operation-result-card hidden";
      target.innerHTML = "";
    });
  }
}

function getErrorMessage(error, fallback = "操作失败") {
  return error instanceof Error ? error.message : String(error || fallback);
}

function renderOperationError(target, {
  title = "操作未完成",
  error = null,
  recovery = [],
  metrics = [],
} = {}) {
  renderOperationResult(target, {
    title,
    status: "error",
    message: getErrorMessage(error, "当前操作失败。"),
    metrics,
    details: Array.isArray(recovery) && recovery.length
      ? recovery
      : ["请检查输入内容或文件路径后重试。", "如果问题仍然存在，请保留当前错误信息并联系管理员。"],
  });
}

function setButtonEnabled(button, enabled) {
  if (button instanceof HTMLButtonElement) {
    button.disabled = !enabled;
  }
}

async function withOperationRecovery(target, config, action) {
  try {
    return await action();
  } catch (error) {
    renderOperationError(target, { ...config, error });
    throw error;
  }
}

function getFileExtension(name = "") {
  const normalized = String(name || "").trim().toLowerCase();
  if (normalized.endsWith(".tar.gz")) return "tar.gz";
  if (normalized.endsWith(".fasta.gz")) return "fasta.gz";
  if (normalized.endsWith(".fna.gz")) return "fna.gz";
  if (normalized.endsWith(".fa.gz")) return "fa.gz";
  const match = normalized.match(/\.([^.]+)$/);
  return match ? match[1] : "";
}

function validateImportFile(upload, {
  allowedExtensions = [],
  label = "导入文件",
  target = null,
  recovery = [],
} = {}) {
  if (!upload) {
    renderOperationError(target, {
      title: `${label}未选择`,
      error: `请先选择${label}。`,
      recovery: recovery.length ? recovery : ["点击“选择文件”后重新提交。"],
    });
    return false;
  }
  const extension = getFileExtension(upload.name);
  const allowed = allowedExtensions.map((item) => String(item || "").toLowerCase());
  if (allowed.length && !allowed.includes(extension)) {
    renderOperationError(target, {
      title: `${label}格式不支持`,
      error: `${upload.name} 的文件格式不在允许范围内。`,
      recovery: [
        `请使用 ${allowed.map((item) => `.${item}`).join("、")} 格式。`,
        ...recovery,
      ],
      metrics: [{ label, value: upload.name }],
    });
    return false;
  }
  if (Number(upload.size || 0) <= 0) {
    renderOperationError(target, {
      title: `${label}为空文件`,
      error: `${upload.name} 没有可导入内容。`,
      recovery: ["请重新导出或重新选择非空文件。", ...recovery],
      metrics: [{ label, value: upload.name }],
    });
    return false;
  }
  return true;
}

function formatFileSize(bytes = 0) {
  const value = Number(bytes || 0);
  if (!Number.isFinite(value) || value <= 0) return "0 B";
  const units = ["B", "KB", "MB", "GB"];
  let size = value;
  let unitIndex = 0;
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex += 1;
  }
  return `${size >= 10 || unitIndex === 0 ? Math.round(size) : size.toFixed(1)} ${units[unitIndex]}`;
}

function parseDelimitedHeaderLine(text = "", delimiter = ",") {
  const firstLine = String(text || "").split(/\r?\n/).find((line) => line.trim()) || "";
  const headers = [];
  let current = "";
  let quoted = false;
  for (let index = 0; index < firstLine.length; index += 1) {
    const char = firstLine[index];
    const next = firstLine[index + 1];
    if (char === '"' && quoted && next === '"') {
      current += '"';
      index += 1;
      continue;
    }
    if (char === '"') {
      quoted = !quoted;
      continue;
    }
    if (char === delimiter && !quoted) {
      headers.push(current.trim().replace(/^\ufeff/, ""));
      current = "";
      continue;
    }
    current += char;
  }
  headers.push(current.trim().replace(/^\ufeff/, ""));
  return headers.filter(Boolean);
}

async function readDelimitedHeaders(upload, extension) {
  if (!upload || !["csv", "tsv"].includes(extension)) return [];
  const text = await upload.text();
  return parseDelimitedHeaderLine(text, extension === "tsv" ? "\t" : ",");
}

async function renderImportFilePrecheck(target, upload, {
  label = "导入文件",
  allowedExtensions = SPREADSHEET_IMPORT_EXTENSIONS,
  templateHint = "建议使用当前页面提供的模板重新导出。",
  requiredColumns = [],
} = {}) {
  if (!(target instanceof HTMLElement)) return;
  if (!upload) {
    target.className = "operation-result-card operation-result-pending import-precheck-card hidden";
    target.innerHTML = "";
    return { status: "empty", canSubmit: false };
  }
  const extension = getFileExtension(upload.name);
  const allowed = allowedExtensions.map((item) => String(item || "").toLowerCase());
  const details = [];
  const metrics = [
    { label: "文件名", value: upload.name },
    { label: "格式", value: extension ? `.${extension}` : "未知" },
    { label: "大小", value: formatFileSize(upload.size) },
  ];
  let status = "success";
  let message = "文件级预检通过，可以继续提交导入。";
  if (allowed.length && !allowed.includes(extension)) {
    status = "error";
    message = "文件格式不在允许范围内，当前文件不会被提交。";
    details.push(`允许格式：${allowed.map((item) => `.${item}`).join("、")}`);
    details.push(templateHint);
  } else if (Number(upload.size || 0) <= 0) {
    status = "error";
    message = "当前文件为空文件，不能导入。";
    details.push("请重新导出或重新选择非空文件。");
  } else if (["csv", "tsv"].includes(extension) && requiredColumns.length) {
    try {
      const headers = await readDelimitedHeaders(upload, extension);
      const headerSet = new Set(headers.map((item) => String(item || "").trim()));
      const missingColumns = requiredColumns.filter((column) => !headerSet.has(column));
      metrics.push({ label: "识别列数", value: headers.length });
      if (!headers.length) {
        status = "error";
        message = "未识别到表头，当前文件不能导入。";
        details.push("请确认第一行是字段 key，而不是中文说明或空行。");
      } else if (missingColumns.length) {
        status = "error";
        message = "字段级预检未通过，缺少关键列。";
        details.push(`缺少关键列：${missingColumns.join("、")}`);
        details.push(templateHint);
      } else {
        message = "文件级和字段级预检通过，可以继续提交导入。";
        details.push(`已识别关键列：${requiredColumns.join("、")}`);
        details.push("后端仍会继续检查必填字段内容、标准词表和路径可访问性。");
      }
    } catch (error) {
      status = "warning";
      message = "文件可读取性需要复核，字段级预检未完成。";
      details.push(getErrorMessage(error, "读取表头失败。"));
      details.push("仍可提交给后端做完整预检和导入。");
    }
  } else if (extension === "xlsx" && requiredColumns.length) {
    status = "warning";
    message = "XLSX 文件级预检通过，字段级检查将在提交后由后端完成。";
    details.push(`关键列应包含：${requiredColumns.join("、")}`);
    details.push(templateHint);
  } else {
    details.push("下一步后端会继续检查字段名、必填字段、标准词表和路径可访问性。");
    details.push(templateHint);
  }
  renderOperationResult(target, {
    title: `${label}预检${status === "error" ? "未通过" : "通过"}`,
    status,
    message,
    metrics,
    details,
  });
  return { status, canSubmit: status !== "error" };
}

function renderServerImportPrecheck(target, result, { label = "导入文件" } = {}) {
  const issueCount = Number(result?.issue_count || 0);
  const missingColumns = Array.isArray(result?.missing_columns) ? result.missing_columns : [];
  const issues = Array.isArray(result?.issues) ? result.issues : [];
  const canImport = Boolean(result?.can_import);
  const details = [];
  if (missingColumns.length) {
    details.push(`缺少关键列：${missingColumns.join("、")}`);
  }
  issues.slice(0, 8).forEach((item) => {
    details.push(`第 ${item.row || "-"} 行：${item.reason || "未通过预检"}`);
  });
  if (result?.truncated) {
    details.push("还有更多问题行未展示，请下载模板修正后重新预检。");
  }
  if (!details.length) {
    details.push("后端已使用真实导入解析逻辑完成字段、空行、路径和词表预检。");
  }
  if (canImport && Number(result?.precheck_ttl_seconds || 0) > 0) {
    details.push(`预检快照将在 ${Math.round(Number(result.precheck_ttl_seconds) / 60)} 分钟内有效，正式导入会复用这份已验证文件。`);
  }
  renderOperationResult(target, {
    title: `${label}后端预检${canImport ? "通过" : "未通过"}`,
    status: canImport ? "success" : "error",
    message: canImport ? "文件已生成预检快照，可以进入正式导入。" : "请先修正预检问题，再重新选择文件或提交预检。",
    metrics: [
      { label: "有效行", value: result?.valid_rows ?? 0 },
      { label: "问题行", value: issueCount },
      { label: "空行", value: result?.empty_rows ?? 0 },
      { label: "识别列", value: Array.isArray(result?.headers) ? result.headers.length : 0 },
    ],
    details,
  });
  return {
    status: canImport ? "success" : "error",
    canSubmit: canImport,
    precheckId: canImport ? String(result?.precheck_id || "") : "",
  };
}

async function runServerImportPrecheck({
  endpoint,
  upload,
  target,
  label,
  extraFields = {},
} = {}) {
  if (!upload) return { status: "empty", canSubmit: false };
  renderOperationResult(target, {
    title: `${label}正在进行后端预检`,
    status: "pending",
    message: "正在使用后端真实解析逻辑检查字段、路径和词表。",
    metrics: [
      { label: "文件名", value: upload.name },
      { label: "大小", value: formatFileSize(upload.size) },
    ],
  });
  const formData = new FormData();
  formData.append("file", upload);
  Object.entries(extraFields || {}).forEach(([key, value]) => {
    formData.append(key, String(value ?? ""));
  });
  const result = await requestJson(endpoint, {
    method: "POST",
    body: formData,
  });
  return renderServerImportPrecheck(target, result, { label });
}

function validateLocalPathPrecheck(input, {
  fieldId = "",
  label = "文件路径",
  allowedExtensions = [],
  target = null,
  required = true,
  recovery = [],
} = {}) {
  const value = String(input?.value || "").trim();
  if (!value) {
    if (required) {
      markFieldInvalid(input, fieldId, `请填写或选择${label}。`);
      renderOperationError(target, {
        title: `${label}缺失`,
        error: `请填写或选择${label}。`,
        recovery: recovery.length ? recovery : ["点击路径选择器选择服务器可访问的文件。"],
      });
      input?.focus();
      return false;
    }
    return true;
  }
  const extension = getFileExtension(value);
  const allowed = allowedExtensions.map((item) => String(item || "").toLowerCase());
  if (allowed.length && !allowed.includes(extension)) {
    markFieldInvalid(input, fieldId, `${label}格式不支持。`);
    renderOperationError(target, {
      title: `${label}格式不支持`,
      error: `${value} 的文件扩展名不在允许范围内。`,
      recovery: [
        `请使用 ${allowed.map((item) => `.${item}`).join("、")} 格式。`,
        ...recovery,
      ],
      metrics: [{ label, value }],
    });
    input?.focus();
    return false;
  }
  if (!value.startsWith("/") && !value.startsWith("~") && !/^[A-Za-z]:[\\/]/.test(value)) {
    renderOperationResult(target, {
      title: `${label}需要复核`,
      status: "warning",
      message: "当前路径不像服务器上的绝对路径，后端可能无法读取。",
      metrics: [{ label, value }],
      details: recovery.length ? recovery : ["建议通过“选择文件”按钮从服务器目录中选择文件。"],
    });
  }
  return true;
}

