async function loadReferenceData() {
  try {
    const [countries, chinaRegions, worldGeojson, chinaGeojson] = await Promise.all([
      requestJson("/static/data/countries.json"),
      requestJson("/static/data/china_regions.json"),
      requestJson("/static/data/world_countries.geojson").catch(() => null),
      requestJson("/static/data/china_full.geojson").catch(() => null),
    ]);
    COUNTRY_OPTIONS = Array.isArray(countries) ? countries : [];
    CHINA_REGION_TREE = chinaRegions && typeof chinaRegions === "object" ? chinaRegions : {};
    WORLD_GEOJSON = worldGeojson && typeof worldGeojson === "object" ? worldGeojson : null;
    CHINA_GEOJSON = chinaGeojson && typeof chinaGeojson === "object" ? chinaGeojson : null;
  } catch (_error) {
    COUNTRY_OPTIONS = [];
    CHINA_REGION_TREE = {};
    WORLD_GEOJSON = null;
    CHINA_GEOJSON = null;
  }
}

async function loadDatabaseMetadataTemplates() {
  try {
    const data = await requestJson("/api/database/metadata-templates");
    state.databaseMetadataTemplates = Array.isArray(data.items) ? data.items : [];
  } catch (_error) {
    state.databaseMetadataTemplates = [];
  }
}

async function loadSession() {
  const user = await requestJson("/api/session");
  state.currentUser = user;
  if (elements.currentUserChip) {
    const fullLabel = `${user.username} (${buildRoleLabel(user.role)})`;
    elements.currentUserChip.textContent = fullLabel;
    elements.currentUserChip.dataset.fullLabel = fullLabel;
    elements.currentUserChip.dataset.shortLabel = user.username || "用户";
    elements.currentUserChip.title = fullLabel;
    elements.currentUserChip.setAttribute("aria-label", fullLabel);
  }
  const isAdmin = user.role === "admin";
  elements.adminPanel.classList.toggle("hidden", !isAdmin);
  elements.databaseExtraTabButton.classList.toggle("hidden", !isAdmin);
  elements.adminTabButton.classList.toggle("hidden", !isAdmin);
  elements.auditPanel.classList.toggle("hidden", !isAdmin);
  elements.auditTabButton.classList.toggle("hidden", !isAdmin);
  if (!isAdmin && state.activeTab === "database-extra-tab") {
    setActiveTab("submission-tab");
  }
  if (!isAdmin && state.activeTab === "admin-tab") {
    setActiveTab("submission-tab");
  }
  if (!isAdmin && state.activeTab === "audit-tab") {
    setActiveTab("submission-tab");
  }
  syncAllowedWorkstationChoices();
}

async function onSubmitTask(event) {
  event.preventDefault();
  const stepOneMissing = getMissingStepOneFields();
  if (stepOneMissing.length) {
    state.submissionWizardStep = 1;
    markMissingFields(stepOneMissing);
    showToast(`请先补全：${stepOneMissing.map((field) => field.label).join("、")}`, "warning");
    focusFieldById(stepOneMissing[0].id);
    syncSubmissionStepState();
    return;
  }
  const stepTwoMissing = getMissingStepTwoFields();
  if (stepTwoMissing.length) {
    state.submissionWizardStep = 2;
    markMissingFields(stepTwoMissing);
    showToast(`请先补全：${stepTwoMissing.map((field) => field.label).join("、")}`, "warning");
    focusFieldById(stepTwoMissing[0].id);
    syncSubmissionStepState();
    return;
  }
  const stepThreeMissing = getMissingStepThreeFields();
  if (stepThreeMissing.length) {
    state.submissionWizardStep = 3;
    markMissingFields(stepThreeMissing);
    showToast(`请先补全：${stepThreeMissing.map((field) => field.label).join("、")}`, "warning");
    focusFieldById(stepThreeMissing[0].id);
    syncSubmissionStepState();
    return;
  }
  clearSubmissionValidation();
  const payload = collectFormPayload();
  await withSubmittingState(
    elements.submitButton,
    state.rebuildModalOpen && state.rebuildMode === "rerun" ? "续跑中..." : "启动中...",
    async () => {
      if (isPairedFastqSingleInput()) {
        const generatedInputPath = await buildFastqSingleInput(payload);
        payload.input_path = generatedInputPath;
        payload.inputtype = "@";
        document.getElementById("input_path").value = generatedInputPath;
      }
      const isRerun = state.rebuildModalOpen && state.rebuildMode === "rerun" && state.rebuildTaskId;
      const created = await requestJson(
        isRerun ? `/api/tasks/${encodeURIComponent(state.rebuildTaskId)}/rerun` : "/api/tasks",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        }
      );
      showToast(isRerun ? `任务已继续运行：${created.name}` : `任务已提交：${created.name}`);
      state.currentTaskDetail = null;
      state.selectedTaskId = created.id;
      state.taskDetailView = "result";
      await loadTasks();
      if (state.rebuildModalOpen) {
        closeRebuildModal();
      }
      setActiveTab("queue-tab");
      window.location.href = `/tasks/${encodeURIComponent(created.id)}/result-page`;
    },
  ).catch((error) => {
    showToast(error instanceof Error ? error.message : "任务提交失败", "error");
  });
}

async function buildFastqSingleInput(payload = {}) {
  const inputLeft = String(elements.metagenomeShortLeft?.value || "").trim();
  const inputRight = String(elements.metagenomeShortRight?.value || "").trim();
  if (!inputLeft) {
    throw new Error("请先填写二代左端输入路径");
  }
  if (state.fastqFolderBatch?.sourcePath === inputLeft && state.fastqFolderBatch?.batchPath) {
    return state.fastqFolderBatch.batchPath;
  }
  const data = await requestFastqSingleBatchInput(payload);
  applyFastqFolderBatchResult(inputLeft, data, { announce: Boolean(data.scanned_directory && Number(data.rows || 0) > 1) });
  return data.path || data.absolute_path || "";
}

async function requestFastqSingleBatchInput(payload = {}) {
  const inputLeft = String(elements.metagenomeShortLeft?.value || "").trim();
  const inputRight = String(elements.metagenomeShortRight?.value || "").trim();
  const data = await requestJson("/api/batch-inputs/fastq-single", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      task_name: String(payload.task_name || "").trim(),
      short_left: inputLeft,
      short_right: inputRight,
      species: "nolevel",
    }),
  });
  return data;
}

async function generateFastqFolderBatchPreview() {
  const inputLeft = String(elements.metagenomeShortLeft?.value || "").trim();
  if (!inputLeft) {
    showToast("请先选择二代左端文件夹。", "warning");
    return;
  }
  const payload = collectFormPayload();
  await withSubmittingState(elements.generateFastqFolderBatchButton, "生成中...", async () => {
    const data = await requestFastqSingleBatchInput(payload);
    applyFastqFolderBatchResult(inputLeft, data, { announce: true });
    if (elements.inputPath) {
      elements.inputPath.value = data.path || data.absolute_path || "";
    }
    syncSubmissionStepState();
  }).catch((error) => {
    showToast(error instanceof Error ? error.message : "批量 TSV 生成失败", "error");
  });
}

function applyFastqFolderBatchResult(sourcePath, data = {}, { announce = false } = {}) {
  const batchPath = data.path || data.absolute_path || "";
  if (!batchPath) return;
  state.fastqFolderBatch = {
    sourcePath,
    batchPath,
    rows: Number(data.rows || 0),
  };
  renderFastqFolderBatchNote({
    visible: Boolean(data.scanned_directory),
    generated: Boolean(data.scanned_directory),
    rows: Number(data.rows || 0),
    batchPath,
  });
  if (announce && data.scanned_directory) {
    showToast(`已从二代目录识别 ${data.rows || 0} 个样本并生成批量 TSV`);
  }
}

function renderFastqFolderBatchNote({ visible = false, generated = false, rows = 0, batchPath = "" } = {}) {
  const currentLeft = String(elements.metagenomeShortLeft?.value || "").trim();
  const sourceMatches = !state.fastqFolderBatch?.sourcePath || state.fastqFolderBatch.sourcePath === currentLeft;
  const shouldShow = Boolean(visible && currentLeft && sourceMatches && !looksLikeFilePath(currentLeft));
  elements.fastqFolderBatchNote?.classList.toggle("hidden", !shouldShow);
  if (!shouldShow) return;
  if (elements.fastqFolderBatchText) {
    elements.fastqFolderBatchText.textContent = generated
      ? `已识别 ${rows || 0} 个样本，批量 TSV 已生成。`
      : "已选择二代测序目录，可先生成批量 TSV 并确认识别结果。";
  }
  if (elements.generateFastqFolderBatchButton) {
    elements.generateFastqFolderBatchButton.classList.toggle("hidden", generated);
  }
  if (elements.fastqFolderBatchLink) {
    elements.fastqFolderBatchLink.classList.toggle("hidden", !generated || !batchPath);
    elements.fastqFolderBatchLink.href = batchPath ? `/api/batch-inputs/download?path=${encodeURIComponent(batchPath)}` : "#";
    elements.fastqFolderBatchLink.textContent = batchPath ? `打开批量 TSV：${batchPath}` : "打开批量 TSV";
  }
}

function resetFastqFolderBatchNote() {
  state.fastqFolderBatch = { sourcePath: "", batchPath: "", rows: 0 };
  renderFastqFolderBatchNote({ visible: false });
}

function looksLikeFilePath(pathValue = "") {
  const value = String(pathValue || "").trim().toLowerCase();
  return /\.(fastq|fq|fasta|fa|fna|gz|txt|tsv|csv|xlsx?|json|gbk?|gff3?|gtf|qza|qzv)$/.test(value);
}

