function collectCommunityAnalyses() {
  return elements.communityAnalysisOptions
    .filter((input) => input.checked)
    .map((input) => String(input.value || "").trim())
    .filter(Boolean);
}

function syncCommunityAnalysesState() {
  const hiddenInput = document.getElementById("community_analyses");
  if (!hiddenInput) return;
  const analyses = collectCommunityAnalyses();
  hiddenInput.value = analyses.join(",");
}

function getCommunityInputSourceMode() {
  return String(state.communityMerge?.sourceMode || elements.communityInputSource?.value || "manual").trim() === "merge_tasks"
    ? "merge_tasks"
    : "manual";
}

function isCommunityMergeSourceMode() {
  return isCommunityWorkstation() && getCommunityInputSourceMode() === "merge_tasks";
}

function getAvailableCommunityMergeTasks() {
  return (Array.isArray(state.tasks) ? state.tasks : []).filter((task) => {
    const params = task?.params || {};
    const workstationKey = String(params.workstation_key || "").trim().toLowerCase();
    const method = String(params.method || "").trim().toLowerCase();
    const status = String(task?.status || "").trim().toUpperCase();
    return (workstationKey === "metagenome" || method === "meta") && status === "SUCCEEDED";
  });
}

function sanitizeCommunityMergeSelections() {
  const availableIds = new Set(getAvailableCommunityMergeTasks().map((task) => String(task.id || "")));
  const current = state.communityMerge?.selections || {};
  state.communityMerge.selections = Object.fromEntries(
    Object.entries(current).filter(([taskId]) => availableIds.has(String(taskId || "")))
  );
}

function getCommunityMergeSelections() {
  sanitizeCommunityMergeSelections();
  return Object.entries(state.communityMerge?.selections || {})
    .filter(([, item]) => item && item.selected)
    .map(([taskId, item]) => ({
      task_id: String(taskId || "").trim(),
      group: String(item.group || "").trim() || "未分组",
    }))
    .filter((item) => item.task_id);
}

function setCommunityInputSourceMode(mode = "manual") {
  const normalized = String(mode || "").trim() === "merge_tasks" ? "merge_tasks" : "manual";
  state.communityMerge.sourceMode = normalized;
  if (elements.communityInputSource) {
    elements.communityInputSource.value = normalized;
  }
  syncCommunityInputSourceState();
  syncSubmissionStepState();
}

function updateCommunityMergeSelection(taskId, patch = {}) {
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId) return;
  const current = state.communityMerge.selections[normalizedTaskId] || { selected: false, group: "未分组" };
  state.communityMerge.selections[normalizedTaskId] = {
    ...current,
    ...patch,
  };
}

function renderCommunityMergeTaskOptions() {
  if (!elements.communityMergeTaskList) return;
  sanitizeCommunityMergeSelections();
  const tasks = getAvailableCommunityMergeTasks();
  if (!tasks.length) {
    elements.communityMergeTaskList.innerHTML = `
      <div class="community-merge-empty">
        <strong>暂无可用宏基因组任务</strong>
        <p>请先完成至少 2 个宏基因组任务，再在这里把它们汇总成群落输入。</p>
      </div>
    `;
    return;
  }
  elements.communityMergeTaskList.innerHTML = tasks.map((task) => {
    const taskId = String(task.id || "").trim();
    const saved = state.communityMerge.selections[taskId] || {};
    const checked = Boolean(saved.selected);
    const groupValue = String(saved.group || "未分组").trim() || "未分组";
    const statusText = statusLabel(task.status);
    const createdAt = formatDate(task.created_at);
    const owner = String(task.owner || "-").trim() || "-";
    const taskName = String(task.name || taskId || "未命名任务").trim();
    return `
      <label class="community-merge-task-card ${checked ? "is-selected" : ""}" data-community-merge-task="${escapeHtml(taskId)}">
        <div class="community-merge-task-main">
          <input type="checkbox" data-community-merge-task-check="${escapeHtml(taskId)}" ${checked ? "checked" : ""}>
          <div class="community-merge-task-copy">
            <strong>${escapeHtml(taskName)}</strong>
            <span>${escapeHtml(owner)} · ${escapeHtml(statusText)} · ${escapeHtml(createdAt)}</span>
          </div>
        </div>
        <div class="community-merge-task-group">
          <span>样本分组</span>
          <input data-community-merge-task-group="${escapeHtml(taskId)}" value="${escapeHtml(groupValue)}" placeholder="例如 病例组 / 对照组">
        </div>
      </label>
    `;
  }).join("");
  elements.communityMergeTaskList.querySelectorAll("[data-community-merge-task-check]").forEach((input) => {
    if (!(input instanceof HTMLInputElement)) return;
    input.addEventListener("change", () => {
      updateCommunityMergeSelection(input.dataset.communityMergeTaskCheck, { selected: input.checked });
      renderCommunityMergeTaskOptions();
      syncSubmissionStepState();
    });
  });
  elements.communityMergeTaskList.querySelectorAll("[data-community-merge-task-group]").forEach((input) => {
    if (!(input instanceof HTMLInputElement)) return;
    input.addEventListener("input", () => {
      updateCommunityMergeSelection(input.dataset.communityMergeTaskGroup, { group: input.value });
      syncSubmissionStepState();
    });
  });
}

function syncCommunityInputSourceState() {
  const isMergeMode = isCommunityMergeSourceMode();
  if (elements.communityInputSource) {
    elements.communityInputSource.value = getCommunityInputSourceMode();
  }
  elements.communitySourceManualButton?.classList.toggle("active", !isMergeMode);
  elements.communitySourceMergeButton?.classList.toggle("active", isMergeMode);
  elements.communityManualSourceFields?.classList.toggle("hidden", isMergeMode);
  elements.communityMergeSourceFields?.classList.toggle("hidden", !isMergeMode);
  elements.inputPathSingleWrap?.classList.toggle("hidden", isCommunityWorkstation() && isMergeMode);
  if (isMergeMode) {
    renderCommunityMergeTaskOptions();
  }
}

