    long_type: isPathoSource || isCommunity ? "Nanopore" : document.getElementById("long_type").value.trim(),
    genome_len: isPathoSource || isCommunity ? "4m" : document.getElementById("genome_len").value.trim(),
    asm_type: isPathoSource || isCommunity ? "shortasm" : document.getElementById("asm_type").value.trim(),
    polish_times: isPathoSource || isCommunity ? "1" : document.getElementById("polish_times").value.trim(),
    polish_soft: isPathoSource || isCommunity ? "medaka" : document.getElementById("polish_soft").value.trim(),
    species: isPathoSource ? "salmonella" : ((isMetagenome || isCommunity) ? "False" : document.getElementById("species").value.trim()),
    runflow: isPathoSource ? "物种鉴定" : (isCommunity ? collectCommunityAnalyses().join(",") : document.getElementById("runflow").value.trim()),
    rmhost: isPathoSource || isCommunity ? "norm" : (elements.rmhost?.value.trim() || "norm"),
    abun: isPathoSource || isCommunity ? "1" : document.getElementById("abun").value.trim(),
    rna: isPathoSource || isCommunity ? "0" : document.getElementById("rna").value.trim(),
    watch_mode: isPathoSource || isCommunity ? "0" : document.getElementById("watch_mode").value.trim(),
    watch_stable_minutes: isPathoSource || isCommunity ? "30" : document.getElementById("watch_stable_minutes").value.trim(),
    watch_poll_minutes: isPathoSource || isCommunity ? "5" : document.getElementById("watch_poll_minutes").value.trim(),
    watch_max_samples: isPathoSource || isCommunity ? "0" : document.getElementById("watch_max_samples").value.trim(),
    fake_pip: isPathoSource || isCommunity ? "0" : document.getElementById("fake_pip").value.trim(),
    ref: isPathoSource ? pathosourceRef : (isCommunity ? "" : document.getElementById("ref").value.trim()),
    gtf: isPathoSource || isCommunity ? "nogtf" : document.getElementById("gtf").value.trim(),
    pathosource_cgmlstana: "no",
    pathosource_gubbins: String(elements.pathosourceGubbins?.value || "yes").trim(),
    pathosource_msamethod: pathosourceMsaMethod,
    pathosource_treemethod: String(elements.pathosourceTreeMethod?.value || "ML").trim(),
    pathosource_bootstrap: String(elements.pathosourceBootstrap?.value || "1000").trim(),
    pathosource_mltype: String(elements.pathosourceMltype?.value || "MFP").trim(),
    community_metadata: String(elements.communityMetadata?.value || "").trim(),
    community_taxonomy: String(elements.communityTaxonomy?.value || "").trim(),
    community_input_source: getCommunityInputSourceMode(),
    community_merge_tasks: getCommunityMergeSelections(),
    community_group_column: String(elements.communityGroupColumn?.value || "").trim(),
    community_taxonomy_level: String(elements.communityTaxonomyLevel?.value || "genus").trim(),
    community_normalization: String(elements.communityNormalization?.value || "relative").trim(),
    community_analyses: collectCommunityAnalyses().join(","),
    community_alpha_metrics: String(elements.communityAlphaMetrics?.value || "shannon,simpson,chao1").trim(),
    community_beta_metric: String(elements.communityBetaMetric?.value || "braycurtis").trim(),
    community_ml_model: String(elements.communityMlModel?.value || "random_forest").trim(),
