function syncWorkstationUrlState() {
  const currentUrl = new URL(window.location.href);
  const tabMap = {
    "submission-tab": "submission",
    "queue-tab": "queue",
    "host-tab": "host",
    "database-tab": "database",
    "database-extra-tab": "database-extra",
    "project-tab": "project",
    "server-tab": "server",
    "admin-tab": "admin",
    "audit-tab": "audit",
  };
  const tabValue = tabMap[state.activeTab] || "submission";
  currentUrl.searchParams.set("tab", tabValue);
  if (tabValue === "database" && state.databaseSection) {
    currentUrl.searchParams.set("database_section", state.databaseSection);
  } else {
    currentUrl.searchParams.delete("database_section");
  }
  if (tabValue === "host" && state.referenceSection) {
    currentUrl.searchParams.set("reference_section", state.referenceSection);
  } else {
    currentUrl.searchParams.delete("reference_section");
  }
  if (tabValue === "database-extra" && state.databaseExtraSection) {
    currentUrl.searchParams.set("database_extra_section", state.databaseExtraSection);
  } else {
    currentUrl.searchParams.delete("database_extra_section");
  }
  window.history.replaceState({}, "", currentUrl.toString());
}

function splitTemplateLines(value) {
  return String(value || "")
    .split(/\n+/)
    .map((item) => item.replace(/^\s*[0-9一二三四五六七八九十]+[.、)]\s*/u, "").trim())
    .filter(Boolean);
}

function getActiveVirusReportTemplate() {
  const templates = Array.isArray(state.virusReportTemplates) ? state.virusReportTemplates : [];
  return templates.find((item) => String(item?.id || "") === state.activeVirusReportTemplateId) || templates[0] || null;
}

function collectVirusReportTemplateFormPayload(form, active = {}) {
  if (!(form instanceof HTMLFormElement)) return active || {};
  return {
    ...active,
    clinicalRisk: String(form.elements.clinicalRisk?.value || "").trim(),
    cdcRisk: String(form.elements.cdcRisk?.value || "").trim(),
    evidenceBasis: String(form.elements.evidenceBasis?.value || "").trim(),
    clinicalMeaning: String(form.elements.clinicalMeaning?.value || "").trim(),
    clinicalRecommendations: splitTemplateLines(form.elements.clinicalRecommendations?.value || ""),
    cdcMeaning: String(form.elements.cdcMeaning?.value || "").trim(),
    cdcRecommendations: splitTemplateLines(form.elements.cdcRecommendations?.value || ""),
  };
}

function normalizeVirusReportTemplateComparable(template = {}) {
  return {
    clinicalRisk: String(template?.clinicalRisk || "").trim(),
    cdcRisk: String(template?.cdcRisk || "").trim(),
    evidenceBasis: String(template?.evidenceBasis || "").trim(),
    clinicalMeaning: String(template?.clinicalMeaning || "").trim(),
    clinicalRecommendations: Array.isArray(template?.clinicalRecommendations) ? template.clinicalRecommendations.map((item) => String(item || "").trim()).filter(Boolean) : [],
    cdcMeaning: String(template?.cdcMeaning || "").trim(),
    cdcRecommendations: Array.isArray(template?.cdcRecommendations) ? template.cdcRecommendations.map((item) => String(item || "").trim()).filter(Boolean) : [],
  };
}

function validateVirusReportTemplateDraft(template = {}) {
  const errors = [];
  const warnings = [];
  const clinicalRecommendations = Array.isArray(template?.clinicalRecommendations) ? template.clinicalRecommendations : [];
  const cdcRecommendations = Array.isArray(template?.cdcRecommendations) ? template.cdcRecommendations : [];
  if (!String(template?.evidenceBasis || "").trim()) errors.push("证据基础不能为空。");
  if (!String(template?.clinicalMeaning || "").trim()) errors.push("医院报告临床意义不能为空。");
  if (!String(template?.cdcMeaning || "").trim()) errors.push("疾控报告监测意义不能为空。");
  if (!clinicalRecommendations.length) errors.push("医院报告至少需要 1 条建议。");
  if (!cdcRecommendations.length) errors.push("疾控报告至少需要 1 条建议。");
  if (String(template?.clinicalMeaning || "").length > 1200) errors.push("医院报告临床意义超过 1200 字。");
  if (String(template?.cdcMeaning || "").length > 1200) errors.push("疾控报告监测意义超过 1200 字。");
  if (clinicalRecommendations.length > 8) errors.push("医院报告建议最多 8 条。");
  if (cdcRecommendations.length > 8) errors.push("疾控报告建议最多 8 条。");
  if ([...clinicalRecommendations, ...cdcRecommendations].some((item) => String(item || "").length > 300)) {
    errors.push("单条建议不能超过 300 字。");
  }
  if (String(template?.clinicalRisk || "") === "中风险" && String(template?.cdcRisk || "") === "低") {
    warnings.push("医院关注为中风险，但疾控监测为低，请确认两个场景的风险口径是否有意区分。");
  }
  if (getVirusTemplateScopeLabels(template).length >= 4 && /登革|肝炎|HIV|猴痘|流感/.test(String(template?.clinicalMeaning || "") + String(template?.cdcMeaning || ""))) {
    warnings.push("该模板影响多个病毒流程，文案中出现了具体病种名称；若不是有意覆盖，请改为更通用表述。");
  }
  if (clinicalRecommendations.length > 5 || cdcRecommendations.length > 5) {
    warnings.push("建议条目较多，最终报告会显得偏重；建议优先保留最可执行的 3 到 5 条。");
  }
  return { errors, warnings };
}

function renderVirusTemplateQualityPanel(template = {}) {
  const result = validateVirusReportTemplateDraft(template);
  const status = result.errors.length ? "error" : result.warnings.length ? "warning" : "ok";
  const title = status === "error" ? "需要修正" : status === "warning" ? "建议复核" : "文案质控通过";
  const items = result.errors.concat(result.warnings);
  return `
    <aside class="virus-template-quality virus-template-quality-${status}" data-virus-template-quality>
      <div>
        <span>文案质控</span>
        <strong>${escapeHtml(title)}</strong>
      </div>
      ${items.length ? `<ul>${items.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>` : "<p>必填项、长度和医院/疾控风险口径暂未发现明显问题。</p>"}
    </aside>
  `;
}

function setVirusReportTemplateDirty(isDirty) {
  state.virusReportTemplateDirty = Boolean(isDirty);
  const root = elements.virusReportTemplateEditor;
  root?.querySelector("[data-virus-template-dirty]")?.toggleAttribute("hidden", !state.virusReportTemplateDirty);
  const saveButton = root?.querySelector("[data-virus-template-save]");
  if (saveButton instanceof HTMLButtonElement) {
    const form = root?.querySelector("#virus-report-template-form");
    const quality = form instanceof HTMLFormElement
      ? validateVirusReportTemplateDraft(collectVirusReportTemplateFormPayload(form, getActiveVirusReportTemplate() || {}))
      : { errors: [] };
    saveButton.disabled = !state.virusReportTemplateDirty || quality.errors.length > 0;
  }
}

function syncVirusReportTemplateDirtyState(form) {
  const active = getActiveVirusReportTemplate() || {};
  const current = normalizeVirusReportTemplateComparable(collectVirusReportTemplateFormPayload(form, active));
  const baseline = normalizeVirusReportTemplateComparable(active);
  setVirusReportTemplateDirty(JSON.stringify(current) !== JSON.stringify(baseline));
}

function confirmDiscardVirusTemplateChanges() {
  if (!state.virusReportTemplateDirty) return true;
  return window.confirm("当前报告模板有未保存修改，离开会丢失这些改动。确定继续吗？");
}

