    monkeypox_nextclade: "猴痘",
    hepatovirus_typing: "肝炎病毒",
    bandavirus_typing: "班达病毒",
    orthohantavirus_typing: "汉坦病毒",
    orthoebolavirus_typing: "埃博拉病毒",
    ebola_nextclade: "埃博拉病毒",
    denv_nextclade: "登革热病毒",
    zikav_nextclade: "寨卡病毒",
    chikv_nextclade: "基孔肯雅病毒",
    hiv_resistance: "HIV",
    rsv_nextclade: "合胞病毒",
    hmpv_nextclade: "偏肺病毒",
    hpiv_typing: "副流感病毒",
    hadv_typing: "腺病毒",
    rhinovirus_typing: "鼻病毒",
    seasonal_hcov_typing: "季节性冠状病毒",
    norovirus_typing: "诺如病毒",
    enterovirus_typing: "肠道病毒",
    rotavirus_typing: "轮状病毒",
