function classifyQueueBacteriaScatterPoint(item) {
  const completeness = Number(item?.completeness);
  const contamination = Number(item?.contamination);
  if (!Number.isFinite(completeness) || !Number.isFinite(contamination)) {
    return "exception";
  }
  if (completeness >= 90 && contamination <= 5) {
    return "high";
  }
  if (completeness < 50 || contamination > 10) {
    return "low";
  }
  return "medium";
}

function renderQueueBacteriaScatterShell(points) {
  const normalizedPoints = points.map((item) => ({
    ...item,
    completeness: Number(item.completeness),
    contamination: Number(item.contamination),
    scatterClass: classifyQueueBacteriaScatterPoint(item),
  })).filter((item) => Number.isFinite(item.completeness) && Number.isFinite(item.contamination));
  const total = normalizedPoints.length || 1;
  const xMin = 50;
  const xMax = 100;
  const rawMaxContamination = Math.max(10, ...normalizedPoints.map((item) => item.contamination));
  const yMax = Math.max(10, Math.ceil(rawMaxContamination));
  const xTicks = [50, 60, 70, 80, 90, 100];
  const yTicks = Array.from({ length: Math.min(6, yMax + 1) }, (_, index) => {
    if (index === 0) return 0;
    if (index === Math.min(5, yMax)) return yMax;
    return Math.round((index / Math.min(5, yMax)) * yMax);
  }).filter((value, index, array) => array.indexOf(value) === index);
  const scatterClasses = [
    { key: "high", label: "高质量", color: "#b6df62" },
    { key: "medium", label: "中等质量", color: "#ffae63" },
    { key: "low", label: "低质量", color: "#8ab6d8" },
    { key: "exception", label: "异常值", color: "#1f2937" },
  ];
  const classMap = Object.fromEntries(scatterClasses.map((item) => [item.key, item]));
  const legendStats = scatterClasses.map((item) => {
    const count = normalizedPoints.filter((point) => point.scatterClass === item.key).length;
    return {
      ...item,
      count,
      percent: count ? (count / total) * 100 : 0,
    };
  }).filter((item) => item.count > 0);
  const summary = {
    total: normalizedPoints.length,
    high: legendStats.find((item) => item.key === "high")?.count || 0,
    medium: legendStats.find((item) => item.key === "medium")?.count || 0,
    low: legendStats.find((item) => item.key === "low")?.count || 0,
  };
  const completenessBins = Array.from({ length: 10 }, (_, index) => ({
    start: 50 + index * 5,
    end: 55 + index * 5,
    high: 0,
    medium: 0,
    low: 0,
    exception: 0,
  }));
  const contaminationBins = Array.from({ length: Math.max(10, Math.ceil(yMax)) }, (_, index) => ({
    start: index,
    end: index + 1,
    high: 0,
    medium: 0,
    low: 0,
    exception: 0,
  }));
  normalizedPoints.forEach((point) => {
    const xIndex = Math.max(0, Math.min(completenessBins.length - 1, Math.floor((Math.max(xMin, Math.min(xMax, point.completeness)) - xMin) / 5)));
    completenessBins[xIndex][point.scatterClass] += 1;
    const yIndex = Math.max(0, Math.min(contaminationBins.length - 1, Math.floor(Math.max(0, Math.min(yMax - 0.0001, point.contamination)))));
    contaminationBins[yIndex][point.scatterClass] += 1;
  });
  const topMaxRatio = Math.max(
    0.1,
    ...completenessBins.map((bin) => (bin.high + bin.medium + bin.low + bin.exception) / total)
  );
  const rightMaxRatio = Math.max(
    0.1,
    ...contaminationBins.map((bin) => (bin.high + bin.medium + bin.low + bin.exception) / total)
  );
  const xPercent = (value) => ((Math.max(xMin, Math.min(xMax, value)) - xMin) / (xMax - xMin)) * 100;
  const yPercent = (value) => 100 - (Math.max(0, Math.min(yMax, value)) / yMax) * 100;
  const topBars = completenessBins.map((bin) => {
    const totalRatio = (bin.high + bin.medium + bin.low + bin.exception) / total;
    const barHeight = Math.max(4, (totalRatio / topMaxRatio) * 100);
    const stack = ["high", "medium", "low", "exception"].map((key) => {
      const segmentRatio = bin[key] / total;
      const height = totalRatio > 0 ? (segmentRatio / topMaxRatio) * 100 : 0;
      if (height <= 0) return "";
      return `<span class="queue-scatter-html-segment" style="height:${height}%;background:${classMap[key].color}"></span>`;
    }).join("");
    return `
      <span class="queue-scatter-html-column" title="${escapeHtml(`${bin.start}-${bin.end}%：${bin.high + bin.medium + bin.low + bin.exception} 个任务`)}">
        <span class="queue-scatter-html-stack" style="height:${barHeight}%">${stack}</span>
      </span>
    `;
  }).join("");
  const rightBars = contaminationBins.map((bin) => {
    const totalRatio = (bin.high + bin.medium + bin.low + bin.exception) / total;
    const stack = ["medium", "high", "low", "exception"].map((key) => {
      const segmentRatio = bin[key] / total;
      const width = totalRatio > 0 ? (segmentRatio / rightMaxRatio) * 100 : 0;
      if (width <= 0) return "";
      return `<span class="queue-scatter-html-segment" style="width:${width}%;background:${classMap[key].color}"></span>`;
    }).join("");
    return `
      <span class="queue-scatter-html-row" title="${escapeHtml(`${bin.start}-${bin.end}%：${bin.high + bin.medium + bin.low + bin.exception} 个任务`)}">
        ${stack}
      </span>
    `;
  }).join("");
  const pointsMarkup = normalizedPoints.map((item) => {
    const left = xPercent(item.completeness);
    const top = yPercent(item.contamination);
    const style = classMap[item.scatterClass] || classMap.medium;
    return `
      <button
        class="queue-scatter-html-point queue-scatter-html-point-${escapeHtml(item.scatterClass)}"
        type="button"
        style="left:${left}%;top:${top}%;--point-color:${style.color}"
        data-bacteria-scatter-task="${escapeHtml(item.taskId || "")}"
        title="${escapeHtml(`${item.taskName || item.taskId} | 完整性 ${item.completeness.toFixed(1)}% | 污染率 ${item.contamination.toFixed(1)}% | ${style.label}`)}"
        aria-label="${escapeHtml(`${item.taskName || item.taskId}，完整性 ${item.completeness.toFixed(1)}%，污染率 ${item.contamination.toFixed(1)}%，${style.label}`)}"
      ></button>
    `;
  }).join("");
  return `
    <div class="viz-shell queue-scatter-shell">
      <div class="queue-scatter-head">
        <div>
          <h4>细菌完整性 / 污染率散点图</h4>
        </div>
        <div class="queue-scatter-metrics">
          <span><strong>${summary.total}</strong><small>纳入任务</small></span>
          <span><strong>${summary.high}</strong><small>高质量</small></span>
          <span><strong>${summary.medium + summary.low}</strong><small>待复核</small></span>
        </div>
      </div>
      <div class="queue-scatter-html" role="group" aria-label="细菌完整性和污染率散点图">
        <div class="queue-scatter-html-top" aria-label="完整性分布直方图">${topBars}</div>
        <div class="queue-scatter-html-ytitle">Contamination (%)</div>
        <div class="queue-scatter-html-yaxis">
          ${yTicks.map((tick) => `<span style="bottom:${100 - yPercent(tick)}%">${escapeHtml(String(tick))}</span>`).join("")}
        </div>
        <div class="queue-scatter-html-plot">
          <div class="queue-scatter-html-safezone" style="left:${xPercent(90)}%;top:${yPercent(5)}%"></div>
          ${yTicks.map((tick) => `<span class="queue-scatter-html-gridline" style="bottom:${100 - yPercent(tick)}%"></span>`).join("")}
          ${pointsMarkup}
        </div>
        <div class="queue-scatter-html-right" aria-label="污染率分布直方图">${rightBars}</div>
        <div class="queue-scatter-html-xaxis">
          ${xTicks.map((tick) => `<span style="left:${xPercent(tick)}%">${escapeHtml(String(tick))}</span>`).join("")}
        </div>
        <div class="queue-scatter-html-xtitle">Completeness (%)</div>
      </div>
      <div class="viz-legend viz-legend-inline queue-scatter-legend">
        ${legendStats.map((item) => `
          <span class="viz-legend-item queue-scatter-legend-item">
            <span class="queue-scatter-legend-mark ${item.key === "exception" ? "is-exception" : ""}" style="${item.key === "exception" ? "" : `background:${item.color}`}" aria-hidden="true"></span>
            ${escapeHtml(`${item.label} (${formatNumber(item.count)} 个任务；${item.percent.toFixed(1)}%)`)}
          </span>
        `).join("")}
      </div>
    </div>
  `;
}

function buildQueueAnalyticsActiveFilterChips() {
  const filters = state.queueAnalytics?.filters || {};
  const chips = [];
  if (filters.workstation) {
    chips.push({ key: "workstation", label: "任务类型", value: WORKSTATION_LABELS[filters.workstation] || filters.workstation });
  }
  if (filters.quality) {
    chips.push({ key: "quality", label: "数据质控", value: getQueueQualityBandMeta(filters.quality).label });
  }
  if (filters.species) {
    chips.push({ key: "species", label: "物种鉴定", value: filters.species });
  }
  return chips;
}

function compareTasks(left, right, sortMode) {
  if (sortMode === "created_asc") {
    return compareText(left.created_at, right.created_at);
  }
  if (sortMode === "name_asc") {
    return compareText(left.name || left.id, right.name || right.id);
  }
  if (sortMode === "name_desc") {
    return compareText(right.name || right.id, left.name || left.id);
  }
  if (sortMode === "status") {
    const order = { RUNNING: 0, PAUSED: 1, QUEUED: 2, FAILED: 3, STOPPED: 4, SUCCEEDED: 5 };
    const statusDelta = (order[left.status] ?? 9) - (order[right.status] ?? 9);
    if (statusDelta !== 0) {
      return statusDelta;
    }
    return compareText(right.created_at, left.created_at);
  }
  return compareText(right.created_at, left.created_at);
}

function compareText(left, right) {
  return String(left || "").localeCompare(String(right || ""), "zh-CN");
}

function onQueueFilterChange(status) {
  state.queueControls.status = status || "ALL";
  renderTaskList();
}

function onQueueSearchChange(event) {
  if (event?.isComposing || state.queueControls.searchComposing) {
    return;
  }
  state.queueControls.search = String(event.target.value || "");
  renderTaskList();
}

function onQueueSearchCompositionStart() {
  state.queueControls.searchComposing = true;
}

function onQueueSearchCompositionEnd(event) {
  state.queueControls.searchComposing = false;
  state.queueControls.search = String(event?.target?.value || "");
  renderTaskList();
}

function onQueueSortChange(event) {
  state.queueControls.sort = String(event.target.value || "created_desc");
  syncQueueTableSortPreset();
  renderTaskList();
}

function closeQueueControlMenus() {
  const hadOpenMenu = state.queueTable.sortMenuOpen || state.queueTable.filterMenuOpen;
  if (!hadOpenMenu) return false;
  state.queueTable.sortMenuOpen = false;
  state.queueTable.filterMenuOpen = false;
  renderTaskList();
  return true;
}

function closeDemoDropdown() {
  const details = elements.demoButton?.closest("details");
  if (details?.open) {
    details.open = false;
  }
}

function closeAutoCloseDetails(exceptDetails = null) {
  let closed = false;
  document.querySelectorAll(`${AUTO_CLOSE_DETAILS_SELECTOR}[open]`).forEach((details) => {
    if (!(details instanceof HTMLDetailsElement)) return;
    if (exceptDetails instanceof HTMLDetailsElement && details === exceptDetails) return;
    details.open = false;
    closed = true;
  });
  return closed;
}

function syncAutoCloseDetailsState(details) {
  if (!(details instanceof HTMLDetailsElement)) return;
  const summary = details.querySelector("summary");
  summary?.setAttribute("aria-expanded", details.open ? "true" : "false");
}

function onGlobalDetailsToggle(event) {
  const details = event.target;
  if (!(details instanceof HTMLDetailsElement)) return;
  if (!details.matches(AUTO_CLOSE_DETAILS_SELECTOR)) return;
  syncAutoCloseDetailsState(details);
  if (details.open) {
    closeAutoCloseDetails(details);
  }
}

function isVisibleModal(modal) {
  return modal instanceof HTMLElement && !modal.classList.contains("hidden") && modal.getAttribute("aria-hidden") !== "true";
}

function closeTopmostModalOnEscape() {
  const confirmModal = document.getElementById("confirm-action-modal");
  const modalStack = [
    { isOpen: () => isVisibleModal(confirmModal), close: () => closeConfirmActionModal(false) },
    { isOpen: () => state.pathBrowser.open, close: closePathBrowser },
    { isOpen: () => state.rebuildModalOpen, close: closeRebuildModal },
    { isOpen: () => isVisibleModal(elements.taskDeleteModal), close: closeTaskDeleteModal },
    { isOpen: () => isVisibleModal(elements.referenceDeleteModal), close: closeReferenceDeleteModal },
    { isOpen: () => isVisibleModal(elements.databaseDeleteModal), close: closeDatabaseDeleteModal },
    { isOpen: () => isVisibleModal(elements.projectDeleteModal), close: closeProjectDeleteModal },
    { isOpen: () => state.mergedExportOpen, close: closeMergedExportModal },
    { isOpen: () => state.resultViewerOpen, close: closeResultViewerToQueue },
    { isOpen: () => state.taskDetailOpen, close: closeTaskDetail },
    { isOpen: () => state.batchInput.open, close: closeBatchInputModal },
    { isOpen: () => isVisibleModal(elements.metaDatabaseImportModal), close: closeMetaDatabaseImportModal },
    { isOpen: () => isVisibleModal(elements.databaseSampleModal), close: closeDatabaseSampleModal },
    { isOpen: () => isVisibleModal(elements.databaseDictionaryModal), close: closeDatabaseDictionaryModal },
    { isOpen: () => isVisibleModal(elements.databaseBatchImportModal), close: closeDatabaseBatchImportModal },
    { isOpen: () => isVisibleModal(elements.databaseBatchEditModal), close: closeDatabaseBatchEditModal },
    { isOpen: () => isVisibleModal(elements.databaseLocalImportModal), close: closeDatabaseLocalImportModal },
    { isOpen: () => isVisibleModal(elements.databaseReleaseModal), close: closeDatabaseReleaseModal },
    { isOpen: () => isVisibleModal(elements.databaseAlertRuleModal), close: closeDatabaseAlertRuleModal },
    { isOpen: () => isVisibleModal(elements.nextstrainBuildModal), close: closeNextstrainBuildModal },
    { isOpen: () => isVisibleModal(elements.hostLocalImportModal), close: closeHostLocalImportModal },
    { isOpen: () => isVisibleModal(elements.hostRemoteImportModal), close: closeHostRemoteImportModal },
    { isOpen: () => isVisibleModal(elements.pathogenLocalImportModal), close: closePathogenLocalImportModal },
    { isOpen: () => isVisibleModal(elements.pathogenRemoteImportModal), close: closePathogenRemoteImportModal },
    { isOpen: () => isVisibleModal(elements.referenceBatchImportModal), close: closeReferenceBatchImportModal },
    { isOpen: () => isVisibleModal(elements.createUserModal), close: closeCreateUserModal },
    { isOpen: () => isVisibleModal(elements.editUserModal), close: closeEditUserModal },
    { isOpen: () => isVisibleModal(elements.projectMilestoneModal), close: closeProjectMilestoneModal },
    { isOpen: () => isVisibleModal(elements.projectOwnerModal), close: closeProjectOwnerModal },
    { isOpen: () => isVisibleModal(elements.projectCreateModal), close: closeProjectCreateModal },
  ];
  const active = modalStack.find((item) => item.isOpen());
  if (!active) return false;
  active.close();
  return true;
}

function onGlobalPointerDown(event) {
  const target = event.target;
  if (!(target instanceof Element)) return;
  const activeDetails = target.closest(AUTO_CLOSE_DETAILS_SELECTOR);
  closeAutoCloseDetails(activeDetails instanceof HTMLDetailsElement ? activeDetails : null);
  if (!target.closest("[data-queue-sort-menu], [data-queue-filter-menu]")) {
    closeQueueControlMenus();
  }
  if (!target.closest(".submission-actions .action-dropdown")) {
    closeDemoDropdown();
  }
}

function onGlobalKeyDown(event) {
  if (event.key !== "Escape") return;
  const closedDetails = closeAutoCloseDetails();
  const closedQueueMenus = closeQueueControlMenus();
  if (closedDetails || closedQueueMenus) {
    event.preventDefault();
    return;
  }
  if (closeTopmostModalOnEscape()) {
    event.preventDefault();
  }
}

function syncQueueControls() {
  elements.queueFilterButtons.forEach((button) => {
    button.classList.toggle("active", (button.dataset.filterStatus || "ALL") === state.queueControls.status);
  });
  if (elements.queueSearch && !state.queueControls.searchComposing && elements.queueSearch.value !== state.queueControls.search) {
    elements.queueSearch.value = state.queueControls.search;
  }
  if (elements.queueSort && elements.queueSort.value !== state.queueControls.sort) {
    elements.queueSort.value = state.queueControls.sort;
  }
}

function syncQueueTableSortPreset() {
  const presetMap = {
    created_desc: { sortKey: "runtime", sortDirection: "desc" },
    created_asc: { sortKey: "runtime", sortDirection: "asc" },
    name_asc: { sortKey: "name", sortDirection: "asc" },
    name_desc: { sortKey: "name", sortDirection: "desc" },
    status: { sortKey: "status", sortDirection: "asc" },
  };
  const preset = presetMap[state.queueControls.sort] || presetMap.created_desc;
  state.queueTable.sortKey = preset.sortKey;
  state.queueTable.sortDirection = preset.sortDirection;
}

const MERGED_SAMPLE_COLUMNS = [
  { key: "task_name", label: "任务名称", sortable: true, text: true },
  { key: "task_id", label: "任务 ID", sortable: false, text: true },
  { key: "sample_name", label: "样本名称", sortable: true, text: true },
  { key: "status", label: "状态", sortable: true, text: true },
  { key: "reads", label: "测序量", sortable: true, numericKey: "reads_value" },
  { key: "q20_q30", label: "Q20 / Q30", sortable: true, numericKey: "q30_value" },
  { key: "species", label: "物种鉴定", sortable: true, text: true },
  { key: "mlst", label: "MLST / ST", sortable: true, text: true },
  { key: "serotype", label: "血清型", sortable: true, text: true },
  { key: "completeness_contamination", label: "完整性 / 污染率", sortable: true, numericKey: "completeness_value" },
  { key: "assembly", label: "组装结果", sortable: false, text: true },
  { key: "resistance_virulence", label: "耐药 / 毒力", sortable: true, numericKey: "resistance_virulence_count" },
  { key: "note", label: "关注说明", sortable: false, text: true },
];

function isTaskMergeExportable(task) {
  return String(task?.status || "").toUpperCase() === "SUCCEEDED";
}

function toggleMergeTaskSelection(taskId, checked) {
  const current = new Set(state.queueSelectedTaskIds || []);
  const normalized = String(taskId || "");
  if (checked) {
    current.add(normalized);
  } else {
    current.delete(normalized);
  }
  state.queueSelectedTaskIds = Array.from(current).filter(Boolean);
}

function toggleVisibleMergeTaskSelection(taskIds, checked) {
  const current = new Set(state.queueSelectedTaskIds || []);
  (taskIds || []).map((taskId) => String(taskId || "")).filter(Boolean).forEach((taskId) => {
    if (checked) current.add(taskId);
    else current.delete(taskId);
  });
  state.queueSelectedTaskIds = Array.from(current);
}

function closeMergedExportModal() {
  state.mergedExportOpen = false;
  elements.mergedExportModal?.classList.add("hidden");
  elements.mergedExportModal?.setAttribute("aria-hidden", "true");
  document.documentElement.classList.remove("modal-scroll-locked");
  document.body.classList.remove("modal-scroll-locked");
}

async function openMergedExportPreview() {
  const selectedTasks = (state.queueSelectedTaskIds || [])
    .map((taskId) => state.tasks.find((task) => String(task.id || "") === String(taskId)))
    .filter(Boolean);
  const invalidCount = selectedTasks.filter((task) => !isTaskMergeExportable(task)).length;
  const exportableTasks = selectedTasks.filter(isTaskMergeExportable);
  if (invalidCount) {
    showToast("仅已完成任务可导出，已忽略不可导出的任务。", "warning");
  }
  if (!exportableTasks.length) {
    showToast("请先勾选至少一个已完成任务。", "warning");
    return;
  }
  state.mergedExportOpen = true;
  state.mergedExport.loading = true;
  state.mergedExport.tasks = exportableTasks.map((task) => normalizeMergedExportTask(task));
  state.mergedExport.samples = [];
  state.mergedExport.selectedSampleIds = [];
  renderMergedExportModal();
  elements.mergedExportModal?.classList.remove("hidden");
  elements.mergedExportModal?.setAttribute("aria-hidden", "false");
  document.documentElement.classList.add("modal-scroll-locked");
  document.body.classList.add("modal-scroll-locked");

  const results = await Promise.all(exportableTasks.map(async (task) => {
    try {
      const report = await requestJson(`/api/tasks/${encodeURIComponent(task.id)}/report-data`, { silentError: true });
      return { task, report, error: "" };
    } catch (error) {
      return { task, report: null, error: error?.message || "任务结果文件缺失或无法读取" };
    }
  }));
  const tasks = [];
  const samples = [];
  results.forEach((item) => {
    tasks.push(normalizeMergedExportTask(item.task, item.error));
    if (!item.error) {
      samples.push(...extractMergedSamplesFromReport(item.task, item.report));
    }
  });
  state.mergedExport.tasks = tasks;
  state.mergedExport.samples = samples;
  state.mergedExport.selectedSampleIds = samples.map((sample) => sample.sample_id);
  state.mergedExport.loading = false;
  renderMergedExportModal();
  if (!samples.length) {
    showToast("所选任务暂无可合并的样本结果。", "warning");
  }
}

function normalizeMergedExportTask(task, error = "") {
  return {
    task_id: String(task?.id || ""),
    task_name: String(task?.name || task?.id || "-"),
    task_type: resolveQueueTaskWorkstationLabel(task),
    created_at: formatDate(task?.created_at || task?.started_at || ""),
    status: statusLabel(task?.status || ""),
    abnormal: Boolean(error),
    note: error || "",
  };
}

function extractMergedSamplesFromReport(task, report) {
  const summary = report?.task?.multi_sample_summary || report?.sections?.overview?.multi_sample_summary || {};
  const samples = Array.isArray(summary?.samples) ? summary.samples : [];
  if (samples.length) {
    return samples.map((sample, index) => normalizeMergedSampleRow(task, sample, index));
  }
  return [normalizeMergedSingleSampleRow(task, report)];
}

function normalizeMergedSampleRow(task, sample, index = 0) {
  const sampleName = String(sample?.sample || sample?.sample_name || sample?.sample_id || `${task.name || task.id}_${index + 1}`).trim();
  const resistanceCount = Number(sample?.resistance_count || 0);
  const virulenceCount = Number(sample?.virulence_count || 0);
  const completeness = coerceFiniteNumber(sample?.completeness);
  const contamination = coerceFiniteNumber(sample?.contamination);
  const q20 = coerceFiniteNumber(sample?.q20_rate);
  const q30 = coerceFiniteNumber(sample?.q30_rate);
  const readsValue = coerceFiniteNumber(sample?.total_bases) ?? coerceFiniteNumber(sample?.total_reads) ?? 0;
  return {
    task_id: String(task.id || ""),
    task_name: String(task.name || task.id || "-"),
    sample_id: `${task.id || "task"}::${sampleName || index}`,
    sample_name: sampleName || "-",
    status: sample?.ready === false ? "异常" : String(sample?.qc_status || "已完成"),
    reads: formatQueueHumanBp(sample?.total_bases) !== "--" ? formatQueueHumanBp(sample?.total_bases) : formatQueueNumber(sample?.total_reads),
    reads_value: readsValue,
    q20_q30: `${formatMergedPercent(q20)} / ${formatMergedPercent(q30)}`,
    q20_value: q20,
    q30_value: q30,
    species: safeMergedText(sample?.species_name),
    mlst: safeMergedText(sample?.typing),
    serotype: safeMergedText(sample?.serotype),
    completeness_contamination: `${formatMergedPercent(completeness)} / ${formatMergedPercent(contamination)}`,
    completeness_value: completeness,
    contamination_value: contamination,
    assembly: buildMergedAssemblyText(sample),
    resistance_virulence: `${Number.isFinite(resistanceCount) ? resistanceCount : 0} / ${Number.isFinite(virulenceCount) ? virulenceCount : 0}`,
    resistance_virulence_count: (Number.isFinite(resistanceCount) ? resistanceCount : 0) + (Number.isFinite(virulenceCount) ? virulenceCount : 0),
    note: safeMergedText(sample?.note),
  };
}

function normalizeMergedSingleSampleRow(task, report) {
  const reportTask = report?.task || {};
  const metrics = Array.isArray(report?.overview_metrics) ? report.overview_metrics : [];
  const sections = report?.sections || {};
  const totalBasesMetric = findMergedMetric(metrics, ["total_bases"]);
  const qMetric = findMergedMetric(metrics, ["q_metrics", "quality", "quality_overview", "sequencing"]);
  const checkmMetric = findMergedMetric(metrics, ["checkm_metrics"]);
  const speciesMetric = findMergedMetric(metrics, ["species_estimation", "taxonomy", "species", "virus_taxonomy"]);
  const assemblyMetric = findMergedMetric(metrics, ["assembly", "assembly_overview"]);
  const assemblySection = sections.assembly || {};
  const resistanceSection = sections.resistance_virulence || {};
  const resistanceOverview = resistanceSection.overview || {};
  const resistanceCount = coerceFiniteNumber(resistanceOverview.resistance?.hit_count) ?? mergedSectionRowCount(resistanceSection.resistance_elements);
  const virulenceCount = coerceFiniteNumber(resistanceOverview.virulence?.hit_count) ?? mergedSectionRowCount(resistanceSection.virulence_elements);
  const species = reportTask.species_name
    || reportTask.mlst_species_name
    || getMergedMetricItemDisplay(speciesMetric, ["物种名称", "species"])
    || speciesMetric?.display
    || speciesMetric?.value
    || "";
  const mlst = reportTask.mlst_st || reportTask.mlst || reportTask.typing_result || reportTask.subtype || getMergedMlstValue(sections.mlst) || "";
  const serotype = reportTask.serotype_result || reportTask.serotype || getMergedSerotypeValue(sections.serotype) || "";
  const q20 = coerceFiniteNumber(reportTask.q20_rate) ?? parsePercentNumber(getMergedMetricItemDisplay(qMetric, ["Q20"]));
  const q30 = coerceFiniteNumber(reportTask.q30_rate) ?? parsePercentNumber(getMergedMetricItemDisplay(qMetric, ["Q30"]));
  const completeness = coerceFiniteNumber(reportTask.completeness) ?? parsePercentNumber(getMergedMetricItemDisplay(checkmMetric, ["完整性", "completeness"]));
  const contamination = coerceFiniteNumber(reportTask.contamination) ?? parsePercentNumber(getMergedMetricItemDisplay(checkmMetric, ["污染率", "contamination"]));
  const readsValue = coerceFiniteNumber(reportTask.total_bases || reportTask.sum_len || reportTask.total_reads || reportTask.sum_reads || totalBasesMetric?.value) || 0;
  const readsDisplay = totalBasesMetric?.display
    || (formatQueueHumanBp(reportTask.total_bases || reportTask.sum_len) !== "--" ? formatQueueHumanBp(reportTask.total_bases || reportTask.sum_len) : formatQueueNumber(reportTask.total_reads || reportTask.sum_reads));
  return {
    task_id: String(task.id || ""),
    task_name: String(task.name || task.id || "-"),
    sample_id: `${task.id || "task"}::${reportTask.sample_name || reportTask.sample_display_name || task.name || task.id}`,
    sample_name: String(reportTask.sample_display_name || reportTask.sample_name || task.name || task.id || "-"),
    status: statusLabel(task.status || "SUCCEEDED"),
    reads: readsDisplay || "-",
    reads_value: readsValue,
    q20_q30: `${formatMergedPercent(q20)} / ${formatMergedPercent(q30)}`,
    q20_value: q20,
    q30_value: q30,
    species: safeMergedText(species),
    mlst: safeMergedText(mlst),
    serotype: safeMergedText(serotype),
    completeness_contamination: `${formatMergedPercent(completeness)} / ${formatMergedPercent(contamination)}`,
    completeness_value: completeness,
    contamination_value: contamination,
    assembly: safeMergedText(reportTask.assembly_summary || reportTask.assembly || buildMergedSingleAssemblyText(assemblyMetric, assemblySection)),
    resistance_virulence: `${Number.isFinite(resistanceCount) ? resistanceCount : 0} / ${Number.isFinite(virulenceCount) ? virulenceCount : 0}`,
    resistance_virulence_count: (Number.isFinite(resistanceCount) ? resistanceCount : 0) + (Number.isFinite(virulenceCount) ? virulenceCount : 0),
    note: safeMergedText(reportTask.note || reportTask.attention_note || getMergedQualityNote(completeness, contamination)),
  };
}

function getMergedMetricItemDisplay(metric, labels) {
  const items = Array.isArray(metric?.items) ? metric.items : [];
  const normalizedLabels = labels.map((label) => String(label || "").trim().toLowerCase());
  const found = items.find((item) => {
    const label = String(item?.label || item?.key || "").trim().toLowerCase();
    return normalizedLabels.some((candidate) => label === candidate || label.includes(candidate));
  });
  return String(found?.display ?? found?.value ?? "").trim();
}

function getMergedMlstValue(section) {
  const rows = Array.isArray(section?.rows) ? section.rows : [];
  const columns = Array.isArray(section?.columns) ? section.columns : [];
  if (!rows.length || !columns.length) return "";
  const stIndex = columns.findIndex((column) => ["序列分型(st)", "st", "sequence type"].includes(String(column || "").trim().toLowerCase()));
  const speciesIndex = columns.findIndex((column) => ["物种信息", "scheme", "mlst scheme"].includes(String(column || "").trim().toLowerCase()));
  const row = rows.find((item) => Array.isArray(item) && item.some((cell) => String(cell || "").trim())) || [];
  const st = stIndex >= 0 ? String(row[stIndex] || "").trim() : "";
  const species = speciesIndex >= 0 ? String(row[speciesIndex] || "").trim() : "";
  if (st && species) return `${species} / ST${String(st).replace(/^ST/i, "")}`;
  if (st) return `ST${String(st).replace(/^ST/i, "")}`;
  return "";
}

function getMergedSerotypeValue(section) {
  const rows = Array.isArray(section?.rows) ? section.rows : [];
  const columns = Array.isArray(section?.columns) ? section.columns : [];
  if (!rows.length || !columns.length) return "";
  const preferred = ["SEROGROUP", "SEROTYPE", "血清型", "亚型全称", "predicted_serotype", "predicted_clade"];
  for (const label of preferred) {
    const index = columns.findIndex((column) => String(column || "").trim().toLowerCase() === label.toLowerCase());
    if (index >= 0) {
      const value = String(rows[0]?.[index] || "").trim();
      if (value && value !== "-") return value;
    }
  }
  return String(section?.predicted_serotype || section?.predicted_clade || "").trim();
}

function buildMergedSingleAssemblyText(metric, section) {
  const summary = section?.summary || {};
  const summaryRows = Array.isArray(summary?.rows) ? summary.rows : [];
  const summaryColumns = Array.isArray(summary?.columns) ? summary.columns : [];
  const row = summaryRows[0] || [];
  const contigFromSummary = getMergedTableCell(summaryColumns, row, ["Contig数量", "contig"]);
  const n50 = getMergedTableCell(summaryColumns, row, ["N50长度", "N50"]);
  const length = metric?.total_length ? formatQueueHumanBp(metric.total_length) : "";
  const contigs = metric?.total_count || metric?.contig_count || contigFromSummary;
  return [
    contigs ? `${contigs} contigs` : "",
    n50 ? `N50 ${n50}` : "",
    length || "",
  ].filter(Boolean).join(" / ");
}

function getMergedTableCell(columns, row, candidates) {
  const index = columns.findIndex((column) => candidates.some((candidate) => String(column || "").toLowerCase().includes(String(candidate).toLowerCase())));
  return index >= 0 ? String(row?.[index] || "").trim() : "";
}

function mergedSectionRowCount(section) {
  return Array.isArray(section?.rows) ? section.rows.length : 0;
}

function getMergedQualityNote(completeness, contamination) {
  if (Number.isFinite(completeness) && completeness < 90) return "完整性低于 90%，建议复核组装质量。";
  if (Number.isFinite(contamination) && contamination >= 5) return "污染率不低于 5%，建议复核样本纯度。";
  return "";
}

function findMergedMetric(metrics, keys) {
  return metrics.find((metric) => {
    const candidates = [metric?.key, metric?.type, metric?.id, metric?.label, metric?.title].map((value) => String(value || "").toLowerCase());
    return candidates.some((value) => keys.some((key) => value === String(key).toLowerCase() || value.includes(String(key).toLowerCase())));
  }) || null;
}

function buildMergedAssemblyText(sample) {
  const parts = [];
  if (sample?.contig_count) parts.push(`${formatQueueNumber(sample.contig_count)} contigs`);
  if (sample?.assembly_length) parts.push(formatQueueHumanBp(sample.assembly_length));
  if (sample?.plasmid_count) parts.push(`${formatQueueNumber(sample.plasmid_count)} plasmids`);
  return parts.length ? parts.join(" / ") : "-";
}

function safeMergedText(value) {
  const text = String(value ?? "").trim();
  return text || "-";
}

function coerceFiniteNumber(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === "string" && !value.trim()) return null;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
}

function formatMergedPercent(value) {
  const numeric = coerceFiniteNumber(value);
  if (numeric === null) return "-";
  return `${numeric.toFixed(2)}%`;
}

function renderMergedExportModal(focusKey = "", caretPosition = null) {
  if (!elements.mergedExportBody) return;
  const filteredSamples = getMergedFilteredSortedSamples();
  const selectedIds = new Set(state.mergedExport.selectedSampleIds || []);
  const selectedVisibleCount = filteredSamples.filter((sample) => selectedIds.has(sample.sample_id)).length;
  const totalSamples = state.mergedExport.samples.length;
  if (elements.mergedExportDescription) {
    elements.mergedExportDescription.textContent = `已从 ${state.mergedExport.tasks.length} 个任务中汇总 ${totalSamples} 个样本。可对样本进行筛选、勾选和排序，最终将当前选中的样本按当前排序顺序导出。`;
  }
  if (elements.mergedExportFormat) {
    elements.mergedExportFormat.value = state.mergedExport.exportFormat || "xlsx";
  }
  if (elements.mergedExportFilteredButton) {
    elements.mergedExportFilteredButton.disabled = state.mergedExport.loading || !filteredSamples.length;
  }
  if (elements.mergedExportSelectedButton) {
    elements.mergedExportSelectedButton.disabled = state.mergedExport.loading || !selectedVisibleCount;
  }
  if (state.mergedExport.loading) {
    elements.mergedExportBody.innerHTML = `
      <div class="merged-export-loading">
        <strong>正在合并任务结果</strong>
        <span>逐个读取已完成任务的样本摘要，字段缺失会自动以 “-” 补齐。</span>
      </div>
    `;
    return;
  }
  const abnormalTasks = state.mergedExport.tasks.filter((task) => task.abnormal);
  const allVisibleSelected = Boolean(filteredSamples.length) && filteredSamples.every((sample) => selectedIds.has(sample.sample_id));
  const partialVisibleSelected = filteredSamples.some((sample) => selectedIds.has(sample.sample_id)) && !allVisibleSelected;
  elements.mergedExportBody.innerHTML = `
    <div class="merged-export-stats">
      ${renderMergedExportStat("来源任务数", state.mergedExport.tasks.length)}
      ${renderMergedExportStat("总样本数", totalSamples)}
      ${renderMergedExportStat("当前筛选样本数", filteredSamples.length)}
      ${renderMergedExportStat("已勾选样本数", selectedVisibleCount)}
    </div>
    ${abnormalTasks.length ? `
      <div class="merged-export-warning">
        ${escapeHtml(`${abnormalTasks.length} 个任务结果读取异常，已跳过其样本并继续合并其他任务。`)}
      </div>
    ` : ""}
    <div class="merged-export-filters">
      ${renderMergedFilterInput("任务名称", "taskName")}
      ${renderMergedFilterInput("样本名称", "sampleName")}
      ${renderMergedFilterInput("状态", "status")}
      ${renderMergedFilterInput("物种", "species")}
      ${renderMergedFilterInput("ST 型", "mlst")}
      ${renderMergedFilterInput("血清型", "serotype")}
      ${renderMergedFilterInput("完整性最小", "completenessMin", "number")}
      ${renderMergedFilterInput("完整性最大", "completenessMax", "number")}
      ${renderMergedFilterInput("污染率最小", "contaminationMin", "number")}
      ${renderMergedFilterInput("污染率最大", "contaminationMax", "number")}
      <label class="merged-filter-field">
        <span>耐药/毒力</span>
        <select data-merged-filter="resistanceVirulence">
          <option value="all" ${state.mergedExport.filters.resistanceVirulence === "all" ? "selected" : ""}>全部</option>
          <option value="detected" ${state.mergedExport.filters.resistanceVirulence === "detected" ? "selected" : ""}>有检出</option>
          <option value="none" ${state.mergedExport.filters.resistanceVirulence === "none" ? "selected" : ""}>未检出</option>
        </select>
      </label>
      <label class="merged-filter-field">
        <span>关注说明</span>
        <select data-merged-filter="noteMode">
          <option value="all" ${state.mergedExport.filters.noteMode === "all" ? "selected" : ""}>全部</option>
          <option value="has" ${state.mergedExport.filters.noteMode === "has" ? "selected" : ""}>有说明</option>
          <option value="empty" ${state.mergedExport.filters.noteMode === "empty" ? "selected" : ""}>为空</option>
        </select>
      </label>
    </div>
    <div class="merged-export-table-shell">
      <table class="merged-export-table">
        <thead>
          <tr>
            <th class="merged-check-cell">
              <input type="checkbox" data-merged-select-visible ${allVisibleSelected ? "checked" : ""} ${filteredSamples.length ? "" : "disabled"} ${partialVisibleSelected ? "data-indeterminate=\"true\"" : ""} aria-label="全选当前筛选结果">
            </th>
            ${MERGED_SAMPLE_COLUMNS.map((column) => `
              <th>
                ${column.sortable ? `<button type="button" data-merged-sort="${escapeHtml(column.key)}">${escapeHtml(column.label)}${state.mergedExport.sortKey === column.key ? ` ${state.mergedExport.sortDirection === "desc" ? "↓" : "↑"}` : ""}</button>` : escapeHtml(column.label)}
              </th>
            `).join("")}
          </tr>
        </thead>
        <tbody>
          ${filteredSamples.length ? filteredSamples.map((sample) => renderMergedSampleRow(sample, selectedIds.has(sample.sample_id))).join("") : `
            <tr><td colspan="${MERGED_SAMPLE_COLUMNS.length + 1}" class="merged-empty-cell">当前筛选范围内没有样本。</td></tr>
          `}
        </tbody>
      </table>
    </div>
  `;
  bindMergedExportModalEvents();
  if (focusKey) {
    const target = elements.mergedExportBody.querySelector(`[data-merged-filter="${CSS.escape(focusKey)}"]`);
    if (target instanceof HTMLInputElement || target instanceof HTMLSelectElement) {
      target.focus();
      if (target instanceof HTMLInputElement) {
        const nextPos = Math.min(caretPosition ?? target.value.length, target.value.length);
        target.setSelectionRange(nextPos, nextPos);
      }
    }
  }
}

function renderMergedExportStat(label, value) {
  return `<article><span>${escapeHtml(label)}</span><strong>${escapeHtml(formatNumber(value))}</strong></article>`;
}

function renderMergedFilterInput(label, key, type = "text") {
  return `
    <label class="merged-filter-field">
      <span>${escapeHtml(label)}</span>
      <input type="${escapeHtml(type)}" data-merged-filter="${escapeHtml(key)}" value="${escapeHtml(state.mergedExport.filters[key] || "")}">
    </label>
  `;
}

function renderMergedSampleRow(sample, checked) {
  return `
    <tr class="${checked ? "is-selected" : ""}">
      <td class="merged-check-cell"><input type="checkbox" data-merged-sample="${escapeHtml(sample.sample_id)}" ${checked ? "checked" : ""} aria-label="选择 ${escapeHtml(sample.sample_name)}"></td>
      ${MERGED_SAMPLE_COLUMNS.map((column) => `<td>${escapeHtml(sample[column.key] ?? "-")}</td>`).join("")}
    </tr>
  `;
}

function bindMergedExportModalEvents() {
  elements.mergedExportBody.querySelectorAll("[data-merged-filter]").forEach((field) => {
    field.addEventListener("input", () => {
      const key = field.dataset.mergedFilter;
      state.mergedExport.filters[key] = field.value;
      renderMergedExportModal(key, field.selectionStart ?? field.value.length);
    });
    field.addEventListener("change", () => {
      const key = field.dataset.mergedFilter;
      state.mergedExport.filters[key] = field.value;
      renderMergedExportModal(key, field.selectionStart ?? field.value.length);
    });
  });
  elements.mergedExportBody.querySelectorAll("[data-merged-sort]").forEach((button) => {
    button.addEventListener("click", () => {
      const key = String(button.dataset.mergedSort || "");
      if (state.mergedExport.sortKey === key) {
        state.mergedExport.sortDirection = state.mergedExport.sortDirection === "asc" ? "desc" : "asc";
      } else {
        state.mergedExport.sortKey = key;
        state.mergedExport.sortDirection = "asc";
      }
      renderMergedExportModal();
    });
  });
  elements.mergedExportBody.querySelectorAll("[data-merged-select-visible]").forEach((input) => {
    input.indeterminate = input.dataset.indeterminate === "true";
    input.addEventListener("change", () => {
      const current = new Set(state.mergedExport.selectedSampleIds || []);
      getMergedFilteredSortedSamples().forEach((sample) => {
        if (input.checked) current.add(sample.sample_id);
        else current.delete(sample.sample_id);
      });
      state.mergedExport.selectedSampleIds = Array.from(current);
      renderMergedExportModal();
    });
  });
  elements.mergedExportBody.querySelectorAll("[data-merged-sample]").forEach((input) => {
    input.addEventListener("change", () => {
      const current = new Set(state.mergedExport.selectedSampleIds || []);
      const sampleId = String(input.dataset.mergedSample || "");
      if (input.checked) current.add(sampleId);
      else current.delete(sampleId);
      state.mergedExport.selectedSampleIds = Array.from(current);
      renderMergedExportModal();
    });
  });
}

function getMergedFilteredSortedSamples() {
  const filters = state.mergedExport.filters || {};
  const filtered = (state.mergedExport.samples || []).filter((sample) => {
    if (!mergedTextMatches(sample.task_name, filters.taskName)) return false;
    if (!mergedTextMatches(sample.sample_name, filters.sampleName)) return false;
    if (!mergedTextMatches(sample.status, filters.status)) return false;
    if (!mergedTextMatches(sample.species, filters.species)) return false;
    if (!mergedTextMatches(sample.mlst, filters.mlst)) return false;
    if (!mergedTextMatches(sample.serotype, filters.serotype)) return false;
    if (!mergedRangeMatches(sample.completeness_value, filters.completenessMin, filters.completenessMax)) return false;
    if (!mergedRangeMatches(sample.contamination_value, filters.contaminationMin, filters.contaminationMax)) return false;
    if (filters.resistanceVirulence === "detected" && !(Number(sample.resistance_virulence_count || 0) > 0)) return false;
    if (filters.resistanceVirulence === "none" && Number(sample.resistance_virulence_count || 0) > 0) return false;
    const noteHasValue = String(sample.note || "").trim() && String(sample.note || "").trim() !== "-";
    if (filters.noteMode === "has" && !noteHasValue) return false;
    if (filters.noteMode === "empty" && noteHasValue) return false;
    return true;
  });
  return filtered.sort(compareMergedSamples);
}

function mergedTextMatches(value, keyword) {
  const query = String(keyword || "").trim().toLowerCase();
  if (!query) return true;
  return String(value || "").toLowerCase().includes(query);
}

function mergedRangeMatches(value, minValue, maxValue) {
  const numeric = coerceFiniteNumber(value);
  const min = coerceFiniteNumber(minValue);
  const max = coerceFiniteNumber(maxValue);
  if (min === null && max === null) return true;
  if (numeric === null) return false;
  if (min !== null && numeric < min) return false;
  if (max !== null && numeric > max) return false;
  return true;
}

function compareMergedSamples(left, right) {
  const column = MERGED_SAMPLE_COLUMNS.find((item) => item.key === state.mergedExport.sortKey) || MERGED_SAMPLE_COLUMNS[2];
  const factor = state.mergedExport.sortDirection === "desc" ? -1 : 1;
  if (column.numericKey) {
    const leftValue = coerceFiniteNumber(left[column.numericKey]);
    const rightValue = coerceFiniteNumber(right[column.numericKey]);
    if (leftValue !== null || rightValue !== null) {
      return ((leftValue ?? -Infinity) - (rightValue ?? -Infinity)) * factor;
    }
  }
  return compareText(left[column.key], right[column.key]) * factor;
}

async function exportMergedSamples(mode) {
  const filtered = getMergedFilteredSortedSamples();
  const selectedIds = new Set(state.mergedExport.selectedSampleIds || []);
  const rows = mode === "selected" ? filtered.filter((sample) => selectedIds.has(sample.sample_id)) : filtered;
  if (mode === "selected" && !rows.length) {
    showToast("请先勾选样本，或选择“导出当前筛选结果”。", "warning");
    return;
  }
  if (!rows.length) {
    showToast("当前筛选范围内没有可导出的样本。", "warning");
    return;
  }
  const format = state.mergedExport.exportFormat || "xlsx";
  const columns = MERGED_SAMPLE_COLUMNS.map((column) => column.label);
  const sampleRows = rows.map((sample) => MERGED_SAMPLE_COLUMNS.map((column) => sample[column.key] ?? "-"));
  const taskColumns = ["任务 ID", "任务名称", "任务类型", "创建时间", "状态", "读取状态", "说明"];
  const taskRows = state.mergedExport.tasks.map((task) => [
    task.task_id,
    task.task_name,
    task.task_type,
    task.created_at,
    task.status,
    task.abnormal ? "异常" : "正常",
    task.note || "-",
  ]);
  const infoRows = buildMergedExportInfoRows(mode, rows.length);
  const payload = {
    title: "merged_samples",
    filename: `merged_samples_${new Date().toISOString().slice(0, 19).replace(/[:T]/g, "")}`,
    format,
    columns,
    rows: sampleRows,
  };
  if (format === "xlsx") {
    payload.sheets = [
      { title: "merged_samples", columns, rows: sampleRows },
      { title: "selected_tasks", columns: taskColumns, rows: taskRows },
      { title: "export_info", columns: ["项目", "内容"], rows: infoRows },
    ];
  }
  await downloadExportTable(payload);
  showToast(`已导出 ${rows.length} 个样本。`);
}

function buildMergedExportInfoRows(mode, sampleCount) {
  const filters = state.mergedExport.filters || {};
  const activeFilters = Object.entries(filters)
    .filter(([, value]) => String(value || "").trim() && !["all"].includes(String(value || "").trim()))
    .map(([key, value]) => `${key}: ${value}`);
  return [
    ["导出时间", new Date().toLocaleString()],
    ["导出范围", mode === "selected" ? "已勾选样本" : "当前筛选结果"],
    ["来源任务数", String(state.mergedExport.tasks.length)],
    ["样本数量", String(sampleCount)],
    ["筛选条件", activeFilters.join("；") || "未启用"],
    ["排序方式", `${state.mergedExport.sortKey} ${state.mergedExport.sortDirection}`],
  ];
}

async function downloadExportTable(payload) {
  const response = await fetch("/api/export/table", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  if (!response.ok) {
    let message = "导出失败";
    try {
      const data = await response.json();
      message = data.error || message;
    } catch (_error) {}
    showToast(message, "error");
    throw new Error(message);
  }
  const blob = await response.blob();
  const disposition = response.headers.get("Content-Disposition") || "";
  const filenameMatch = disposition.match(/filename\*=UTF-8''([^;]+)/);
  const filename = filenameMatch ? decodeURIComponent(filenameMatch[1]) : "merged_samples.xlsx";
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = filename;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

function renderQueueWorkbench(tasks) {
  const columns = [
    { key: "name", label: "任务名称", filterable: true, sortable: true },
    { key: "owner", label: "归属用户", filterable: true, sortable: true },
    { key: "asmType", label: "组装方式", filterable: true, sortable: true },
    { key: "method", label: "组装软件", filterable: true, sortable: true },
    { key: "runtime", label: "运行时间", filterable: true, sortable: true },
  ];
  const rows = tasks.map((task) => ({
    task,
    values: {
      name: String(task.name || task.id || "-"),
      owner: String(task.owner || "-"),
      asmType: String(getAsmTypeLabel(task.params?.asm_type)),
      method: String(task.params?.method || "-"),
      runtime: String(getTaskRunTimeLabel(task)),
      actions: "",
      status: String(task.status || "未知"),
      runtimeRaw: String(task.started_at || task.created_at || ""),
    },
  }));

  if (!tasks.some((task) => task.id === state.selectedTaskId)) {
    state.selectedTaskId = tasks[0]?.id || "";
    state.currentTaskDetail = null;
  }

  const applyState = (focusKey = "", caretPosition = null) => {
    const previousFrame = elements.taskList.querySelector(".queue-rail");
    if (previousFrame) {
      state.queueTable.scrollTop = previousFrame.scrollTop;
    }
    const previousInspector = elements.taskList.querySelector(".queue-inspector-scroll");
    if (previousInspector) {
      state.queueTable.inspectorScrollTop = previousInspector.scrollTop;
    }

    const activeFilters = Object.entries(state.queueTable.filters)
      .filter(([, value]) => String(value || "").trim())
      .map(([key, value]) => ({ key, value: String(value).trim(), label: columns.find((item) => item.key === key)?.label || key }));

    const filteredRows = rows.filter((row) => columns.every((column) => {
      if (!column.filterable) return true;
      const keyword = String(state.queueTable.filters[column.key] || "").trim().toLowerCase();
      if (!keyword) return true;
      return String(row.values[column.key] || "").toLowerCase().includes(keyword);
    }));

    const sortedRows = filteredRows.slice().sort((left, right) => compareQueueTableRows(left, right, state.queueTable.sortKey, state.queueTable.sortDirection));
    const exportableRows = sortedRows.filter((row) => isTaskMergeExportable(row.task));
    const selectedTaskIds = new Set(state.queueSelectedTaskIds || []);
    const selectedExportableCount = state.queueSelectedTaskIds
      .map((taskId) => state.tasks.find((task) => String(task.id || "") === String(taskId)))
      .filter((task) => task && isTaskMergeExportable(task)).length;
    const allVisibleExportableSelected = Boolean(exportableRows.length) && exportableRows.every((row) => selectedTaskIds.has(String(row.task.id || "")));
    const partialVisibleExportableSelected = exportableRows.some((row) => selectedTaskIds.has(String(row.task.id || ""))) && !allVisibleExportableSelected;
    if (!sortedRows.some((row) => row.task.id === state.selectedTaskId)) {
      state.selectedTaskId = sortedRows[0]?.task.id || "";
      state.currentTaskDetail = null;
    }
    const selectedRow = sortedRows.find((row) => row.task.id === state.selectedTaskId) || sortedRows[0] || null;
    const selectedTask = selectedRow?.task || null;
    const selectedSummary = selectedTask ? buildQueueInspectorSummary(selectedTask) : null;
    const statusOptions = [
      ["ALL", "全部"],
      ["RUNNING", "运行中"],
      ["PAUSED", "已暂停"],
      ["SUCCEEDED", "已完成"],
      ["FAILED", "失败"],
      ["QUEUED", "排队中"],
      ["STOPPED", "已停止"],
    ];
    const sortOptions = columns
      .filter((column) => column.sortable)
      .flatMap((column) => ([
        { key: column.key, direction: "asc", label: `${column.label} · 升序` },
        { key: column.key, direction: "desc", label: `${column.label} · 降序` },
      ]));

    elements.taskList.innerHTML = `
      <section class="queue-workbench">
        <div class="queue-command-panel">
          <div class="queue-dispatch-band queue-dispatch-band-unified">
            <div class="queue-command-copy queue-command-copy-inline">
              <strong>当前显示 ${sortedRows.length} / ${rows.length} 个任务</strong>
              <span>默认排序：${buildQueueSortLabel(columns)}</span>
              <label class="queue-merge-select-all">
                <input type="checkbox" data-merge-select-visible ${allVisibleExportableSelected ? "checked" : ""} ${exportableRows.length ? "" : "disabled"} ${partialVisibleExportableSelected ? "data-indeterminate=\"true\"" : ""}>
                <span>选择当前筛选结果中的已完成任务</span>
              </label>
            </div>
            <div class="queue-command-tools">
              <button class="primary-button queue-merge-export-button" type="button" data-open-merge-export ${selectedExportableCount ? "" : "disabled"}>合并导出</button>
              <span class="queue-merge-selected-count">已选择 ${selectedExportableCount} 个任务</span>
              <details class="queue-control-menu" ${state.queueTable.sortMenuOpen ? "open" : ""} data-queue-sort-menu>
                <summary class="queue-control-trigger">
                  <span>排序</span>
                  <strong>${escapeHtml(buildQueueSortLabel(columns))}</strong>
                </summary>
                <div class="queue-control-popover">
                  <div class="queue-control-popover-head">
                    <strong>排序方式</strong>
                    <span>选择列与顺序</span>
                  </div>
                  <div class="queue-option-list">
                    ${sortOptions.map((option) => `
                      <button
                        class="queue-option-button ${(state.queueTable.sortKey === option.key && state.queueTable.sortDirection === option.direction) ? "active" : ""}"
                        type="button"
                        data-queue-sort-option="${escapeHtml(`${option.key}:${option.direction}`)}"
                      >${escapeHtml(option.label)}</button>
                    `).join("")}
                  </div>
                </div>
              </details>
              <details class="queue-control-menu queue-filter-menu" ${state.queueTable.filterMenuOpen ? "open" : ""} data-queue-filter-menu>
                <summary class="queue-control-trigger">
                  <span>筛选</span>
                  <strong>${activeFilters.length || state.queueControls.status !== "ALL" ? `已启用 ${activeFilters.length + (state.queueControls.status !== "ALL" ? 1 : 0)} 项` : "未启用"}</strong>
                </summary>
                <div class="queue-control-popover queue-control-popover-wide">
                  <div class="queue-control-popover-head">
                    <strong>筛选条件</strong>
                    <span>状态和列筛选统一在这里调整</span>
                  </div>
                  <div class="queue-filter-block">
                    <span class="queue-filter-block-label">任务状态</span>
                    <div class="queue-dispatch-status" role="tablist" aria-label="任务状态筛选">
                      ${statusOptions.map(([value, label]) => `
                        <button class="queue-dispatch-status-button ${state.queueControls.status === value ? "active" : ""}" type="button" data-dispatch-status="${escapeHtml(value)}">${escapeHtml(label)}</button>
                      `).join("")}
                    </div>
                  </div>
                  <div class="queue-filter-block">
                    <span class="queue-filter-block-label">按列筛选</span>
                    <div class="queue-column-filters">
	                      ${columns.map((column) => `
	                        <label class="queue-column-filter">
	                          <span>${escapeHtml(column.label)}</span>
	                          ${renderTableFilterInput({
	                            value: state.queueTable.filters[column.key] || "",
	                            dataName: "data-queue-filter",
	                            dataValue: column.key,
	                            clearDataName: "data-clear-queue-filter",
	                          })}
	                        </label>
	                      `).join("")}
                    </div>
                  </div>
                </div>
              </details>
            </div>
          </div>
        </div>
        <div class="queue-console-grid">
	          <div class="queue-rail">
	            ${sortedRows.length ? sortedRows.map((row, index) => renderQueueRailItem(row, index)).join("") : renderEmptyState({
	              title: "当前没有符合条件的任务",
	              reason: rows.length ? "任务队列里有记录，但当前状态、列筛选或搜索词把它们全部过滤掉了。" : "当前还没有提交或生成任何分析任务。",
	              action: rows.length ? "清空部分筛选条件，或切回“全部”状态后再查看。" : "先提交一个分析任务，或使用示例数据生成 Demo 任务。",
	              className: "queue-empty queue-rail-empty",
	            })}
	          </div>
	          <aside class="queue-inspector">
	            ${selectedTask ? renderQueueInspector(selectedTask, selectedSummary) : renderEmptyState({
	              title: "当前没有可展示任务",
	              reason: "右侧详情依赖左侧任务选择；当前筛选范围内没有可选任务。",
	              action: "放宽筛选条件，或先提交新任务后再查看详情。",
	              className: "queue-empty queue-inspector-empty",
	            })}
	          </aside>
        </div>
      </section>
    `;

    const frame = elements.taskList.querySelector(".queue-rail");
    if (frame) {
      frame.scrollTop = state.queueTable.scrollTop;
      frame.addEventListener("scroll", () => {
        state.queueTable.scrollTop = frame.scrollTop;
      }, { passive: true });
    }
    const inspectorFrame = elements.taskList.querySelector(".queue-inspector-scroll");
    if (inspectorFrame) {
      inspectorFrame.scrollTop = state.queueTable.inspectorScrollTop || 0;
      inspectorFrame.addEventListener("scroll", () => {
        state.queueTable.inspectorScrollTop = inspectorFrame.scrollTop;
      }, { passive: true });
    }

    elements.taskList.querySelectorAll("[data-queue-sort-option]").forEach((button) => {
      button.addEventListener("click", () => {
        const [key, direction] = String(button.dataset.queueSortOption || "").split(":");
        if (!key || !direction) return;
        state.queueTable.sortKey = key;
        state.queueTable.sortDirection = direction;
        state.queueTable.sortMenuOpen = false;
        applyState();
      });
    });

    elements.taskList.querySelectorAll("[data-merge-select-visible]").forEach((input) => {
      input.indeterminate = input.dataset.indeterminate === "true";
      input.addEventListener("change", () => {
        toggleVisibleMergeTaskSelection(exportableRows.map((row) => row.task.id), input.checked);
        applyState();
      });
    });

    elements.taskList.querySelectorAll("[data-open-merge-export]").forEach((button) => {
      button.addEventListener("click", () => openMergedExportPreview());
    });

    elements.taskList.querySelectorAll("[data-queue-task-checkbox]").forEach((input) => {
      input.addEventListener("click", (event) => event.stopPropagation());
      input.addEventListener("change", () => {
        const taskId = String(input.dataset.queueTaskCheckbox || "");
        const task = state.tasks.find((item) => String(item.id || "") === taskId);
        if (!task) return;
        if (!isTaskMergeExportable(task)) {
          showToast("仅已完成任务支持合并导出。", "warning");
          input.checked = false;
          return;
        }
        toggleMergeTaskSelection(taskId, input.checked);
        applyState();
      });
    });

    elements.taskList.querySelector("[data-queue-sort-menu]")?.addEventListener("toggle", (event) => {
      state.queueTable.sortMenuOpen = Boolean(event.currentTarget?.open);
    });

    elements.taskList.querySelector("[data-queue-filter-menu]")?.addEventListener("toggle", (event) => {
      state.queueTable.filterMenuOpen = Boolean(event.currentTarget?.open);
    });

    elements.taskList.querySelectorAll("[data-dispatch-status]").forEach((button) => {
      button.addEventListener("click", () => {
        state.queueControls.status = String(button.dataset.dispatchStatus || "ALL");
        state.queueTable.filterMenuOpen = true;
        renderTaskList();
      });
    });

    elements.taskList.querySelectorAll("[data-queue-select]").forEach((button) => {
      button.addEventListener("click", async () => {
        const taskId = String(button.dataset.queueSelect || "");
        if (!taskId || taskId === state.selectedTaskId) return;
        state.selectedTaskId = taskId;
        state.currentTaskDetail = null;
        state.currentQueueReport = null;
        state.queueTable.inspectorScrollTop = 0;
        renderTaskList();
        await preloadQueueInspector(taskId);
      });
    });

    elements.taskList.querySelectorAll("[data-queue-filter]").forEach((input) => {
      input.addEventListener("compositionstart", () => {
        input.dataset.imeComposing = "1";
      });
      input.addEventListener("compositionend", (event) => {
        input.dataset.imeComposing = "0";
        const key = String(input.dataset.queueFilter || "");
        state.queueTable.filters[key] = event.currentTarget.value;
        state.queueTable.filterMenuOpen = true;
        applyState(key, event.currentTarget.selectionStart ?? event.currentTarget.value.length);
      });
      input.addEventListener("input", (event) => {
        if (event.isComposing || input.dataset.imeComposing === "1") return;
        const key = String(input.dataset.queueFilter || "");
        state.queueTable.filters[key] = input.value;
        state.queueTable.filterMenuOpen = true;
        applyState(key, input.selectionStart ?? input.value.length);
      });
    });

    elements.taskList.querySelectorAll("[data-clear-queue-filter]").forEach((button) => {
      button.addEventListener("click", () => {
        const key = String(button.dataset.clearQueueFilter || "");
        if (key === "__status__") {
          state.queueControls.status = "ALL";
          state.queueTable.filterMenuOpen = false;
          renderTaskList();
          return;
        }
        state.queueTable.filters[key] = "";
        state.queueTable.filterMenuOpen = true;
        applyState(key, 0);
      });
    });

    bindQueueRowActions();
    if (selectedTask) {
      preloadQueueInspector(selectedTask.id);
    }

    if (focusKey) {
      const target = elements.taskList.querySelector(`[data-queue-filter="${focusKey}"]`);
      if (target && target.dataset.imeComposing !== "1") {
        target.focus();
        const nextPos = Math.min(caretPosition ?? target.value.length, target.value.length);
        target.setSelectionRange(nextPos, nextPos);
      }
    }
  };

  applyState();
}

function renderQueueRailItem(row, index) {
  const task = row.task;
  const isActive = task.id === state.selectedTaskId ? " active" : "";
  const isExportable = isTaskMergeExportable(task);
  const isMergeSelected = state.queueSelectedTaskIds.includes(String(task.id || ""));
  const selectedClass = isMergeSelected ? " merge-selected" : "";
  const subtitle = [task.owner || "-", getAsmTypeLabel(task.params?.asm_type), task.params?.method || "-"].join(" · ");
  const progress = buildTaskProgressView(task);
  const showProgressBlock = String(task.status || "").toUpperCase() !== "SUCCEEDED";
  return `
    <article class="queue-rail-item${isActive}${selectedClass}" data-task-row="${escapeHtml(task.id)}">
      <div class="queue-rail-rowline">
        <label class="queue-task-checkbox-wrap" title="${isExportable ? "选择该任务用于合并导出" : "仅已完成任务支持合并导出。"}">
          <input
            type="checkbox"
            data-queue-task-checkbox="${escapeHtml(task.id)}"
            ${isMergeSelected ? "checked" : ""}
            ${isExportable ? "" : "disabled"}
            aria-label="选择 ${escapeHtml(task.name || task.id)} 用于合并导出"
          >
        </label>
        <button class="queue-rail-select" type="button" data-queue-select="${escapeHtml(task.id)}" aria-label="查看 ${escapeHtml(task.name || task.id)}">
          <span class="queue-rail-index">${String(index + 1).padStart(2, "0")}</span>
          <span class="queue-rail-content">
            <span class="queue-rail-topline">
              <strong>${escapeHtml(task.name || task.id)}</strong>
              <span class="mini-chip ${statusClassName(task.status)}">${escapeHtml(statusLabel(task.status))}</span>
            </span>
            <span class="queue-rail-subline">${escapeHtml(subtitle)}</span>
            <span class="queue-rail-meta">
              <span>${escapeHtml(getTaskRunTimeLabel(task))}</span>
              <span>${escapeHtml(task.id || "-")}</span>
            </span>
            ${showProgressBlock ? renderQueueProgressBlock(progress, "rail") : ""}
          </span>
        </button>
      </div>
      <div class="queue-rail-actions">
        <span class="queue-rail-index-mobile">${String(index + 1).padStart(2, "0")}</span>
        <button class="task-utility-button task-result-button" type="button" data-task-open="${escapeHtml(task.id)}">结果</button>
        <details class="task-action-menu">
          <summary class="task-utility-button task-more-button">更多</summary>
          <div class="task-action-popover">
            <button class="task-action-menu-item" type="button" data-task-action="browse_output" data-task-id="${escapeHtml(task.id)}">打开分析文件夹</button>
            <button class="task-action-menu-item" type="button" data-task-action="import_database" data-task-id="${escapeHtml(task.id)}">导入数据库</button>
            ${renderTaskLifecycleActions(task)}
            <button class="task-action-menu-item" type="button" data-task-action="log" data-task-id="${escapeHtml(task.id)}">日志</button>
            <button class="task-action-menu-item" type="button" data-task-action="meta" data-task-id="${escapeHtml(task.id)}">任务详情</button>
            ${canRebuildTask(task) ? `<button class="task-action-menu-item" type="button" data-task-action="rerun" data-task-id="${escapeHtml(task.id)}">重新运行</button>` : ""}
            ${canRebuildTask(task) ? `<button class="task-action-menu-item" type="button" data-task-action="rebuild" data-task-id="${escapeHtml(task.id)}">重建任务</button>` : ""}
            ${canDeleteTask(task) ? `<button class="task-action-menu-item task-action-menu-item-danger" type="button" data-task-action="delete" data-task-id="${escapeHtml(task.id)}">删除任务</button>` : ""}
          </div>
        </details>
      </div>
    </article>
  `;
}

function bindQueueRowActions() {
  elements.taskList.querySelectorAll(".task-action-menu").forEach((menu) => {
    menu.addEventListener("toggle", () => {
      const taskCard = menu.closest(".queue-rail-item, .queue-inspector-shell");
      if (!taskCard) return;
      taskCard.classList.toggle("menu-open", menu.open);
    });
  });

  elements.taskList.querySelectorAll("[data-task-row]").forEach((rowNode) => {
    rowNode.addEventListener("dblclick", () => {
      const taskId = rowNode.dataset.taskRow || "";
      if (taskId) {
        window.location.href = `/tasks/${encodeURIComponent(taskId)}/result-page`;
      }
    });
  });

  elements.taskList.querySelectorAll("[data-task-open]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.stopPropagation();
      const taskId = button.dataset.taskOpen || "";
      if (taskId) {
        window.location.href = `/tasks/${encodeURIComponent(taskId)}/result-page`;
      }
    });
  });

  elements.taskList.querySelectorAll("[data-queue-inspector-anchor]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const sectionKey = String(button.dataset.queueInspectorAnchor || "").trim();
      const inspector = button.closest(".queue-inspector-shell");
      const scrollFrame = inspector?.querySelector(".queue-inspector-scroll");
      const target = inspector?.querySelector(`[data-queue-inspector-section="${CSS.escape(sectionKey)}"]`);
      if (!(scrollFrame instanceof HTMLElement) || !(target instanceof HTMLElement)) return;
      const offset = target.offsetTop - scrollFrame.offsetTop;
      scrollFrame.scrollTo({ top: Math.max(0, offset - 10), behavior: "smooth" });
      inspector.querySelectorAll("[data-queue-inspector-anchor]").forEach((anchor) => {
        anchor.classList.toggle("active", anchor === button);
      });
      target.classList.remove("queue-inspector-section-pulse");
      window.requestAnimationFrame(() => {
        target.classList.add("queue-inspector-section-pulse");
      });
    });
  });

  elements.taskList.querySelectorAll("[data-task-action]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.stopPropagation();
      const taskId = String(button.dataset.taskId || "");
      const action = String(button.dataset.taskAction || "");
      const task = state.tasks.find((item) => item.id === taskId);
      if (!task) return;
      state.currentTaskDetail = null;
      state.currentQueueReport = null;
      state.selectedTaskId = task.id;
      if (action === "delete") {
        await onDeleteTask(task);
        return;
      }
      if (action === "browse_output") {
        await openTaskOutputBrowser(task);
        return;
      }
      if (action === "import_database") {
        await importTaskIntoDatabase(task);
        return;
      }
      if (action === "pause") {
        await onPauseTask(task);
        return;
      }
      if (action === "resume") {
        await onResumeTask(task);
        return;
      }
      if (action === "stop") {
        await onStopTask(task);
        return;
      }
      if (action === "rebuild") {
        await openRebuildFromTaskId(task.id);
        return;
      }
      if (action === "rerun") {
        await openRerunFromTaskId(task.id);
        return;
      }
      setTaskDetailView(action || "log");
      renderTaskList();
      await loadTaskDetail(task.id);
      openTaskDetail();
    });
  });
}

function renderQueueInspector(task, summary) {
  const detail = state.currentTaskDetail && state.currentTaskDetail.id === task.id ? state.currentTaskDetail : null;
  const report = state.currentQueueReport && state.currentQueueReport.task?.id === task.id ? state.currentQueueReport : null;
  const latestLog = detail?.log ? String(detail.log).trim().split("\n").slice(-8).join("\n") : "点击“日志”可查看完整运行日志。";
  const progress = buildTaskProgressView(task);
  const workstationKey = String(task?.params?.workstation_key || "").trim().toLowerCase();
  const isMetaTask = String(task?.params?.method || "").trim().toLowerCase() === "meta";
  const isCommunityTask = String(report?.report_kind || "").trim().toLowerCase() === "community_meta_ecology"
    || String(task?.params?.workstation_key || "").trim().toLowerCase() === "community"
    || String(task?.pipeline_script || "").trim().includes("CommunityAnalysis.py");
  const isPathoSourceTask = String(report?.report_kind || "").trim().toLowerCase() === "pathosource_phylogeny"
    || String(task?.params?.workstation_key || "").trim().toLowerCase() === "pathosource";
  const isVirusTask = workstationKey === "virus"
    || String(task?.params?.analysis_target || "").trim().toLowerCase() === "virus";
  const runflowValues = normalizeRunflowValues(task?.params?.runflow || "");
  const analysisModeLabel = isPathoSourceTask
    ? "分子溯源流程"
    : (isCommunityTask
      ? "群落生态分析流程"
      : (isMetaTask
        ? "宏基因组流程"
        : (isVirusTask ? "病毒分析流程" : getAsmTypeLabel(task.params?.asm_type))));
  const coreFlowLabel = isPathoSourceTask
    ? "成簇 / SNP / ANI / 树"
    : (isCommunityTask
      ? (runflowValues.length ? runflowValues.join(" / ") : "Alpha / Beta / LEfSe / RF / Network")
      : (isMetaTask
        ? (runflowValues.length ? runflowValues.join(" / ") : "分箱 / 分类 / 病毒筛选")
        : (isVirusTask
          ? (runflowValues.length ? runflowValues.join(" / ") : "基因组组装 / 物种鉴定 / 分型鉴定")
          : (task.params?.method || "-"))));
  return `
    <div class="queue-inspector-shell">
      <div class="queue-inspector-fixed">
        <div class="queue-inspector-head">
          <div>
            <p class="section-kicker">Selected Task</p>
            <h3>${escapeHtml(task.name || task.id)}</h3>
            <p class="queue-inspector-copy">${escapeHtml(summary.copy)}</p>
          </div>
          <span class="queue-inspector-status ${statusClassName(task.status)}">${escapeHtml(statusLabel(task.status))}</span>
        </div>
        <div class="queue-inspector-actions">
          <button class="task-utility-button task-result-button task-result-button-strong" type="button" data-task-open="${escapeHtml(task.id)}">打开结果</button>
          <details class="task-action-menu task-action-menu-inspector">
            <summary class="task-utility-button task-more-button">更多操作</summary>
            <div class="task-action-popover">
              <button class="task-action-menu-item" type="button" data-task-action="browse_output" data-task-id="${escapeHtml(task.id)}">打开分析文件夹</button>
              <button class="task-action-menu-item" type="button" data-task-action="import_database" data-task-id="${escapeHtml(task.id)}">导入数据库</button>
              ${renderTaskLifecycleActions(task)}
              <button class="task-action-menu-item" type="button" data-task-action="log" data-task-id="${escapeHtml(task.id)}">日志</button>
              <button class="task-action-menu-item" type="button" data-task-action="meta" data-task-id="${escapeHtml(task.id)}">任务详情</button>
              ${canRebuildTask(task) ? `<button class="task-action-menu-item" type="button" data-task-action="rerun" data-task-id="${escapeHtml(task.id)}">重新运行</button>` : ""}
              ${canRebuildTask(task) ? `<button class="task-action-menu-item" type="button" data-task-action="rebuild" data-task-id="${escapeHtml(task.id)}">重建任务</button>` : ""}
              ${canDeleteTask(task) ? `<button class="task-action-menu-item task-action-menu-item-danger" type="button" data-task-action="delete" data-task-id="${escapeHtml(task.id)}">删除任务</button>` : ""}
            </div>
          </details>
        </div>
        <nav class="queue-inspector-anchors" aria-label="任务详情快速定位">
          <button type="button" data-queue-inspector-anchor="overview">概览</button>
          <button type="button" data-queue-inspector-anchor="progress">进度</button>
          <button type="button" data-queue-inspector-anchor="result">结果</button>
          <button type="button" data-queue-inspector-anchor="log">日志</button>
        </nav>
      </div>
      <div class="queue-inspector-scroll">
        <div class="queue-inspector-section queue-inspector-grid" data-queue-inspector-section="overview">
          <article><span>归属用户</span><strong>${escapeHtml(task.owner || "-")}</strong></article>
          <article><span>${isPathoSourceTask || isMetaTask || isCommunityTask || isVirusTask ? "分析模式" : "组装方式"}</span><strong>${escapeHtml(analysisModeLabel)}</strong></article>
          <article><span>${isPathoSourceTask || isMetaTask || isCommunityTask || isVirusTask ? "核心流程" : "组装软件"}</span><strong>${escapeHtml(coreFlowLabel)}</strong></article>
          <article><span>运行时间</span><strong>${escapeHtml(getTaskRunTimeLabel(task))}</strong></article>
        </div>
        <div class="queue-inspector-section" data-queue-inspector-section="progress">
          ${renderQueueProgressBlock(progress, "inspector")}
        </div>
        ${renderReviewGateBlock(task)}
        <div class="queue-stream-card queue-inspector-section" data-queue-inspector-section="result">
          <div class="queue-stream-head">
            <strong>结果概览</strong>
            <span>${report ? "已同步" : "待加载"}</span>
          </div>
          ${renderQueueResultOverview(report)}
        </div>
        <div class="queue-stream-card queue-inspector-section" data-queue-inspector-section="log">
          <div class="queue-stream-head">
            <strong>日志尾部</strong>
            <span>${detail ? "已同步" : "待加载"}</span>
          </div>
          <pre class="queue-log-preview">${escapeHtml(latestLog)}</pre>
        </div>
      </div>
    </div>
  `;
}

function buildQueueInspectorSummary(task) {
  const reviewGate = task.review_gate || {};
  if (String(reviewGate.state || "").toLowerCase() === "pending") {
    return {
      copy: String(reviewGate.summary || "物种鉴定结果触发了人工复核条件，任务已自动暂停。"),
      emphasis: "待人工确认",
      points: [],
    };
  }
  const statusMap = {
    RUNNING: { copy: "任务正在运行，优先关注运行时间和日志尾部是否持续推进。", emphasis: "运行观察" },
    PAUSED: { copy: "任务已暂停，恢复后会重新进入调度队列，按并发上限继续运行。", emphasis: "暂停待续" },
    FAILED: { copy: "任务运行失败，建议先回看日志尾部，再决定是否重建任务。", emphasis: "失败复核" },
    SUCCEEDED: { copy: "任务已完成，可直接进入结果页进行报告浏览与导出。", emphasis: "结果就绪" },
    QUEUED: { copy: "任务正在排队，当前更适合检查参数和输出目录设置是否合理。", emphasis: "等待调度" },
    STOPPED: { copy: "任务已停止，不会继续执行；如需继续，请重建任务。", emphasis: "任务停止" },
  };
  const preset = statusMap[task.status] || { copy: "当前任务已进入工作台，可继续查看结果、日志或参数详情。", emphasis: "任务快览" };
  return {
    copy: preset.copy,
    emphasis: preset.emphasis,
    points: [],
  };
}

function renderReviewGateBlock(task) {
  const reviewGate = task.review_gate || {};
  if (String(reviewGate.state || "").toLowerCase() !== "pending") {
    return "";
  }
  const evidence = Array.isArray(reviewGate.evidence) ? reviewGate.evidence.filter(Boolean) : [];
  const sampleName = String(reviewGate.sample_name || "").trim();
  return `
    <div class="queue-stream-card queue-review-gate-card">
      <div class="queue-stream-head">
        <strong>人工确认节点</strong>
        <span>物种鉴定后自动拦停</span>
      </div>
      <div class="queue-review-gate-body">
        <strong>${escapeHtml(sampleName ? `${sampleName} 需要人工确认` : "当前任务需要人工确认")}</strong>
        <p>${escapeHtml(String(reviewGate.summary || "物种鉴定结果提示细菌信号偏低或存在明显杂菌污染，建议人工复核后再决定是否继续运行。"))}</p>
        ${evidence.length ? `<ul class="queue-review-gate-list">${evidence.map((item) => `<li>${escapeHtml(String(item))}</li>`).join("")}</ul>` : ""}
        <div class="queue-review-gate-actions">
          <button class="task-utility-button task-result-button" type="button" data-task-open="${escapeHtml(task.id)}">查看结果</button>
          <button class="primary-button" type="button" data-task-action="resume" data-task-id="${escapeHtml(task.id)}">确认后继续运行</button>
        </div>
      </div>
    </div>
  `;
}

async function importTaskIntoDatabase(task) {
  const method = String(task?.params?.method || "").trim().toLowerCase();
  if (method === "meta") {
    const preview = await requestJson(`/api/tasks/${encodeURIComponent(task.id)}/database-import-preview`);
    openMetaDatabaseImportModal(task, preview);
    return;
  }
  const data = await requestJson(`/api/tasks/${encodeURIComponent(task.id)}/database-import`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
  });
  const imported = Number(data.imported_count || 0);
  const skipped = Number(data.skipped_count || 0);
  showToast(
    imported > 0
      ? `已导入 ${imported} 个样本${skipped ? `，跳过 ${skipped} 个` : ""}`
      : `没有可导入样本${skipped ? `，跳过 ${skipped} 个` : ""}`,
    imported <= 0,
  );
  await loadDatabaseRecords();
}

function openMetaDatabaseImportModal(task, preview) {
  const items = Array.isArray(preview?.items) ? preview.items : [];
  state.metaDatabaseImport = {
    open: true,
    taskId: String(task?.id || "").trim(),
    taskName: String(task?.name || task?.id || "").trim(),
    items,
    selected: Object.fromEntries(items.filter((item) => item && item.available).map((item) => [String(item.bin_name || ""), true])),
    table: {
      sortKey: "bin_name",
      sortDirection: "asc",
      filters: {
        bin_name: "",
        completeness: "",
        contamination: "",
        species_name: "",
        status: "",
      },
    },
  };
  if (elements.metaDatabaseImportNote) {
    elements.metaDatabaseImportNote.textContent = `${state.metaDatabaseImport.taskName || "当前任务"} 共识别 ${items.length} 个 bin，勾选后会提取对应 fasta 导入样本数据库。`;
  }
  renderMetaDatabaseImportTable();
  elements.metaDatabaseImportModal?.classList.remove("hidden");
  elements.metaDatabaseImportModal?.setAttribute("aria-hidden", "false");
}

function closeMetaDatabaseImportModal() {
  state.metaDatabaseImport = {
    open: false,
    taskId: "",
    taskName: "",
    items: [],
    selected: {},
    table: {
      sortKey: "bin_name",
      sortDirection: "asc",
      filters: {
        bin_name: "",
        completeness: "",
        contamination: "",
        species_name: "",
        status: "",
      },
    },
  };
  if (elements.metaDatabaseImportRows) {
    elements.metaDatabaseImportRows.innerHTML = `
      <tr>
        <td colspan="6" class="meta-database-import-empty">正在加载可导入 bin...</td>
      </tr>
    `;
  }
  if (elements.metaDatabaseImportSelectAll) {
    elements.metaDatabaseImportSelectAll.checked = false;
    elements.metaDatabaseImportSelectAll.indeterminate = false;
  }
  if (elements.metaDatabaseImportSummary) elements.metaDatabaseImportSummary.textContent = "已选 0 / 0";
  elements.metaDatabaseImportModal?.classList.add("hidden");
  elements.metaDatabaseImportModal?.setAttribute("aria-hidden", "true");
}

function renderMetaDatabaseImportTable() {
  const items = state.metaDatabaseImport.items || [];
  const selected = state.metaDatabaseImport.selected || {};
  const tableState = state.metaDatabaseImport.table || {};
  if (!elements.metaDatabaseImportRows) return;
  if (!items.length) {
    elements.metaDatabaseImportRows.innerHTML = `
      <tr>
        <td colspan="6" class="meta-database-import-empty">当前没有可导入的 bin 记录。</td>
      </tr>
    `;
    syncMetaDatabaseImportSummary();
    return;
  }
  const visibleItems = getSortedMetaDatabaseImportRows(getFilteredMetaDatabaseImportRows(items, tableState), tableState);
  elements.metaDatabaseImportRows.innerHTML = visibleItems.map((item) => {
    const binName = String(item?.bin_name || "").trim();
    const available = Boolean(item?.available);
    const checked = available && Boolean(selected[binName]);
    return `
      <tr>
        <td class="meta-import-check-col"${renderMobileCellAttributes("选择", "selection")}>
          <input type="checkbox" data-meta-bin="${escapeHtml(binName)}" ${checked ? "checked" : ""} ${available ? "" : "disabled"}>
        </td>
        <td${renderMobileCellAttributes("Bin名称")}><strong>${escapeHtml(binName || "-")}</strong></td>
        <td${renderMobileCellAttributes("完整性")}>${escapeHtml(String(item?.completeness || "-"))}</td>
        <td${renderMobileCellAttributes("污染率")}>${escapeHtml(String(item?.contamination || "-"))}</td>
        <td${renderMobileCellAttributes("物种名称")}>${escapeHtml(String(item?.species_name || "-"))}</td>
        <td${renderMobileCellAttributes("状态")}><span class="status-chip ${available ? "" : "warning"}">${available ? "可导入" : "缺少 fasta"}</span></td>
      </tr>
    `;
  }).join("");
  syncMetaDatabaseImportSummary();
  renderMetaDatabaseImportHeader();
}

function renderMetaDatabaseImportHeader() {
  const table = elements.metaDatabaseImportRows?.closest("table");
  const thead = table?.querySelector("thead");
  const tableState = state.metaDatabaseImport.table || {};
  if (!thead) return;
  const columns = [
    { key: "bin_name", label: "Bin名称", numeric: false },
    { key: "completeness", label: "完整性", numeric: true },
    { key: "contamination", label: "污染率", numeric: true },
    { key: "species_name", label: "物种名称", numeric: false },
    { key: "status", label: "状态", numeric: false },
  ];
  thead.innerHTML = `
    <tr>
      <th class="meta-import-check-col">选择</th>
      ${columns.map((column) => `
        <th>
          <div class="table-head-stack queue-table-head-stack">
            <button class="database-sort-button table-sort-button ${tableState.sortKey === column.key ? "active" : ""}" type="button" data-meta-import-sort="${escapeHtml(column.key)}">
              <span class="queue-table-head-label">${escapeHtml(column.label)}</span>
              <span>${tableState.sortKey === column.key ? (tableState.sortDirection === "asc" ? "↑" : "↓") : "↕"}</span>
            </button>
            ${renderTableFilterInput({
              value: tableState.filters?.[column.key] || "",
              placeholder: column.numeric ? "如 >90 或 1-5" : "筛选",
              dataName: "data-meta-import-filter",
              dataValue: column.key,
              clearDataName: "data-clear-meta-import-filter",
            })}
          </div>
        </th>
      `).join("")}
    </tr>
  `;
}

function syncMetaDatabaseImportSummary() {
  const tableState = state.metaDatabaseImport.table || {};
  const items = getFilteredMetaDatabaseImportRows(state.metaDatabaseImport.items || [], tableState);
  const availableItems = items.filter((item) => item && item.available);
  const availableCount = availableItems.length;
  const selectedCount = availableItems.filter((item) => Boolean(state.metaDatabaseImport.selected[String(item.bin_name || "")])).length;
  if (elements.metaDatabaseImportSummary) {
    elements.metaDatabaseImportSummary.textContent = `已选 ${selectedCount} / ${availableCount}`;
  }
  if (elements.metaDatabaseImportSelectAll) {
    elements.metaDatabaseImportSelectAll.checked = availableCount > 0 && selectedCount === availableCount;
    elements.metaDatabaseImportSelectAll.indeterminate = selectedCount > 0 && selectedCount < availableCount;
  }
}

function getMetaDatabaseImportCellValue(item, key) {
  if (key === "status") return item?.available ? "可导入" : "缺少 fasta";
  return String(item?.[key] ?? "").trim();
}

function matchMetaDatabaseImportFilter(item, key, rawFilter) {
  const filter = String(rawFilter || "").trim();
  if (!filter) return true;
  if (key === "completeness" || key === "contamination") {
    const numeric = Number.parseFloat(getMetaDatabaseImportCellValue(item, key));
    return matchNumericFilter(numeric, filter);
  }
  return getMetaDatabaseImportCellValue(item, key).toLowerCase().includes(filter.toLowerCase());
}

function getFilteredMetaDatabaseImportRows(items, tableState) {
  const filters = tableState?.filters || {};
  return (items || []).filter((item) => Object.entries(filters).every(([key, value]) => matchMetaDatabaseImportFilter(item, key, value)));
}

function getSortedMetaDatabaseImportRows(items, tableState) {
  const sortKey = String(tableState?.sortKey || "bin_name");
  const direction = tableState?.sortDirection === "desc" ? -1 : 1;
  return [...(items || [])].sort((left, right) => {
    if (sortKey === "completeness" || sortKey === "contamination") {
      const leftNum = Number.parseFloat(getMetaDatabaseImportCellValue(left, sortKey));
      const rightNum = Number.parseFloat(getMetaDatabaseImportCellValue(right, sortKey));
      return ((Number.isFinite(leftNum) ? leftNum : -Infinity) - (Number.isFinite(rightNum) ? rightNum : -Infinity)) * direction;
    }
    return String(getMetaDatabaseImportCellValue(left, sortKey)).localeCompare(String(getMetaDatabaseImportCellValue(right, sortKey)), "zh-CN") * direction;
  });
}

function matchNumericFilter(value, filter) {
  if (!Number.isFinite(value)) return false;
  const text = String(filter || "").trim();
  if (!text) return true;
  const rangeMatch = text.match(/^(-?\d+(?:\.\d+)?)\s*-\s*(-?\d+(?:\.\d+)?)$/);
  if (rangeMatch) {
    const min = Number.parseFloat(rangeMatch[1]);
    const max = Number.parseFloat(rangeMatch[2]);
    return value >= Math.min(min, max) && value <= Math.max(min, max);
  }
  const compareMatch = text.match(/^(>=|<=|>|<|=)\s*(-?\d+(?:\.\d+)?)$/);
  if (compareMatch) {
    const operator = compareMatch[1];
    const target = Number.parseFloat(compareMatch[2]);
    if (operator === ">") return value > target;
    if (operator === "<") return value < target;
    if (operator === ">=") return value >= target;
    if (operator === "<=") return value <= target;
    return value === target;
  }
  const exact = Number.parseFloat(text);
  if (Number.isFinite(exact)) return value === exact;
  return String(value).includes(text);
}

function handleMetaDatabaseImportTableClick(event) {
  const clearButton = event.target.closest("[data-clear-meta-import-filter]");
  if (clearButton) {
    const key = String(clearButton.dataset.clearMetaImportFilter || "").trim();
    if (!key) return;
    state.metaDatabaseImport.table.filters[key] = "";
    renderMetaDatabaseImportTable();
    const nextInput = elements.metaDatabaseImportModal?.querySelector(`[data-meta-import-filter="${CSS.escape(key)}"]`);
    if (nextInput instanceof HTMLInputElement) {
      nextInput.focus();
      nextInput.setSelectionRange(0, 0);
    }
    return;
  }
  const button = event.target.closest("[data-meta-import-sort]");
  if (!button) return;
  const key = String(button.dataset.metaImportSort || "").trim();
  if (!key) return;
  const tableState = state.metaDatabaseImport.table;
  if (tableState.sortKey === key) {
    tableState.sortDirection = tableState.sortDirection === "asc" ? "desc" : "asc";
  } else {
    tableState.sortKey = key;
    tableState.sortDirection = key === "bin_name" || key === "species_name" || key === "status" ? "asc" : "desc";
  }
  renderMetaDatabaseImportTable();
}

function handleMetaDatabaseImportTableInput(event) {
  const input = event.target.closest("[data-meta-import-filter]");
  if (!(input instanceof HTMLInputElement)) return;
  if (event.isComposing || input.dataset.imeComposing === "1") return;
  commitMetaDatabaseImportFilter(input);
}

function commitMetaDatabaseImportFilter(input) {
  if (!(input instanceof HTMLInputElement)) return;
  const key = String(input.dataset.metaImportFilter || "").trim();
  if (!key) return;
  state.metaDatabaseImport.table.filters[key] = input.value;
  renderMetaDatabaseImportTable();
  const nextInput = elements.metaDatabaseImportModal?.querySelector(`[data-meta-import-filter="${CSS.escape(key)}"]`);
  if (nextInput instanceof HTMLInputElement) {
    nextInput.focus();
    const caret = input.selectionStart ?? input.value.length;
    nextInput.setSelectionRange(caret, caret);
  }
}

function toggleAllMetaDatabaseImportBins(event) {
  const checked = Boolean(event?.target?.checked);
  const nextSelected = {};
  (state.metaDatabaseImport.items || []).forEach((item) => {
    const binName = String(item?.bin_name || "").trim();
    if (binName && item?.available && checked) nextSelected[binName] = true;
  });
  state.metaDatabaseImport.selected = nextSelected;
  renderMetaDatabaseImportTable();
}

function handleMetaDatabaseImportRowToggle(event) {
  const target = event?.target;
  if (!(target instanceof HTMLInputElement) || target.type !== "checkbox") return;
  const binName = String(target.dataset.metaBin || "").trim();
  if (!binName) return;
  if (target.checked) {
    state.metaDatabaseImport.selected[binName] = true;
  } else {
    delete state.metaDatabaseImport.selected[binName];
  }
  syncMetaDatabaseImportSummary();
}

async function submitMetaDatabaseImport() {
  const taskId = state.metaDatabaseImport.taskId;
  const selectedBins = Object.keys(state.metaDatabaseImport.selected || {}).filter(Boolean);
  if (!taskId) {
    showToast("当前没有可导入的 Meta 任务。", "warning");
    return;
  }
  if (!selectedBins.length) {
    showToast("请先勾选至少一个 bin。", "warning");
    return;
  }
  const data = await requestJson(`/api/tasks/${encodeURIComponent(taskId)}/database-import`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ selected_bins: selectedBins }),
  });
  const imported = Number(data.imported_count || 0);
  const skipped = Number(data.skipped_count || 0);
  showToast(
    imported > 0
      ? `已导入 ${imported} 个 bin${skipped ? `，跳过 ${skipped} 个` : ""}`
      : `没有成功导入 bin${skipped ? `，跳过 ${skipped} 个` : ""}`,
    imported <= 0,
  );
  closeMetaDatabaseImportModal();
  await loadDatabaseRecords();
}

function buildTaskProgressView(task) {
  const raw = task.progress || {};
  const status = String(task.status || "").toUpperCase();
  const overall = clamp(Number(raw.overall_percent) || 0, 0, 100);
  const sample = clamp(Number(raw.sample_percent) || 0, 0, 100);
  const sampleName = String(raw.sample_name || "").trim();
  const message = String(raw.message || "").trim();
  const sampleIndex = Number(raw.sample_index);
  const sampleTotal = Number(raw.sample_total);
  const step = Number(raw.step);
  const totalStep = Number(raw.total_step);
  const lastLogLine = String(task.last_log_line || "").trim();
  const lastLogPreview = truncateText(lastLogLine, 20);

  if (status === "QUEUED") {
    if (task.resume_pending) {
      return {
        state: "queued",
        title: sampleIndex && sampleTotal ? `样本 ${sampleIndex}/${sampleTotal}${sampleName ? ` · ${sampleName}` : ""}` : "等待恢复",
        body: "任务已加入恢复队列，等待并发槽位释放。",
        lastLogLine,
        lastLogPreview,
        overallPercent: overall,
        samplePercent: sample,
        overallCaption: `总进度 ${formatCompactPercent(overall)}`,
        sampleCaption: `样本进度 ${formatCompactPercent(sample)}`,
        sampleMeta: step && totalStep ? `上次停在步骤 ${step}/${totalStep}` : "",
      };
    }
    const watchState = String(task.watch?.state || "").trim();
    if (watchState) {
      const sampleCount = Number(task.watch?.sample_count || 0);
      const stableMinutes = Number(task.watch?.stable_minutes || 0);
      const stableCaption = stableMinutes > 0 ? `静默窗口 ${stableMinutes} 分钟` : "";
      const progressTitle = String(raw.label || "").trim() || "目录监听中";
      const progressBody = message || "正在等待测序目录稳定后自动生成批量输入表。";
      const sampleMeta = sampleCount > 0
        ? `已识别 ${sampleCount} 个候选样本${stableCaption ? ` · ${stableCaption}` : ""}`
        : stableCaption || "";
      return {
        state: watchState === "limit_exceeded" || watchState === "missing_input" || watchState === "no_samples" ? "warning" : "queued",
        title: progressTitle,
        body: progressBody,
        lastLogLine,
        lastLogPreview,
        overallPercent: overall,
        samplePercent: 0,
        overallCaption: `监听进度 ${formatCompactPercent(overall)}`,
        sampleCaption: sampleCount > 0 ? `候选样本 ${sampleCount}` : "候选样本 0",
        sampleMeta,
      };
    }
    return {
      state: "queued",
      title: "等待调度",
      body: "任务还未开始执行。",
      lastLogLine,
      lastLogPreview,
      overallPercent: 0,
      samplePercent: 0,
      overallCaption: "总进度 0%",
      sampleCaption: "样本进度 0%",
      sampleMeta: "",
    };
  }

  if (status === "PAUSED") {
    return {
      state: "paused",
      title: sampleIndex && sampleTotal ? `样本 ${sampleIndex}/${sampleTotal}${sampleName ? ` · ${sampleName}` : ""}` : "任务已暂停",
      body: message || "任务已暂停，恢复后会重新进入调度队列。",
      lastLogLine,
      lastLogPreview,
      overallPercent: overall,
      samplePercent: sample,
      overallCaption: `总进度 ${formatCompactPercent(overall)}`,
      sampleCaption: `样本进度 ${formatCompactPercent(sample)}`,
      sampleMeta: step && totalStep ? `暂停于步骤 ${step}/${totalStep}` : "等待继续",
    };
  }

  if (status === "STOPPED") {
    return {
      state: "stopped",
      title: "任务已停止",
      body: message || "执行已终止，不会继续推进。",
      lastLogLine,
      lastLogPreview,
      overallPercent: overall,
      samplePercent: sample,
      overallCaption: `总进度 ${formatCompactPercent(overall)}`,
      sampleCaption: `样本进度 ${formatCompactPercent(sample)}`,
      sampleMeta: sampleIndex && sampleTotal ? `终止于样本 ${sampleIndex}/${sampleTotal}${sampleName ? ` · ${sampleName}` : ""}` : "",
    };
  }

  if (status === "SUCCEEDED") {
    return {
      state: "success",
      title: "任务已完成",
      body: sampleName ? `最后完成样本：${sampleName}` : "全部样本已分析完成。",
      lastLogLine,
      lastLogPreview,
      overallPercent: 100,
      samplePercent: 100,
      overallCaption: "总进度 100%",
      sampleCaption: "样本进度 100%",
      sampleMeta: sampleTotal > 1 ? `共 ${sampleTotal} 个样本` : "",
    };
  }

  if (status === "FAILED") {
    return {
      state: "danger",
      title: "任务已失败",
      body: message || "请优先查看日志尾部确认中断位置。",
      lastLogLine,
      lastLogPreview,
      overallPercent: overall,
      samplePercent: sample,
      overallCaption: `总进度 ${formatCompactPercent(overall)}`,
      sampleCaption: `样本进度 ${formatCompactPercent(sample)}`,
      sampleMeta: sampleIndex && sampleTotal ? `中断于样本 ${sampleIndex}/${sampleTotal}${sampleName ? ` · ${sampleName}` : ""}` : "",
    };
  }

  return {
    state: "running",
    title: sampleIndex && sampleTotal ? `样本 ${sampleIndex}/${sampleTotal}${sampleName ? ` · ${sampleName}` : ""}` : "任务运行中",
    body: message || "正在推进分析流程。",
    lastLogLine,
    lastLogPreview,
    overallPercent: overall,
    samplePercent: sample,
    overallCaption: `总进度 ${formatCompactPercent(overall)}`,
    sampleCaption: `样本进度 ${formatCompactPercent(sample)}`,
    sampleMeta: step && totalStep ? `步骤 ${step}/${totalStep}` : "",
  };
}

function renderQueueProgressBlock(progress, variant = "rail") {
  return `
    <div class="queue-progress-block queue-progress-${escapeHtml(variant)} queue-progress-${escapeHtml(progress.state)}">
      <div class="queue-progress-copy">
        <strong>${escapeHtml(progress.title)}</strong>
        <span>${escapeHtml(progress.body)}</span>
        ${progress.sampleMeta ? `<small>${escapeHtml(progress.sampleMeta)}</small>` : ""}
        ${progress.lastLogPreview ? `<small class="queue-progress-logline" title="${escapeHtml(progress.lastLogLine)}">日志：${escapeHtml(progress.lastLogPreview)}</small>` : ""}
      </div>
      <div class="queue-progress-meters">
        <div class="queue-progress-item">
          <div class="queue-progress-label">
            <span>${escapeHtml(progress.overallCaption)}</span>
          </div>
          <div class="queue-progress-track" aria-hidden="true">
            <div class="queue-progress-fill" style="width:${progress.overallPercent}%"></div>
          </div>
        </div>
        <div class="queue-progress-item">
          <div class="queue-progress-label">
            <span>${escapeHtml(progress.sampleCaption)}</span>
          </div>
          <div class="queue-progress-track queue-progress-track-subtle" aria-hidden="true">
            <div class="queue-progress-fill queue-progress-fill-subtle" style="width:${progress.samplePercent}%"></div>
          </div>
        </div>
      </div>
    </div>
  `;
}

function renderQueueResultOverview(report) {
  if (!report) {
    return '<p class="queue-result-empty">正在读取结果摘要，稍后会显示测序质量、组装质量和重点关注结论。</p>';
  }
  const taskMethod = String(report?.task?.method || "").trim().toLowerCase();
  const reportKind = String(report?.report_kind || report?.task?.report_kind || "").trim().toLowerCase();
  const workstationKey = String(report?.task?.workstation_key || "").trim().toLowerCase();
  const isVirusTask = workstationKey === "virus"
    || String(report?.task?.analysis_target || "").trim().toLowerCase() === "virus";
  if (reportKind === "pathosource_phylogeny" || workstationKey === "pathosource") {
    return renderPathoSourceQueueResultOverview(report);
  }
  if (reportKind === "community_meta_ecology" || workstationKey === "community") {
    return renderCommunityQueueResultOverview(report);
  }
  const multiSampleSummary = report?.task?.multi_sample_summary || report?.sections?.overview?.multi_sample_summary || {};
  if (String(report?.task?.report_mode || "").trim().toLowerCase() === "multi" && Number(multiSampleSummary.sample_count || 0) > 1) {
    return renderMultiSampleQueueResultOverview(report, multiSampleSummary);
  }
  if (taskMethod === "meta") {
    return renderMetaQueueResultOverview(report);
  }
  if (isVirusTask) {
    return renderVirusQueueResultOverview(report);
  }
  const overviewCards = buildQueueExecutiveSummary(report).slice(0, 3);
  const metricMap = Object.fromEntries((report.overview_metrics || []).map((metric) => [metric.key, metric]));
  const totalBases = metricMap.total_bases?.display || "--";
  const assembly = metricMap.assembly_profile || {};
  const checkm = metricMap.checkm_metrics?.items || [];
  return `
    <div class="queue-result-overview">
      <div class="queue-result-overview-grid">
        <article>
          <span>总测序量</span>
          <strong>${escapeHtml(totalBases)}</strong>
        </article>
        <article>
          <span>Contig / 质粒</span>
          <strong>${escapeHtml(`${assembly.contig_count ?? "--"} / ${assembly.plasmid_count ?? "--"}`)}</strong>
        </article>
        <article>
          <span>完整性 / 污染率</span>
          <strong>${escapeHtml(`${checkm[0]?.display || "--"} / ${checkm[1]?.display || "--"}`)}</strong>
        </article>
      </div>
      <div class="queue-result-briefs">
        ${overviewCards.map((card) => `
          <article class="queue-result-brief queue-result-brief-${escapeHtml(card.state || "neutral")}">
            <span>${escapeHtml(card.label || "")}</span>
            <strong>${escapeHtml(card.title || "-")}</strong>
            <p>${escapeHtml(card.body || "-")}</p>
          </article>
        `).join("")}
      </div>
    </div>
  `;
}

