function formatQueueHumanBp(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return "--";
  const units = [
    ["Gb", 1e9],
    ["Mb", 1e6],
    ["Kb", 1e3],
    ["bp", 1],
  ];
  const [unit, divisor] = units.find(([, base]) => numeric >= base) || units[units.length - 1];
  return divisor === 1 ? `${formatNumber(numeric)} ${unit}` : `${(numeric / divisor).toFixed(2)} ${unit}`;
}

function formatQueueNumber(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return "--";
  return formatNumber(numeric);
}

function formatQueuePercent(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return "--";
  return `${numeric.toFixed(2)}%`;
}

