function buildQueueExecutiveSummary(report) {
  const metrics = Array.isArray(report?.overview_metrics) ? report.overview_metrics : [];
  const sections = report?.sections || {};
  const metricMap = Object.fromEntries(metrics.map((metric) => [metric.key, metric]));
  const qItems = metricMap.q_metrics?.items || [];
  const q20 = parsePercentNumber(qItems[0]?.display);
  const q30 = parsePercentNumber(qItems[1]?.display);
  const qualityState = q20 < 90 || q30 < 80 ? "danger" : "success";

  const assemblyMetric = metricMap.assembly_profile || {};
  const contigCount = Number(assemblyMetric.contig_count);
  const checkmItems = metricMap.checkm_metrics?.items || [];
  const completeness = parsePercentNumber(checkmItems[0]?.display);
  const contamination = parsePercentNumber(checkmItems[1]?.display);
  let assemblyState = "neutral";
  if (Number.isFinite(contigCount) && contigCount > 200) {
    assemblyState = "danger";
  } else if ((Number.isFinite(completeness) && completeness < 90) || (Number.isFinite(contamination) && contamination >= 5)) {
    assemblyState = "warning";
  } else if (Number.isFinite(contigCount)) {
    assemblyState = "success";
  }

  const speciesItems = metricMap.species_estimation?.items || [];
  const speciesText = speciesItems[0]?.display || "--";
  const resistanceRows = sections?.resistance_virulence?.resistance_elements?.rows?.length || 0;
  const virulenceRows = sections?.resistance_virulence?.virulence_elements?.rows?.length || 0;
  const priorityRows = countQueuePriorityHits(sections?.priority_serotype || {});
  let focusState = "neutral";
  let focusTitle = "按模块顺序阅读";
  let focusBody = "当前未见需要优先跳读的高风险结果。";
  if (priorityRows > 0) {
    focusState = "danger";
    focusTitle = "优先关注毒力血清型";
    focusBody = `当前检出 ${priorityRows} 条重点关注结果。`;
  } else if (resistanceRows > 0 || virulenceRows > 0) {
    focusState = resistanceRows > 0 && virulenceRows > 0 ? "warning" : "neutral";
    focusTitle = "建议查看耐药与毒力";
    focusBody = `耐药元件 ${resistanceRows} 条，毒力元件 ${virulenceRows} 条。`;
  }

  return [
    {
      label: "测序质量",
      title: qualityState === "danger" ? "需重点关注" : "总体合格",
      body: `Q20 ${qItems[0]?.display || "--"}，Q30 ${qItems[1]?.display || "--"}。`,
      state: qualityState,
    },
    {
      label: "组装质量",
      title: assemblyState === "danger" ? "碎片偏多" : assemblyState === "warning" ? "建议复核" : "整体稳健",
      body: `Contig ${assemblyMetric.contig_count ?? "--"}，完整性 ${checkmItems[0]?.display || "--"}。`,
      state: assemblyState,
    },
    {
      label: "物种预估",
      title: speciesText,
      body: focusBody,
      state: focusState,
    },
  ];
}

function buildMetaQueueExecutiveSummary(report) {
  const metrics = Array.isArray(report?.overview_metrics) ? report.overview_metrics : [];
  const metricMap = Object.fromEntries(metrics.map((metric) => [metric.key, metric]));
  const sections = report?.sections || {};
  const binningResults = sections.binning_results || {};
  const qualitySummary = binningResults.quality?.summary || {};
  const taxonomyRows = Array.isArray(binningResults.taxonomy?.rows) ? binningResults.taxonomy.rows : [];
  const viralSummary = binningResults.viral_assembly?.summary || {};
  const avgCompleteness = Number(qualitySummary.avg_completeness);
  const avgContamination = Number(qualitySummary.avg_contamination);
  const dominantSpecies = metricMap.meta_species_mge?.items?.[0]?.display || "--";
  const viralRetained = Number(viralSummary.retained_count);
  const importReadyBins = taxonomyRows.filter((row) => String(row?.状态 || row?.status || "").trim() !== "缺少 fasta").length;
  const qualityState = Number.isFinite(avgCompleteness) && Number.isFinite(avgContamination)
    ? (avgCompleteness >= 80 && avgContamination < 10 ? "success" : "warning")
    : "neutral";
  const viralState = viralRetained > 0 ? "warning" : "neutral";
  const importState = importReadyBins > 0 ? "success" : "neutral";
  return [
    {
      label: "Binning 质量",
      title: Number.isFinite(avgCompleteness) ? `平均完整性 ${avgCompleteness.toFixed(1)}%` : "等待 Binning 质量结果",
      body: Number.isFinite(avgContamination)
        ? `当前平均污染率 ${avgContamination.toFixed(1)}%，建议结合 taxonomy 一起判断哪些 bin 值得保留。`
        : "当前还没有足够的 CheckM2 / quality_report 结果。",
      state: qualityState,
    },
    {
      label: "优势物种与病毒",
      title: dominantSpecies !== "--" ? dominantSpecies : "尚未形成稳定优势物种",
      body: viralRetained > 0
        ? `病毒组装已保留 ${viralRetained} 条候选 contig，建议优先复核病毒筛选结果。`
        : "当前未见需要优先跳读的病毒保留结果。",
      state: viralState,
    },
    {
      label: "后续动作",
      title: importReadyBins > 0 ? `可导入 ${importReadyBins} 个 bin` : "当前没有可导入 bin",
      body: importReadyBins > 0
        ? "如果这些 bin 满足你的样本库标准，可以直接从任务菜单进入样本库导入。"
        : "当前更适合先回看分箱质量、分类和病毒筛选，而不是直接入库。",
      state: importState,
    },
  ];
}

