async function onBrowserGoUp() {
  await loadBrowserDirectory(elements.browserGoUpButton.dataset.targetPath || "");
}

function startPathBrowserDrag(event) {
  if (!state.pathBrowser.open) return;
  const interactive = event.target.closest("button, input, textarea, select, a");
  if (interactive) return;
  const panel = elements.pathBrowserPanel;
  if (!panel) return;
  const rect = panel.getBoundingClientRect();
  state.pathBrowser.drag = {
    offsetX: event.clientX - rect.left,
    offsetY: event.clientY - rect.top,
  };
  panel.classList.add("is-positioned");
  panel.classList.add("is-dragging");
}

function onPathBrowserPointerMove(event) {
  if (!state.pathBrowser.drag || !state.pathBrowser.open) return;
  const panel = elements.pathBrowserPanel;
  if (!panel) return;
  const margin = 12;
  const width = rectWidth(panel);
  const height = rectHeight(panel);
  const maxLeft = Math.max(margin, window.innerWidth - width - margin);
  const maxTop = Math.max(margin, window.innerHeight - height - margin);
  const left = clamp(event.clientX - state.pathBrowser.drag.offsetX, margin, maxLeft);
  const top = clamp(event.clientY - state.pathBrowser.drag.offsetY, margin, maxTop);
  panel.style.left = `${left}px`;
  panel.style.top = `${top}px`;
  panel.style.transform = "none";
}

function stopPathBrowserDrag() {
  if (!state.pathBrowser.drag) return;
  state.pathBrowser.drag = null;
  elements.pathBrowserPanel?.classList.remove("is-dragging");
}

function resetPathBrowserPosition() {
  const panel = elements.pathBrowserPanel;
  if (!panel) return;
  panel.classList.remove("is-positioned");
  panel.style.left = "";
  panel.style.top = "";
  panel.style.transform = "";
}

function getCurrentTaskInputType() {
  return String(document.getElementById("inputtype")?.value || "").trim().toLowerCase();
}

function getPathBrowserSelectionRules(selector = state.pathBrowser.selector) {
  const normalized = String(selector || "").trim();
  if (normalized === "metagenome_short_right") {
    return { allowFile: true, allowDirectory: false, prompt: "选择二代右端文件" };
  }
  if (normalized === "metagenome_short_left") {
    return { allowFile: true, allowDirectory: true, prompt: "选择二代左端文件或二代数据目录" };
  }
  if (normalized === "input") {
    const inputType = getCurrentTaskInputType();
    const current = String(document.getElementById("input_path")?.value || "").trim();
    if (inputType === "@") {
      return { allowFile: true, allowDirectory: false, prompt: "选择批量输入表" };
    }
    if (inputType === "barcode_fastq") {
      return { allowFile: false, allowDirectory: true, prompt: "选择 barcode FASTQ 目录" };
    }
    if (inputType === "fasta") {
      const preferDirectory = !current || current.endsWith("/") || current.endsWith("\\");
      return preferDirectory
        ? { allowFile: false, allowDirectory: true, prompt: "选择 FASTA 文件夹" }
        : { allowFile: true, allowDirectory: false, prompt: "选择 FASTA 文件" };
    }
    return { allowFile: true, allowDirectory: false, prompt: "选择输入文件" };
  }
  if (normalized === "nextstrain_reference_genbank") {
    return { allowFile: true, allowDirectory: false, prompt: "选择 Nextstrain 使用的参考 GenBank 文件" };
  }
  return { allowFile: true, allowDirectory: true, prompt: "" };
}

function syncPathBrowserWithinViewport() {
  if (!state.pathBrowser.open) return;
  const panel = elements.pathBrowserPanel;
  if (!panel) return;
  if (!panel.style.left && !panel.style.top) return;
  const margin = 12;
  const width = rectWidth(panel);
  const height = rectHeight(panel);
  const left = clamp(parseFloat(panel.style.left || "0"), margin, Math.max(margin, window.innerWidth - width - margin));
  const top = clamp(parseFloat(panel.style.top || "0"), margin, Math.max(margin, window.innerHeight - height - margin));
  panel.style.left = `${left}px`;
  panel.style.top = `${top}px`;
}

