function startPolling() {
  window.clearInterval(state.pollTimer);
  state.pollTimer = window.setInterval(async () => {
    try {
      await loadTasks();
      if (state.activeTab === "server-tab") {
        await loadServerStatus();
      }
      if (state.selectedTaskId && state.taskDetailOpen) {
        await loadTaskDetail(state.selectedTaskId);
      }
    } catch (error) {
      console.error(error);
    }
  }, 5000);
}

async function requestJson(url, options = {}) {
  const { silentError = false, ...fetchOptions } = options;
  const response = await fetch(url, fetchOptions);
  const data = await response.json();
  if (!response.ok) {
    if (!silentError) {
      showToast(data.error || "请求失败", "error");
    }
    throw new Error(data.error || "请求失败");
  }
  return data;
}

function formatDate(value) {
  if (!value) return "-";
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? String(value) : date.toLocaleString();
}

function formatNumber(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return "-";
  return new Intl.NumberFormat("zh-CN").format(numeric);
}

function renderQueueSummary(items = state.tasks) {
  if (!elements.queueSummary) return;
  const chips = buildQueueAnalyticsActiveFilterChips();
  const total = items.length;
  const completed = items.filter((task) => String(task.status || "").toUpperCase() === "SUCCEEDED");
  if (state.queueAnalytics.detailRequested) {
    ensureQueueAnalyticsReportCache(completed);
  } else {
    state.queueAnalytics.loading = false;
  }
  const running = items.filter((task) => String(task.status || "").toUpperCase() === "RUNNING").length;
  const queued = items.filter((task) => ["QUEUED", "PAUSED"].includes(String(task.status || "").toUpperCase())).length;
  const failed = items.filter((task) => String(task.status || "").toUpperCase() === "FAILED").length;
  const completionRate = total ? Math.round((completed.length / total) * 100) : 0;
  const reportSnapshots = completed
    .map((task) => state.queueAnalytics.reportCache[String(task.id || "")])
    .filter((item) => item && item.ready);
  const workstationRows = Object.entries(WORKSTATION_LABELS)
    .map(([key, label]) => ({
      key,
      label,
      count: items.filter((task) => resolveQueueTaskWorkstationKey(task) === key).length,
    }))
    .filter((item) => item.count > 0);
  const workstationSeries = {
    labels: workstationRows.map((item) => item.label),
    values: workstationRows.map((item) => item.count),
  };
  const statusMeta = [
    { key: "RUNNING", label: "运行中" },
    { key: "PAUSED", label: "已暂停" },
    { key: "QUEUED", label: "排队中" },
    { key: "FAILED", label: "失败" },
    { key: "SUCCEEDED", label: "已完成" },
    { key: "STOPPED", label: "已停止" },
  ];
  const statusRows = statusMeta
    .map((item) => ({
      ...item,
      count: items.filter((task) => String(task.status || "").toUpperCase() === item.key).length,
    }))
    .filter((item) => item.count > 0);
  const statusSeries = {
    labels: statusRows.map((item) => item.label),
    values: statusRows.map((item) => item.count),
  };
  const qualityRows = ["success", "warning", "danger", "neutral"]
    .map((band) => ({
      key: band,
      label: getQueueQualityBandMeta(band).label,
      count: reportSnapshots.filter((item) => item.qualityBand === band).length,
    }))
    .filter((item) => item.count > 0);
  const qualitySeries = {
    labels: qualityRows.map((item) => item.label),
    values: qualityRows.map((item) => item.count),
  };
  const leadingWorkstation = workstationRows[0] || null;
  const successfulQualityCount = qualityRows.find((item) => item.key === "success")?.count || 0;
  const leadingQuality = qualityRows[0] || null;
  const speciesRows = buildDatabaseCountSeries(
    reportSnapshots.filter((item) => item.dominantSpecies),
    (item) => item.dominantSpecies,
    6
  );
  const bacteriaScatterPoints = reportSnapshots
    .filter((item) => item.workstationKey === "bacteria" && item.bacteriaQuality)
    .map((item) => ({
      taskId: item.taskId,
      taskName: item.taskName,
      qualityBand: item.qualityBand,
      completeness: Number(item.bacteriaQuality?.completeness),
      contamination: Number(item.bacteriaQuality?.contamination),
    }))
    .filter((item) => Number.isFinite(item.completeness) && Number.isFinite(item.contamination));
  elements.queueSummary.innerHTML = total ? `
    <section class="queue-analytics-panel">
      <div class="queue-analytics-head">
        <div>
          <p class="section-kicker">Analytics</p>
          <h3>任务统计</h3>
        </div>
        <div class="queue-analytics-head-side">
          <span class="table-state-pill">当前范围 ${formatNumber(total)} 个任务</span>
          ${chips.length ? '<button class="ghost-button" type="button" data-queue-analytics-clear-all>清空联动</button>' : ""}
        </div>
      </div>
      ${chips.length ? `
        <div class="queue-analytics-chiprow">
          ${chips.map((chip) => `
            <button class="queue-table-filter-chip" type="button" data-queue-analytics-clear="${escapeHtml(chip.key)}">
              <strong>${escapeHtml(chip.label)}</strong>${escapeHtml(chip.value)}
            </button>
          `).join("")}
        </div>
      ` : ""}
      <div class="queue-analytics-kpis">
        <article class="queue-analytics-kpi">
          <span>总任务数</span>
          <strong>${escapeHtml(formatNumber(total))}</strong>
          <small>当前筛选</small>
        </article>
        <article class="queue-analytics-kpi">
          <span>完成率</span>
          <strong>${escapeHtml(`${completionRate}%`)}</strong>
          <small>${escapeHtml(`${completed.length} / ${total}`)}</small>
        </article>
        <article class="queue-analytics-kpi">
          <span>运行压力</span>
          <strong>${escapeHtml(String(running + queued))}</strong>
          <small>${escapeHtml(`运行 ${running} / 等待 ${queued}`)}</small>
        </article>
        <article class="queue-analytics-kpi ${failed > 0 ? "queue-analytics-kpi-warning" : ""}">
          <span>结果摘要覆盖</span>
          <strong>${escapeHtml(state.queueAnalytics.detailRequested ? `${reportSnapshots.length} / ${completed.length}` : "按需加载")}</strong>
          <small>${state.queueAnalytics.detailRequested ? (state.queueAnalytics.loading ? "读取中" : "已读取") : "结果统计"}</small>
        </article>
      </div>
      <div class="queue-analytics-grid">
        <article class="queue-analytics-card queue-analytics-card-focus queue-analytics-card-workstation">
          <div data-queue-chart="workstation"></div>
        </article>
        <article class="queue-analytics-card queue-analytics-card-focus queue-analytics-card-status">
          <div data-queue-chart="status"></div>
        </article>
        <article class="queue-analytics-card queue-analytics-card-focus queue-analytics-card-quality">
          <div data-queue-chart="quality"></div>
        </article>
        <article class="queue-analytics-card queue-analytics-card-wide">
          <div data-queue-chart="species"></div>
        </article>
        <article class="queue-analytics-card queue-analytics-card-wide">
          <div data-queue-chart="bacteria-scatter"></div>
        </article>
      </div>
    </section>
  ` : `
    <div class="empty-state queue-empty">
      <strong>当前没有可统计的任务</strong>
      <p>放宽搜索条件或清空联动筛选后，这里会重新生成任务统计视图。</p>
    </div>
  `;
  if (!total) return;

  const workstationHost = elements.queueSummary.querySelector('[data-queue-chart="workstation"]');
  if (workstationHost instanceof HTMLElement) {
    if (workstationSeries.labels.length) {
      workstationHost.innerHTML = renderQueueAnalyticsBarShell("任务类型", {
        eyebrow: "结构分布",
        value: leadingWorkstation ? formatQueueAnalyticsShare(leadingWorkstation.count, total) : "0%",
        label: leadingWorkstation ? leadingWorkstation.label : "暂无任务",
        tone: "workstation",
      });
      initializeDatabaseBarChart(workstationHost, workstationSeries, "任务类型", (item) => {
        const matched = workstationRows.find((entry) => entry.label === item.label);
        if (matched) toggleQueueAnalyticsFilter("workstation", matched.key);
      });
    } else {
      workstationHost.innerHTML = '<div class="empty-state">当前范围内暂无可统计的任务类型。</div>';
    }
  }

  const statusHost = elements.queueSummary.querySelector('[data-queue-chart="status"]');
  if (statusHost instanceof HTMLElement) {
    if (statusSeries.labels.length) {
      statusHost.innerHTML = renderQueueAnalyticsDonutShell("任务完成情况", {
        eyebrow: "运行态势",
        value: `${completionRate}%`,
        label: "完成率",
        tone: "status",
      });
      initializeDatabaseDonutChart(statusHost, statusSeries, "任务完成情况", (item) => {
        const matched = statusRows.find((entry) => entry.label === item.label);
        if (!matched) return;
        state.queueControls.status = state.queueControls.status === matched.key ? "ALL" : matched.key;
        renderTaskList();
      });
    } else {
      statusHost.innerHTML = '<div class="empty-state">当前范围内暂无状态统计。</div>';
    }
  }

  const qualityHost = elements.queueSummary.querySelector('[data-queue-chart="quality"]');
  if (qualityHost instanceof HTMLElement) {
    if (!state.queueAnalytics.detailRequested) {
      qualityHost.innerHTML = renderQueueAnalyticsInsightPlaceholder({
        eyebrow: "质控判读",
        title: "数据质控",
        value: String(completed.length),
        label: "待读取摘要",
        buttonLabel: "加载质控统计",
        tone: "quality",
      });
    } else if (qualitySeries.labels.length) {
      qualityHost.innerHTML = renderQueueAnalyticsDonutShell("数据质控", {
        eyebrow: "质控判读",
        value: formatQueueAnalyticsShare(successfulQualityCount, reportSnapshots.length),
        label: "质控稳定",
        tone: "quality",
      });
      initializeDatabaseDonutChart(qualityHost, qualitySeries, "数据质控", (item) => {
        const matched = qualityRows.find((entry) => entry.label === item.label);
        if (matched) toggleQueueAnalyticsFilter("quality", matched.key);
      });
    } else {
      qualityHost.innerHTML = state.queueAnalytics.loading
        ? renderQueueAnalyticsInsightPlaceholder({
            eyebrow: "质控判读",
            title: "数据质控",
            value: String(reportSnapshots.length),
            label: "已读取摘要",
            tone: "quality",
          })
        : renderQueueAnalyticsInsightPlaceholder({
            eyebrow: "质控判读",
            title: "数据质控",
            value: leadingQuality ? `${leadingQuality.count}` : "0",
            label: leadingQuality ? leadingQuality.label : "暂无摘要",
            buttonLabel: "重新读取",
            tone: "quality",
          });
    }
  }

  const speciesHost = elements.queueSummary.querySelector('[data-queue-chart="species"]');
  if (speciesHost instanceof HTMLElement) {
    if (!state.queueAnalytics.detailRequested) {
      speciesHost.innerHTML = renderQueueAnalyticsDeferredCard("物种鉴定按需读取", "主导物种统计会优先读取已缓存摘要；旧任务第一次查看时再自动补齐。");
    } else if (speciesRows.labels.length) {
      speciesHost.innerHTML = renderDatabaseSiteRankingShell("物种鉴定", "汇总已完成任务里的主导物种或主导病毒，适合快速回看当前检出结构。");
      initializeDatabaseSiteRanking(speciesHost, speciesRows, "物种鉴定", (item) => {
        toggleQueueAnalyticsFilter("species", item.label);
      });
    } else {
      speciesHost.innerHTML = state.queueAnalytics.loading
        ? renderQueueAnalyticsLoadingCard("正在汇总物种鉴定", "正在补齐历史任务的统计摘要缓存，主导物种列表稍后会自动出现。")
        : renderQueueAnalyticsDeferredCard("暂无可统计的物种鉴定", "当前已完成任务里还没有可用于汇总的物种预估或病毒分类结果。", "重新读取");
    }
  }

  const bacteriaScatterHost = elements.queueSummary.querySelector('[data-queue-chart="bacteria-scatter"]');
  if (bacteriaScatterHost instanceof HTMLElement) {
    if (!state.queueAnalytics.detailRequested) {
      bacteriaScatterHost.innerHTML = renderQueueAnalyticsDeferredCard("细菌质量散点图按需读取", "这张图会优先读取任务完成时写入的完整性和污染率摘要；旧任务首次查看时自动补齐。", "加载细菌质量散点图");
    } else if (bacteriaScatterPoints.length) {
      bacteriaScatterHost.innerHTML = renderQueueBacteriaScatterShell(bacteriaScatterPoints);
    } else {
      bacteriaScatterHost.innerHTML = state.queueAnalytics.loading
        ? renderQueueAnalyticsLoadingCard("正在汇总细菌质量散点", "正在补齐历史任务的完整性和污染率摘要，稍后会自动出现。")
        : renderQueueAnalyticsDeferredCard("暂无细菌质量散点数据", "当前已完成任务里还没有可用于散点图的细菌完整性 / 污染率指标。", "重新读取");
    }
  }

  elements.queueSummary.querySelector("[data-queue-analytics-clear-all]")?.addEventListener("click", clearQueueAnalyticsFilters);
  elements.queueSummary.querySelectorAll("[data-queue-analytics-clear]").forEach((button) => {
    button.addEventListener("click", () => {
      const key = String(button.getAttribute("data-queue-analytics-clear") || "");
      if (!key) return;
      state.queueAnalytics.filters[key] = "";
      renderTaskList();
    });
  });
  elements.queueSummary.querySelectorAll("[data-queue-analytics-load-details]").forEach((button) => {
    button.addEventListener("click", requestQueueAnalyticsDetails);
  });
  elements.queueSummary.querySelectorAll("[data-bacteria-scatter-task]").forEach((button) => {
    button.addEventListener("click", async () => {
      const taskId = String(button.getAttribute("data-bacteria-scatter-task") || "");
      if (!taskId) return;
      await loadTaskDetail(taskId);
      openTaskDetail();
    });
  });
}

function renderServerStatus() {
  if (!elements.serverSummary || !elements.serverMetrics) return;
  const status = state.serverStatus;
  if (!status) {
    elements.serverSummary.innerHTML = "";
    elements.serverMetrics.innerHTML = `
      <div class="empty-state queue-empty">
        <strong>暂无服务器信息</strong>
        <p>请点击刷新状态重新获取当前服务器资源情况。</p>
      </div>
    `;
    return;
  }

  const cpuSeverity = getUsageSeverity(status.cpu?.percent);
  const memorySeverity = getUsageSeverity(status.memory?.percent);
  const diskSeverity = getUsageSeverity(status.disk?.used_percent);
  const overallSeverity = [cpuSeverity.rank, memorySeverity.rank, diskSeverity.rank].includes(3)
    ? { label: "资源紧张", note: "建议优先检查占用峰值与磁盘清理。", tone: "critical" }
    : [cpuSeverity.rank, memorySeverity.rank, diskSeverity.rank].includes(2)
      ? { label: "需要关注", note: "服务可用，建议继续观察负载变化。", tone: "warning" }
      : { label: "运行平稳", note: "资源充足，可继续提交任务。", tone: "healthy" };
  const queueStats = getServerQueueStats();
  const decisionItems = buildServerDecisionItems(status, { cpuSeverity, memorySeverity, diskSeverity, queueStats });
  const loadRatio = getServerLoadRatio(status);
  const loadRatioText = Number.isFinite(loadRatio) ? `${(loadRatio * 100).toFixed(0)}%` : "-";
  const trendItems = buildServerTrendItems(state.serverStatusHistory);

  elements.serverSummary.innerHTML = `
    <article class="server-overview-banner server-overview-${overallSeverity.tone}">
      <div class="server-overview-copy">
        <h3>${escapeHtml(status.hostname || "当前服务器")}</h3>
        <p>${escapeHtml(overallSeverity.note)}</p>
      </div>
      <div class="server-overview-meta">
        <span class="server-health-pill server-health-${overallSeverity.tone}">${escapeHtml(overallSeverity.label)}</span>
        <strong>${escapeHtml(status.platform || "-")}</strong>
        <small>更新于 ${escapeHtml(formatDate(status.sampled_at))}</small>
      </div>
    </article>
    <div class="server-summary-grid">
      ${renderServerSummaryStat("CPU 核心", String(status.cpu_count || "-"), status.machine || "-")}
      ${renderServerSummaryStat("总内存", status.memory?.total_human || "-", `剩余 ${status.memory?.free_human || "-"}`)}
      ${renderServerSummaryStat("磁盘剩余", status.disk?.free_human || "-", `总容量 ${status.disk?.total_human || "-"}`)}
      ${renderServerSummaryStat("负载占核心", loadRatioText, `${status.cpu?.load_average || "-"} · ${status.cpu?.source || "-"}`)}
    </div>
  `;

  elements.serverMetrics.innerHTML = `
    <article class="server-card server-diagnosis-card">
      <div class="server-card-head">
        <div>
          <h3>运行判断</h3>
          <p class="server-card-note">把资源数字翻译成当前是否适合继续提交任务。</p>
        </div>
        <span class="server-inline-note">${escapeHtml(queueStats.running ? `${queueStats.running} 个运行中` : "无运行任务")}</span>
      </div>
      <div class="server-decision-list">
        ${decisionItems.map((item) => `
          <article class="server-decision-item server-decision-${escapeHtml(item.tone)}">
            <span>${escapeHtml(item.label)}</span>
            <strong>${escapeHtml(item.title)}</strong>
            <p>${escapeHtml(item.detail)}</p>
            ${item.actionStatus ? `<button class="server-decision-action" type="button" data-server-queue-status="${escapeHtml(item.actionStatus)}">${escapeHtml(item.actionLabel || "查看任务")}</button>` : ""}
          </article>
        `).join("")}
      </div>
    </article>
    <article class="server-card server-card-emphasis">
      <div class="server-card-head">
        <div>
          <h3>资源占用</h3>
        </div>
        <span class="server-inline-note">实时</span>
      </div>
      <div class="server-usage-grid">
        ${renderUsageMetric("CPU 使用率", status.cpu?.percent, status.cpu?.detail)}
        ${renderUsageMetric("内存使用率", status.memory?.percent, `${status.memory?.used_human || "-"} / ${status.memory?.total_human || "-"}`)}
        ${renderUsageMetric("存储使用率", status.disk?.used_percent, `${status.disk?.used_human || "-"} / ${status.disk?.total_human || "-"}`)}
      </div>
      <div class="server-detail-grid server-detail-grid-compact">
        <div><span>内存剩余</span><strong>${escapeHtml(status.memory?.free_human || "-")}</strong></div>
        <div><span>磁盘剩余</span><strong>${escapeHtml(status.disk?.free_human || "-")}</strong></div>
        <div><span>任务队列</span><strong>${escapeHtml(`${queueStats.running} 运行 / ${queueStats.queued} 排队`)}</strong></div>
      </div>
    </article>
    <article class="server-card server-trend-card">
      <div class="server-card-head">
        <div>
          <h3>压力趋势</h3>
          <p class="server-card-note">最近 ${escapeHtml(String(state.serverStatusHistory.length || 1))} 次刷新，用来判断峰值是否持续。</p>
        </div>
        <span class="server-inline-note">${escapeHtml(state.serverStatusHistory.length >= 2 ? "有趋势" : "等待采样")}</span>
      </div>
      <div class="server-trend-grid">
        ${trendItems.map(renderServerTrendItem).join("")}
      </div>
    </article>
    <article class="server-card server-hardware-card">
      <div class="server-card-head">
        <div>
          <h3>硬件概况</h3>
        </div>
        <span class="server-update-time">更新于 ${escapeHtml(formatDate(status.sampled_at))}</span>
      </div>
      <div class="server-detail-grid">
        ${renderServerDetailItem("主机名", status.hostname || "-", true)}
        ${renderServerDetailItem("系统平台", status.platform || "-", true)}
        ${renderServerDetailItem("架构", status.machine || "-")}
        ${renderServerDetailItem("Python", status.python || "-")}
        ${renderServerDetailItem("CPU 逻辑核心", String(status.cpu_count || "-"))}
        ${renderServerDetailItem("部署磁盘路径", status.disk?.path || "-", true)}
      </div>
    </article>
  `;
  elements.serverMetrics.querySelectorAll("[data-server-queue-status]").forEach((button) => {
    button.addEventListener("click", () => {
      openQueueWithStatusFilter(button.getAttribute("data-server-queue-status") || "ALL");
    });
  });
}

function recordServerStatusSample(status) {
  if (!status || typeof status !== "object") return;
  const sampledAt = String(status.sampled_at || new Date().toISOString());
  const sample = {
    sampledAt,
    cpu: normalizeServerTrendValue(status.cpu?.percent),
    memory: normalizeServerTrendValue(status.memory?.percent),
    disk: normalizeServerTrendValue(status.disk?.used_percent),
    load: normalizeServerTrendValue(Number.isFinite(getServerLoadRatio(status)) ? getServerLoadRatio(status) * 100 : null),
  };
  const history = Array.isArray(state.serverStatusHistory) ? state.serverStatusHistory.slice() : [];
  const last = history[history.length - 1];
  if (last?.sampledAt === sampledAt) {
    history[history.length - 1] = sample;
  } else {
    history.push(sample);
  }
  state.serverStatusHistory = history.slice(-5);
}

function normalizeServerTrendValue(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return null;
  return Math.max(0, Math.min(100, numeric));
}

function buildServerTrendItems(history) {
  const samples = Array.isArray(history) && history.length ? history : [state.serverStatus].filter(Boolean).map((status) => ({
    sampledAt: String(status.sampled_at || ""),
    cpu: normalizeServerTrendValue(status.cpu?.percent),
    memory: normalizeServerTrendValue(status.memory?.percent),
    disk: normalizeServerTrendValue(status.disk?.used_percent),
    load: normalizeServerTrendValue(Number.isFinite(getServerLoadRatio(status)) ? getServerLoadRatio(status) * 100 : null),
  }));
  return [
    { key: "cpu", label: "CPU", values: samples.map((sample) => sample.cpu) },
    { key: "memory", label: "内存", values: samples.map((sample) => sample.memory) },
    { key: "disk", label: "磁盘", values: samples.map((sample) => sample.disk) },
  ].map((item) => {
    const values = item.values.filter((value) => Number.isFinite(value));
    const last = values.length ? values[values.length - 1] : null;
    const first = values.length ? values[0] : null;
    const delta = Number.isFinite(last) && Number.isFinite(first) ? last - first : 0;
    const average = values.length ? values.reduce((sum, value) => sum + value, 0) / values.length : null;
    const peak = values.length ? Math.max(...values) : null;
    const severity = Number.isFinite(last) ? getUsageSeverity(last) : { tone: "neutral", label: "未知", rank: 0 };
    return {
      ...item,
      values,
      last,
      average,
      peak,
      delta,
      severity,
      direction: getServerTrendDirection(delta, values.length),
    };
  });
}

function getServerTrendDirection(delta, count) {
  if (count < 2) return { label: "基线", tone: "neutral", text: "再刷新一次形成趋势" };
  if (delta >= 5) return { label: "上升", tone: "warning", text: `较首采样 +${delta.toFixed(1)}%` };
  if (delta <= -5) return { label: "回落", tone: "healthy", text: `较首采样 ${delta.toFixed(1)}%` };
  return { label: "平稳", tone: "neutral", text: `波动 ${Math.abs(delta).toFixed(1)}%` };
}

function renderServerTrendItem(item) {
  const path = buildServerTrendPath(item.values);
  const peakText = Number.isFinite(item.peak) ? formatPercent(item.peak) : "-";
  const averageText = Number.isFinite(item.average) ? formatPercent(item.average) : "-";
  return `
    <div class="server-trend-item server-trend-${escapeHtml(item.severity.tone)}">
      <div class="server-trend-topline">
        <span>${escapeHtml(item.label)}</span>
        <b class="server-trend-direction server-trend-direction-${escapeHtml(item.direction.tone)}">${escapeHtml(item.direction.label)}</b>
      </div>
      <strong class="server-trend-current">${escapeHtml(formatPercent(item.last))}</strong>
      <div class="server-trend-plot" aria-hidden="true">
        ${path ? `<svg viewBox="0 0 128 38" role="img" focusable="false">
          <path class="server-trend-baseline" d="M0 31 H128"></path>
          <path class="server-trend-line" d="${escapeHtml(path)}"></path>
        </svg>` : `<span class="server-trend-empty">暂无曲线</span>`}
      </div>
      <div class="server-trend-meta">
        <small>${escapeHtml(item.direction.text)}</small>
      </div>
      <div class="server-trend-foot">
        <span>峰值 ${escapeHtml(peakText)}</span>
        <span>均值 ${escapeHtml(averageText)}</span>
      </div>
    </div>
  `;
}

function buildServerTrendPath(values) {
  const normalized = Array.isArray(values) ? values.filter((value) => Number.isFinite(value)) : [];
  if (!normalized.length) return "";
  const width = 128;
  const height = 38;
  const leftPad = 4;
  const rightPad = 4;
  const topPad = 4;
  const bottomPad = 6;
  const usableWidth = width - leftPad - rightPad;
  const usableHeight = height - topPad - bottomPad;
  if (normalized.length === 1) {
    const y = topPad + usableHeight * (1 - normalized[0] / 100);
    return `M 56.0 ${y.toFixed(1)} L 72.0 ${y.toFixed(1)}`;
  }
  return normalized.map((value, index) => {
    const x = normalized.length === 1 ? width / 2 : leftPad + (usableWidth * index) / (normalized.length - 1);
    const y = topPad + usableHeight * (1 - value / 100);
    return `${index ? "L" : "M"} ${x.toFixed(1)} ${y.toFixed(1)}`;
  }).join(" ");
}

function getServerQueueStats() {
  const tasks = Array.isArray(state.tasks) ? state.tasks : [];
  const running = tasks.filter((task) => String(task.status || "").toUpperCase() === "RUNNING").length;
  const queuedOnly = tasks.filter((task) => String(task.status || "").toUpperCase() === "QUEUED").length;
  const paused = tasks.filter((task) => String(task.status || "").toUpperCase() === "PAUSED").length;
  const queued = queuedOnly + paused;
  const failed = tasks.filter((task) => String(task.status || "").toUpperCase() === "FAILED").length;
  const recent = tasks.slice(0, 12);
  return { running, queued, queuedOnly, paused, failed, recentCount: recent.length };
}

function openQueueWithStatusFilter(status = "ALL") {
  const normalized = String(status || "ALL").toUpperCase();
  setActiveTab("queue-tab");
  if (state.activeTab !== "queue-tab") return;
  state.queueView = "queue";
  state.queueControls.status = normalized;
  state.queueControls.search = "";
  syncQueueControls();
  renderTaskList();
  const labelMap = {
    RUNNING: "运行中任务",
    QUEUED: "排队任务",
    PAUSED: "暂停任务",
    FAILED: "失败任务",
  };
  showToast(`已切换到任务队列：${labelMap[normalized] || "全部任务"}`);
}

function getServerLoadRatio(status) {
  const loadText = String(status?.cpu?.load_average || "").split("/")[0] || "";
  const load = Number(loadText.trim());
  const cores = Number(status?.cpu_count || 0);
  if (!Number.isFinite(load) || !Number.isFinite(cores) || cores <= 0) return null;
  return load / cores;
}

function buildServerDecisionItems(status, context) {
  const { cpuSeverity, memorySeverity, diskSeverity, queueStats } = context;
  const loadRatio = getServerLoadRatio(status);
  const items = [];
  const worstResource = [
    { key: "CPU", severity: cpuSeverity, value: formatPercent(status?.cpu?.percent), advice: "建议先观察正在运行任务，避免立刻追加大量并行分析。" },
    { key: "内存", severity: memorySeverity, value: formatPercent(status?.memory?.percent), advice: "建议优先减少并行任务，或等待当前任务释放内存后再提交。" },
    { key: "磁盘", severity: diskSeverity, value: formatPercent(status?.disk?.used_percent), advice: "建议清理旧输出目录或转移归档结果后再继续提交大批量任务。" },
  ].sort((left, right) => right.severity.rank - left.severity.rank)[0];
  items.push({
    tone: worstResource.severity.tone,
    label: "资源瓶颈",
    title: `${worstResource.key} ${worstResource.value}`,
    detail: worstResource.severity.rank >= 2 ? worstResource.advice : "当前主要资源未到紧张阈值，可以按常规节奏提交任务。",
  });
  items.push({
    tone: queueStats.queued > 0 ? "warning" : queueStats.running > 0 ? "healthy" : "neutral",
    label: "任务压力",
    title: `${queueStats.running} 个运行中，${queueStats.queuedOnly} 个排队${queueStats.paused ? `，${queueStats.paused} 个暂停` : ""}`,
    detail: queueStats.queued > 0
      ? "队列已经积压，建议先查看任务队列中的等待项和失败项。"
      : queueStats.running > 0
        ? "当前有任务运行但未形成排队，适合继续观察资源曲线。"
        : "当前没有运行任务，服务器处于空闲或低压力状态。",
    actionStatus: queueStats.queuedOnly > 0 ? "QUEUED" : queueStats.paused > 0 ? "PAUSED" : queueStats.running > 0 ? "RUNNING" : "",
    actionLabel: queueStats.queuedOnly > 0 ? "查看排队任务" : queueStats.paused > 0 ? "查看暂停任务" : queueStats.running > 0 ? "查看运行任务" : "",
  });
  items.push({
    tone: Number.isFinite(loadRatio) && loadRatio >= 0.9 ? "warning" : "healthy",
    label: "提交建议",
    title: Number.isFinite(loadRatio) ? `负载约为核心数的 ${(loadRatio * 100).toFixed(0)}%` : "负载未知",
    detail: Number.isFinite(loadRatio) && loadRatio >= 0.9
      ? "建议先不要提高最大并行数，等待 1 分钟负载回落后再追加任务。"
      : "可维持当前并行设置；若要批量提交，仍建议分批观察。",
  });
  return items;
}

function renderDatabaseSubmissions() {
  if (!elements.databaseSubmissions) return;
  const items = Array.isArray(state.databaseSubmissions) ? state.databaseSubmissions : [];
  const versionLogs = Array.isArray(state.databaseVersionLogs) ? state.databaseVersionLogs : [];
  const releaseVersions = Array.isArray(state.databaseReleaseVersions) ? state.databaseReleaseVersions : [];
  const pending = items.filter((item) => item.status === "pending");
  const mine = items.filter((item) => item.owner === state.currentUser?.username).slice(0, 6);
  const recentLogs = (state.currentUser?.role === "admin"
    ? versionLogs
    : versionLogs.filter((item) => item.owner === state.currentUser?.username)
  ).slice(0, 8);
  const recentReleases = releaseVersions.slice(0, 8);
  const renderFoldSection = ({ kicker, title, countLabel = "", body = "", actions = "", open = false, empty = false }) => `
    <details class="database-fold-section ${empty ? "database-fold-empty" : ""}" ${open ? "open" : ""}>
      <summary class="database-fold-summary">
        <div>
          <p class="section-kicker">${escapeHtml(kicker)}</p>
          <h3>${escapeHtml(title)}</h3>
        </div>
        <div class="database-fold-summary-side">
          ${countLabel ? `<span class="table-state-pill">${escapeHtml(countLabel)}</span>` : ""}
          ${actions}
        </div>
      </summary>
      <div class="database-fold-body">${body}</div>
    </details>
  `;
  const renderReleaseSection = () => `
    ${renderFoldSection({
      kicker: "Release",
      title: "主数据库命名版本",
      countLabel: `${recentReleases.length} 条`,
      actions: '<button class="ghost-button" type="button" data-database-publish-release>发布当前版本</button>',
      open: false,
      body: `${recentReleases.length ? `
        <div class="database-review-list">
          ${recentReleases.map((item) => `
            <article class="database-review-card database-version-card">
              <div>
                <strong>${escapeHtml(item.version_label || "-")}</strong>
                <p>${escapeHtml(formatDate(item.created_at) || "-")} · 发布人 ${escapeHtml(item.operator || "-")}</p>
                <p>${escapeHtml(item.summary || "当前主数据库与上一版本完全一致，更新日志为空。")}</p>
                ${item.note ? `<p class="field-note">说明：${escapeHtml(item.note)}</p>` : ""}
              </div>
              <div class="database-version-meta">
                <span class="mini-chip running">已发布</span>
                <span class="field-note">新增 ${escapeHtml(String(item.added_count ?? 0))} / 更新 ${escapeHtml(String(item.updated_count ?? 0))} / 删除 ${escapeHtml(String(item.deleted_count ?? 0))}</span>
              </div>
            </article>
          `).join("")}
        </div>
      ` : '<p class="field-note">当前还没有命名发布版本，可直接基于当前主库快照发布第一版。</p>'}
      <p class="field-note">管理员可在任意状态下基于当前主库快照发布新版本；若与上一版本一致，本次更新日志将为空。</p>`,
    })}
  `;
  const renderVersionLogSection = () => `
    ${renderFoldSection({
      kicker: "Version Log",
      title: "最近发布版本日志",
      countLabel: `${recentLogs.length} 条`,
      open: false,
      body: `${recentLogs.length ? `
        <div class="database-review-list">
          ${recentLogs.map((item) => `
            <article class="database-review-card database-version-card">
              <div>
                <strong>${escapeHtml(item.sample_name || "-")}</strong>
                <p>${escapeHtml(item.version_label || "-")} · ${escapeHtml(formatDate(item.created_at) || "-")}</p>
                <p>${escapeHtml(item.summary || "个人库样本经审核发布入主数据库")}</p>
              </div>
              <div class="database-version-meta">
                <span class="mini-chip running">${escapeHtml(item.action === "publish" ? "已发布" : (item.action || "记录"))}</span>
                <span class="field-note">审核人：${escapeHtml(item.operator || "-")}</span>
              </div>
            </article>
          `).join("")}
        </div>
      ` : '<p class="field-note">当前还没有可展示的发布版本日志。</p>'}`,
    })}
  `;
  const parseSubmissionPayload = (item) => {
    try {
      const parsed = JSON.parse(String(item?.payload_json || "{}"));
      return parsed && typeof parsed === "object" ? parsed : {};
    } catch {
      return {};
    }
  };
  const formatSubmissionPreview = (payload) => {
    const syndrome = getDatabaseMetadataDisplayValue(payload, "suspected_syndrome");
    const submittingUnit = getDatabaseMetadataDisplayValue(payload, "submitting_unit");
    const site = getDatabaseCollectionSiteDisplay(payload);
    const sampleType = String(payload?.sample_type || "").trim();
    const collectionDate = formatDate(payload?.collection_date || payload?.imported_at || "");
    const mlst = String(payload?.mlst_st || "").trim();
    const serotype = String(payload?.serotype_result || "").trim();
    const resistance = String(payload?.resistance_gene_hits || "").trim();
    const virulence = String(payload?.virulence_gene_hits || "").trim();
    const resistanceMge = String(payload?.resistance_mge_hits || "").trim();
    const virulenceMge = String(payload?.virulence_mge_hits || "").trim();
    return {
      chips: [
        sampleType ? `样本类型：${sampleType}` : "",
        collectionDate ? `采样时间：${collectionDate}` : "",
        syndrome ? `症候群：${syndrome}` : "",
        submittingUnit ? `送检单位：${submittingUnit}` : "",
      ].filter(Boolean),
      lines: [
        site ? `采样地点：${site}` : "",
        [mlst ? `MLST：${mlst}` : "", serotype ? `血清型：${serotype}` : ""].filter(Boolean).join("；"),
        resistance ? `耐药基因：${truncateText(resistance, 88)}` : "",
        virulence ? `毒力基因：${truncateText(virulence, 88)}` : "",
        resistanceMge ? `耐药-MGE：${truncateText(resistanceMge, 88)}` : "",
        virulenceMge ? `毒力-MGE：${truncateText(virulenceMge, 88)}` : "",
      ].filter(Boolean),
    };
  };

  if (state.databaseLibraryScope === "main" && state.currentUser?.role === "admin") {
    elements.databaseSubmissions.innerHTML = `${renderFoldSection({
      kicker: "Review Queue",
      title: "待审核入库申请",
      countLabel: `待审核 ${pending.length}`,
      open: pending.length > 0,
      empty: pending.length <= 0,
      body: pending.length ? `
        <div class="database-review-list">
          ${pending.map((item) => {
            const preview = formatSubmissionPreview(parseSubmissionPayload(item));
            return `
            <article class="database-review-card database-review-card-detailed">
              <div class="database-review-card-main">
                <div class="database-review-card-head">
                  <div>
                    <strong>${escapeHtml(item.sample_name || "-")}</strong>
                    <p>${escapeHtml(item.owner || "-")} · ${escapeHtml(item.owner_group || "-")}</p>
                  </div>
                  <span class="mini-chip queued">待审核</span>
                </div>
                ${preview.chips.length ? `
                  <div class="database-review-chip-row">
                    ${preview.chips.map((entry) => `<span class="database-review-chip">${escapeHtml(entry)}</span>`).join("")}
                  </div>
                ` : ""}
                <div class="database-review-detail-stack">
                  ${preview.lines.map((entry) => `<p class="database-review-detail-line">${escapeHtml(entry)}</p>`).join("")}
                </div>
              </div>
              <div class="database-review-actions database-review-actions-vertical">
                <button class="ghost-button compact-button" type="button" data-database-review-detail="${escapeHtml(item.personal_sample_key || "")}">查看样本详情</button>
                <label class="database-review-note-field">
                  <span>审核说明</span>
                  <textarea rows="4" data-database-review-note="${escapeHtml(item.request_id)}" placeholder="填写通过或驳回说明，便于后续追溯"></textarea>
                </label>
                <div class="database-review-action-row">
                  <button class="ghost-button compact-button" type="button" data-database-review="${escapeHtml(item.request_id)}" data-review-action="approve">通过</button>
                  <button class="ghost-button compact-button danger" type="button" data-database-review="${escapeHtml(item.request_id)}" data-review-action="reject">驳回</button>
                </div>
              </div>
            </article>
          `;}).join("")}
        </div>
      ` : '<p class="field-note">当前没有待审核的个人数据库提交记录。</p>',
    })}
    ${renderReleaseSection()}
    ${renderVersionLogSection()}`;
  } else if (state.databaseLibraryScope === "personal") {
    elements.databaseSubmissions.innerHTML = `${mine.length ? `
      <section class="database-review-board">
        <div class="database-review-board-head">
          <div>
            <p class="section-kicker">Submission Status</p>
            <h3>个人提交状态</h3>
          </div>
        </div>
        <div class="database-review-list">
          ${mine.map((item) => {
            const statusLabel = item.status === "approved" ? "已通过" : item.status === "rejected" ? "已驳回" : "待审核";
            const statusTone = item.status === "approved" ? "running" : item.status === "rejected" ? "failed" : "queued";
            const reviewNote = String(item.review_note || "").trim();
            const reviewedBy = String(item.reviewed_by || "").trim();
            const reviewedAt = String(item.reviewed_at || "").trim();
            return `
            <article class="database-review-card database-review-card-detailed">
              <div>
                <strong>${escapeHtml(item.sample_name || "-")}</strong>
                <p>提交时间：${escapeHtml(formatDate(item.created_at))}</p>
                ${(reviewNote || reviewedBy || reviewedAt) ? `
                  <div class="database-review-detail-stack">
                    ${reviewNote ? `<p class="database-review-detail-line"><strong>${item.status === "rejected" ? "驳回理由" : "审核说明"}：</strong>${escapeHtml(reviewNote)}</p>` : ""}
                    ${(reviewedBy || reviewedAt) ? `<p class="database-review-detail-line">审核人：${escapeHtml(reviewedBy || "-")} · ${escapeHtml(reviewedAt ? formatDate(reviewedAt) : "-")}</p>` : ""}
                  </div>
                ` : ""}
              </div>
              <span class="mini-chip ${statusTone}">
                ${escapeHtml(statusLabel)}
              </span>
            </article>
          `;}).join("")}
        </div>
      </section>
    ` : ""}
    ${renderVersionLogSection()}`;
  } else {
    elements.databaseSubmissions.innerHTML = "";
  }

  elements.databaseSubmissions.querySelectorAll("[data-database-review]").forEach((button) => {
    button.addEventListener("click", async () => {
      const requestId = String(button.dataset.databaseReview || "");
      const action = String(button.dataset.reviewAction || "");
      if (!requestId || !action) return;
      const noteField = elements.databaseSubmissions.querySelector(`[data-database-review-note="${CSS.escape(requestId)}"]`);
      const note = String(noteField?.value || "").trim();
      if (action === "reject" && !note) return;
      await requestJson(`/api/database/submissions/${encodeURIComponent(requestId)}/review`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action, note }),
      });
      showToast(action === "approve" ? "已通过主数据库审核" : "已驳回该入库申请");
      await loadDatabaseRecords();
    });
  });
  elements.databaseSubmissions.querySelectorAll("[data-database-review-detail]").forEach((button) => {
    button.addEventListener("click", async () => {
      const sampleKey = String(button.dataset.databaseReviewDetail || "");
      if (!sampleKey) return;
      await openDatabaseSampleModal(sampleKey);
    });
  });
  elements.databaseSubmissions.querySelectorAll("[data-database-publish-release]").forEach((button) => {
    button.addEventListener("click", async () => {
      openDatabaseReleaseModal();
    });
  });
}

function syncDatabaseHeadActionVisibility() {
  if (!(elements.submitDatabaseBatchMainButton instanceof HTMLElement)) return;
  const visibleRows = getVisibleDatabaseRecords();
  const selectedKeys = new Set((state.databaseSelectedSamples || []).map((item) => String(item || "").trim()).filter(Boolean));
  const eligibleCount = visibleRows.filter((row) => (
    selectedKeys.has(String(row.sample_key || ""))
    && row.can_submit_to_main
    && row.pending_submission_status !== "pending"
  )).length;
  const selectedCount = getSelectedDatabaseSampleRows().length;
  const showBatchSubmit = state.databaseLibraryScope === "personal";
  elements.submitDatabaseBatchMainButton.classList.toggle("hidden", !showBatchSubmit);
  elements.submitDatabaseBatchMainButton.disabled = !showBatchSubmit || eligibleCount <= 0;
  elements.submitDatabaseBatchMainButton.textContent = eligibleCount > 0
    ? `批量提交主库（${eligibleCount}）`
    : "批量提交主库";
  if (elements.openNextstrainBuildModalButton) {
    elements.openNextstrainBuildModalButton.disabled = selectedCount < 2;
    elements.openNextstrainBuildModalButton.textContent = selectedCount > 0
      ? `Nextstrain 构建（${selectedCount}）`
      : "Nextstrain 构建";
  }
}

function renderHostDatabaseRecords(focusKey = "", caretPosition = null) {
  if (!elements.hostDatabaseSummary || !elements.hostDatabaseList) return;
  const rows = [...(Array.isArray(state.hostDatabaseRecords) ? state.hostDatabaseRecords : []), ...getPendingReferenceRows("host")];
  const canManage = state.currentUser?.role === "admin";
  [
    elements.openHostLocalImportModalButton,
    elements.openHostSingleImportModalButton,
    elements.openHostBatchImportModalButton,
    elements.openHostRemoteImportModalButton,
    elements.buildHostIndexButton,
  ].forEach((button) => {
    if (!button) return;
    button.disabled = !canManage;
    button.classList.toggle("is-disabled", !canManage);
  });
  const builtCount = rows.filter((row) => String(row.index_status || "") === "built").length;
  const pendingCount = rows.filter((row) => row.__pending || String(row.index_status || "") !== "built").length;
  elements.hostDatabaseSummary.innerHTML = `
    <article><span>宿主记录</span><strong>${rows.length}</strong></article>
    <article><span>已构建索引</span><strong>${builtCount}</strong></article>
    <article><span>待处理</span><strong>${pendingCount}</strong></article>
  `;
  if (!rows.length) {
    elements.hostDatabaseList.innerHTML = `
      <div class="empty-state queue-empty">
        <strong>宿主数据库还没有记录</strong>
        <p>可以先本地导入宿主参考 FASTA，或通过 NCBI / Ensembl 下载后再统一构建索引。</p>
      </div>
    `;
    return;
  }
  elements.hostDatabaseList.innerHTML = buildReferenceTable("host", rows, canManage);
  bindReferenceRecordActions("host", elements.hostDatabaseList, focusKey, caretPosition);
}

function renderPathogenDatabaseRecords(focusKey = "", caretPosition = null) {
  if (!elements.pathogenDatabaseSummary || !elements.pathogenDatabaseList) return;
  const rows = [...(Array.isArray(state.pathogenDatabaseRecords) ? state.pathogenDatabaseRecords : []), ...getPendingReferenceRows("pathogen")];
  const canManage = state.currentUser?.role === "admin";
  [
    elements.openPathogenLocalImportModalButton,
    elements.openPathogenSingleImportModalButton,
    elements.openPathogenBatchImportModalButton,
    elements.openPathogenRemoteImportModalButton,
    elements.buildPathogenIndexButton,
    elements.buildPathogenCgmlstButton,
  ].forEach((button) => {
    if (!button) return;
    button.disabled = !canManage;
    button.classList.toggle("is-disabled", !canManage);
  });
  const builtCount = rows.filter((row) => String(row.index_status || "") === "built").length;
  const pendingCount = rows.filter((row) => row.__pending || String(row.index_status || "") !== "built").length;
  const selectedCount = Object.values(state.pathogenReferenceSelection || {}).filter(Boolean).length;
  elements.pathogenDatabaseSummary.innerHTML = `
    <article><span>病原记录</span><strong>${rows.length}</strong></article>
    <article><span>已构建索引</span><strong>${builtCount}</strong></article>
    <article><span>待处理</span><strong>${pendingCount}</strong></article>
    <article><span>已选参考</span><strong>${selectedCount}</strong></article>
  `;
  if (elements.buildPathogenIndexButton) {
    elements.buildPathogenIndexButton.textContent = selectedCount > 0 ? `构建选中 Index (${selectedCount})` : "构建病原 Index";
  }
  if (elements.buildPathogenCgmlstButton) {
    elements.buildPathogenCgmlstButton.disabled = !canManage || selectedCount === 0;
    elements.buildPathogenCgmlstButton.classList.toggle("is-disabled", !canManage || selectedCount === 0);
    elements.buildPathogenCgmlstButton.textContent = selectedCount > 0 ? `构建 cgMLST Panel (${selectedCount})` : "构建 cgMLST Panel";
  }
  if (!rows.length) {
    elements.pathogenDatabaseList.innerHTML = `
      <div class="empty-state queue-empty">
        <strong>病原基因组数据库还没有记录</strong>
        <p>可以先本地导入病原参考 FASTA，或通过 NCBI / GTDB 下载后再统一构建索引。</p>
      </div>
    `;
    return;
  }
  elements.pathogenDatabaseList.innerHTML = buildReferenceTable("pathogen", rows, canManage);
  bindReferenceRecordActions("pathogen", elements.pathogenDatabaseList, focusKey, caretPosition);
}

function renderPathogenCgmlstPanels() {
  if (!elements.pathogenCgmlstSummary || !elements.pathogenCgmlstList) return;
  const rows = Array.isArray(state.pathogenCgmlstPanels) ? state.pathogenCgmlstPanels : [];
  const builtCount = rows.filter((row) => String(row.status || "") === "built").length;
  const runningCount = rows.filter((row) => ["pending", "running"].includes(String(row.status || ""))).length;
  elements.pathogenCgmlstSummary.innerHTML = `
    <article><span>Panel 数</span><strong>${rows.length}</strong></article>
    <article><span>已构建</span><strong>${builtCount}</strong></article>
    <article><span>构建中</span><strong>${runningCount}</strong></article>
  `;
  if (!rows.length) {
    elements.pathogenCgmlstList.innerHTML = `
      <div class="empty-state queue-empty">
        <strong>还没有 cgMLST panel</strong>
        <p>先在上方病原库勾选同一物种或多物种参考基因组，再启动 chewBBACA 构建。</p>
      </div>
    `;
    return;
  }
  elements.pathogenCgmlstList.innerHTML = rows.map((row) => `
    <article class="reference-panel-card">
      <div class="reference-panel-card-head">
        <div>
          <strong>${escapeHtml(row.species_name || row.panel_key || "-")}</strong>
          <p>${escapeHtml(row.panel_type || "cgmlst").toUpperCase()} · ${escapeHtml(row.genome_count || 0)} 个参考基因组</p>
        </div>
        <span class="mini-chip ${String(row.status || "") === "built" ? "running" : String(row.status || "") === "failed" ? "failed" : "queued"}">${escapeHtml(row.status || "pending")}</span>
      </div>
      <div class="reference-panel-card-grid">
        <div><span>Schema 目录</span><code>${escapeHtml(row.schema_dir || "-")}</code></div>
        <div><span>cgMLST 目录</span><code>${escapeHtml(row.cgmlst_dir || "-")}</code></div>
        <div><span>Loci 列表</span><code>${escapeHtml(row.loci_list_path || "-")}</code></div>
        <div><span>Allele 结果</span><code>${escapeHtml(row.results_alleles_path || "-")}</code></div>
      </div>
      ${row.message ? `<p class="field-note">${escapeHtml(row.message)}</p>` : ""}
    </article>
  `).join("");
}

function bindReferenceRecordActions(category, container, focusKey = "", caretPosition = null) {
  if (!container) return;
  container.querySelectorAll("[data-reference-select-all]").forEach((input) => {
    input.addEventListener("change", () => {
      const rows = getSortedReferenceRows(
        getFilteredReferenceRows(
          [...(Array.isArray(state.pathogenDatabaseRecords) ? state.pathogenDatabaseRecords : []), ...getPendingReferenceRows("pathogen")],
          "pathogen",
        ),
        "pathogen",
      ).filter((row) => !row.__pending && String(row.host_key || "").trim());
      rows.forEach((row) => {
        state.pathogenReferenceSelection[String(row.host_key || "").trim()] = Boolean(input.checked);
      });
      renderPathogenDatabaseRecords();
    });
  });
  container.querySelectorAll("[data-reference-select]").forEach((input) => {
    input.addEventListener("change", () => {
      const hostKey = String(input.dataset.hostKey || "");
      if (!hostKey) return;
      state.pathogenReferenceSelection[hostKey] = Boolean(input.checked);
      renderPathogenDatabaseRecords();
    });
  });
  container.querySelectorAll("[data-reference-build]").forEach((button) => {
    button.addEventListener("click", async () => {
      const hostKey = String(button.dataset.hostKey || "");
      if (!hostKey) return;
      await withSubmittingState(button, "构建中...", async () => {
        if (category === "host") {
          await onBuildSingleHostIndex(hostKey);
        } else {
          await onBuildSinglePathogenIndex(hostKey);
        }
      });
    });
  });
  container.querySelectorAll("[data-reference-edit]").forEach((button) => {
    button.addEventListener("click", async () => {
      const hostKey = String(button.dataset.hostKey || "");
      if (!hostKey) return;
      await openReferenceEditModal(category, hostKey);
    });
  });
  container.querySelectorAll("[data-reference-delete]").forEach((button) => {
    button.addEventListener("click", async () => {
      const hostKey = String(button.dataset.hostKey || "");
      if (!hostKey) return;
      openReferenceDeleteModal(category, hostKey);
    });
  });
  container.querySelectorAll("[data-reference-job-delete]").forEach((button) => {
    button.addEventListener("click", async () => {
	      const jobId = String(button.dataset.jobId || "");
	      if (!jobId) return;
	      const confirmed = await confirmDangerAction({
	        title: "删除失败导入记录",
	        message: "确认删除这条失败的导入记录吗？",
	        impact: "该失败记录会从参考库导入列表中移除",
	        detail: "这只删除失败任务的记录，不会删除已成功导入的参考基因组。",
	        confirmLabel: "确认删除",
	      });
	      if (!confirmed) return;
      if (category === "host") {
        await requestJson(`/api/host-database/remote-import-jobs/${encodeURIComponent(jobId)}`, { method: "DELETE" });
      } else {
        await requestJson(`/api/pathogen-database/remote-import-jobs/${encodeURIComponent(jobId)}`, { method: "DELETE" });
      }
      showToast("已删除失败的导入记录");
      await loadDatabaseRecords();
    });
  });
  container.querySelectorAll("[data-reference-sort]").forEach((button) => {
    button.addEventListener("click", () => {
      const key = String(button.dataset.referenceSort || "");
      if (!key) return;
      const tableState = getReferenceTableState(category);
      if (tableState.sortKey === key) {
        tableState.sortDirection = tableState.sortDirection === "asc" ? "desc" : "asc";
      } else {
        tableState.sortKey = key;
        tableState.sortDirection = "asc";
      }
      renderReferenceCategoryRecords(category);
    });
  });
  container.querySelectorAll("[data-reference-filter]").forEach((input) => {
    bindImeSafeInput(input, () => {
      const key = String(input.dataset.referenceFilter || "");
      if (!key) return;
      getReferenceTableState(category).filters[key] = input.value;
      renderReferenceCategoryRecords(category, key, input.selectionStart ?? input.value.length);
    });
  });
  container.querySelectorAll("[data-reference-clear-filter]").forEach((button) => {
    button.addEventListener("click", () => {
	      const key = String(button.dataset.referenceClearFilter || "");
	      if (!key) return;
	      getReferenceTableState(category).filters[key] = "";
	      renderReferenceCategoryRecords(category, key, 0);
	    });
	  });
  if (focusKey) {
    const target = container.querySelector(`[data-reference-filter="${focusKey}"]`);
    if (target) {
      target.focus();
      const nextPos = Math.min(caretPosition ?? target.value.length, target.value.length);
      target.setSelectionRange(nextPos, nextPos);
    }
  }
}

function renderReferenceCategoryRecords(category, focusKey = "", caretPosition = null) {
  if (category === "host") {
    renderHostDatabaseRecords(focusKey, caretPosition);
  } else {
    renderPathogenDatabaseRecords(focusKey, caretPosition);
  }
}

function bindReferenceDropzone(dropzone, input, labelNode, entityLabel) {
  if (!dropzone || !input) return;
  dropzone.addEventListener("click", () => input.click());
  dropzone.addEventListener("keydown", (event) => {
    if (event.key !== "Enter" && event.key !== " ") return;
    event.preventDefault();
    input.click();
  });
  input.addEventListener("change", () => {
    const file = input.files?.[0] || null;
    dropzone.classList.toggle("has-file", Boolean(file));
    updateReferenceUploadName(labelNode, file, entityLabel);
  });
  ["dragenter", "dragover"].forEach((eventName) => {
    dropzone.addEventListener(eventName, (event) => {
      event.preventDefault();
      dropzone.classList.add("is-dragover");
    });
  });
  ["dragleave", "dragend", "drop"].forEach((eventName) => {
    dropzone.addEventListener(eventName, (event) => {
      event.preventDefault();
      if (eventName !== "drop") {
        dropzone.classList.remove("is-dragover");
      }
    });
  });
  dropzone.addEventListener("drop", (event) => {
    dropzone.classList.remove("is-dragover");
    const files = Array.from(event.dataTransfer?.files || []).filter((file) => file && file.name);
    if (!files.length) return;
    const transfer = new DataTransfer();
    transfer.items.add(files[0]);
    input.files = transfer.files;
    dropzone.classList.add("has-file");
    updateReferenceUploadName(labelNode, files[0], entityLabel);
  });
}

function updateReferenceUploadName(labelNode, file, entityLabel) {
  if (!labelNode) return;
  if (!file) {
    labelNode.textContent = `当前未上传本地文件，默认仍可使用上方路径选择器。`;
    return;
  }
  labelNode.textContent = `${entityLabel}上传文件：${file.name}`;
}

function buildHostSourceLabel(row) {
  const sourceType = String(row?.source_type || "local").trim().toLowerCase();
  const sourceLabel = String(row?.source_label || "").trim();
  if (sourceLabel) return `${sourceType.toUpperCase()} · ${sourceLabel}`;
  if (sourceType === "ncbi") return "NCBI 下载";
  if (sourceType === "ensembl") return "Ensembl 下载";
  return "本地导入";
}

function buildHostIndexStatusLabel(status) {
  if (status === "built") return "已构建";
  if (status === "prepared") return "已准备";
  if (status === "failed") return "失败";
  return "待构建";
}

function buildHostIndexChipClass(status) {
  if (status === "built") return "running";
  if (status === "failed") return "failed";
  return "queued";
}

function getPendingReferenceRows(category) {
  return state.pendingReferenceJobs.filter((item) => item.db_category === category);
}

function getReferenceStatusInfo(row) {
  if (row?.__pending) {
    if (row.__jobStatus === "failed" || row.status === "failed") {
      return { label: "导入失败", tone: "failed", percent: 100, pending: false };
    }
    const rawStatus = String(row.__jobStatus || row.status || "downloading").trim();
    const percent = Number(row.__jobPercent ?? row.progress_percent ?? 0) || 0;
    const label = rawStatus === "importing" ? "导入中" : "下载中";
    return { label, tone: "queued", percent: Math.max(1, Math.min(99, percent || 1)), pending: true };
  }
  const status = String(row?.index_status || "").trim();
  if (status === "built") {
    return { label: "Index成功", tone: "running", percent: 100, pending: false };
  }
  if (status === "failed") {
    return { label: "Index失败", tone: "failed", percent: 100, pending: false };
  }
  return { label: "导入成功", tone: "queued", percent: 100, pending: false };
}

function getReferenceErrorMessage(row) {
  const message = String(row?.message || row?.index_message || "").trim();
  if (!message) return "";
  return message;
}

function getReferenceTableState(category) {
  return category === "host" ? state.hostReferenceTable : state.pathogenReferenceTable;
}

function getReferenceColumns(category) {
  return [
    { key: "genome_name", label: "基因组名称", sortable: true, filterable: true },
    { key: "host_name", label: category === "host" ? "宿主名称" : "病原名称", sortable: true, filterable: true },
    { key: "taxid", label: "TaxID", sortable: true, filterable: true },
    { key: "source_info", label: "来源信息", sortable: true, filterable: true },
    { key: "status", label: "状态", sortable: true, filterable: true },
  ];
}

function getVirusPermissionCheckboxes(scope) {
  return Array.from(document.querySelectorAll(`input[data-virus-checkbox][data-virus-permission-scope="${scope}"]`));
}

function getVirusPermissionGroupCheckboxes(scope, groupKey) {
  if (!groupKey || groupKey === "__all__") return getVirusPermissionCheckboxes(scope);
  return getVirusPermissionCheckboxes(scope)
    .filter((input) => String(input.dataset.virusGroup || "").trim() === groupKey);
}

function getScopedAllowedViruses(scope) {
  return getVirusPermissionCheckboxes(scope)
    .filter((input) => input.checked)
    .map((input) => String(input.dataset.virusCheckbox || "").trim())
    .filter(Boolean);
}

function setScopedAllowedViruses(scope, viruses = []) {
  const selected = new Set(Array.isArray(viruses) ? viruses : []);
  getVirusPermissionCheckboxes(scope).forEach((input) => {
    input.checked = selected.has(String(input.dataset.virusCheckbox || "").trim());
  });
}

function setScopedVirusGroup(scope, groupKey, checked) {
  getVirusPermissionGroupCheckboxes(scope, groupKey).forEach((input) => {
    if (!input.disabled) input.checked = checked;
  });
}

function syncVirusPermissionUi(scope) {
  const role = getPermissionRoleValue(scope);
  const locked = role === "admin";
  const virusModuleCheckbox = getPermissionCheckboxes(scope).find((input) => input.dataset.moduleCheckbox === "virus");
  const hasVirusModule = locked || Boolean(virusModuleCheckbox?.checked);
  const virusCheckboxes = getVirusPermissionCheckboxes(scope);
  virusCheckboxes.forEach((input) => {
    input.disabled = locked || !hasVirusModule;
    const chip = input.closest(".virus-access-chip");
    if (!chip) return;
    chip.classList.toggle("is-selected", input.checked);
    chip.classList.toggle("is-disabled", input.disabled);
  });
  Object.entries(VIRUS_PERMISSION_GROUPS).forEach(([groupKey, groupItems]) => {
    const groupCheckboxes = getVirusPermissionGroupCheckboxes(scope, groupKey);
    const selectedCount = groupCheckboxes.filter((input) => input.checked).length;
    document.querySelectorAll(`[data-virus-group-panel="${groupKey}"][data-virus-permission-scope="${scope}"]`).forEach((panel) => {
      panel.classList.toggle("is-active", selectedCount > 0);
      panel.classList.toggle("is-complete", selectedCount > 0 && selectedCount === groupCheckboxes.length);
      const countElement = panel.querySelector("[data-virus-group-count]");
      if (countElement) {
        countElement.textContent = `${selectedCount} / ${groupItems.length}`;
      }
    });
  });
  document.querySelectorAll(`[data-virus-group-action][data-virus-permission-scope="${scope}"]`).forEach((button) => {
    const groupKey = String(button.dataset.virusGroup || "__all__").trim();
    const action = String(button.dataset.virusGroupAction || "").trim();
    const groupCheckboxes = getVirusPermissionGroupCheckboxes(scope, groupKey);
    const selectedCount = groupCheckboxes.filter((input) => input.checked).length;
    const allSelected = groupCheckboxes.length > 0 && selectedCount === groupCheckboxes.length;
    button.disabled = locked || !hasVirusModule || groupCheckboxes.length === 0
      || (action === "select" ? allSelected : selectedCount === 0);
  });
  document.querySelectorAll(`[data-virus-permission-scope="${scope}"]`).forEach((container) => {
    container.closest(".permission-expiry-field")?.classList.toggle("hidden", !hasVirusModule);
  });
}

function getReferenceCellValue(row, key) {
  if (key === "source_info") return buildHostSourceLabel(row);
  if (key === "status") return getReferenceStatusInfo(row).label;
  return String(row?.[key] || "");
}

function getFilteredReferenceRows(rows, category) {
  const filters = getReferenceTableState(category).filters || {};
  return rows.filter((row) => Object.entries(filters).every(([key, rawValue]) => {
    const value = String(rawValue || "").trim().toLowerCase();
    if (!value) return true;
    const cell = getReferenceCellValue(row, key).toLowerCase();
    return cell.includes(value);
  }));
}

function getSortedReferenceRows(rows, category) {
  const tableState = getReferenceTableState(category);
  const direction = tableState.sortDirection === "asc" ? 1 : -1;
  return [...rows].sort((left, right) => (
    String(getReferenceCellValue(left, tableState.sortKey)).localeCompare(
      String(getReferenceCellValue(right, tableState.sortKey)),
      "zh-CN",
    ) * direction
  ));
}

function getReferenceSortLabel(category) {
  const tableState = getReferenceTableState(category);
  const column = getReferenceColumns(category).find((item) => item.key === tableState.sortKey);
  return `${column?.label || tableState.sortKey} · ${tableState.sortDirection === "asc" ? "升序" : "降序"}`;
}

function buildReferenceTable(category, rows, canManage) {
  const tableState = getReferenceTableState(category);
  const columns = getReferenceColumns(category);
  const filteredRows = getFilteredReferenceRows(rows, category);
  const sortedRows = getSortedReferenceRows(filteredRows, category);
  const showSelection = category === "pathogen";
  const selectedMap = state.pathogenReferenceSelection || {};
  const selectableRows = showSelection ? sortedRows.filter((row) => !row.__pending && String(row.host_key || "").trim()) : [];
  const selectableKeys = selectableRows.map((row) => String(row.host_key || "").trim());
  const selectedCount = selectableKeys.filter((key) => selectedMap[key]).length;
  const isAllSelected = selectableKeys.length > 0 && selectedCount === selectableKeys.length;
  return `
    <div class="database-table-shell reference-table-shell">
      <div class="database-table-frame">
        <table class="database-table report-table table-tone-assembly reference-table">
          <thead>
            <tr>
              ${showSelection ? `
                <th class="reference-table-select-col">
                  <label class="reference-select-check">
                    <input type="checkbox" data-reference-select-all="pathogen" ${isAllSelected ? "checked" : ""}>
                  </label>
                </th>
              ` : ""}
              ${columns.map((column) => `
                <th>
                  <div class="table-head-stack queue-table-head-stack">
                    <button class="database-sort-button table-sort-button ${tableState.sortKey === column.key ? "active" : ""}" type="button" data-reference-sort="${escapeHtml(column.key)}" data-reference-category="${escapeHtml(category)}">
                      <span class="queue-table-head-label">${escapeHtml(column.label)}</span>
                      <span>${tableState.sortKey === column.key ? (tableState.sortDirection === "asc" ? "↑" : "↓") : "↕"}</span>
                    </button>
	                    ${renderTableFilterInput({
	                      value: tableState.filters[column.key] || "",
	                      dataName: "data-reference-filter",
	                      dataValue: column.key,
	                      clearDataName: "data-reference-clear-filter",
	                      extraAttrs: `data-reference-category="${escapeHtml(category)}"`,
	                    })}
                  </div>
                </th>
              `).join("")}
              <th><span class="queue-table-head-label">操作</span></th>
            </tr>
          </thead>
          <tbody>
            ${sortedRows.length ? sortedRows.map((row) => `
              <tr>
                ${showSelection ? `
                  <td class="reference-table-select-col"${renderMobileCellAttributes("选择", "selection")}>
                    ${row.__pending ? `<span class="field-note">-</span>` : `
                      <label class="reference-select-check">
                        <input type="checkbox" data-reference-select="pathogen" data-host-key="${escapeHtml(row.host_key || "")}" ${selectedMap[String(row.host_key || "")] ? "checked" : ""}>
                      </label>
                    `}
                  </td>
                ` : ""}
                <td class="database-cell-primary"${renderMobileCellAttributes(columns[0]?.label || "名称")}><strong>${escapeHtml(row.genome_name || row.host_key || "-")}</strong></td>
                <td${renderMobileCellAttributes(columns[1]?.label || "宿主")}>${escapeHtml(row.host_name || "-")}</td>
                <td${renderMobileCellAttributes(columns[2]?.label || "TaxID")}>${escapeHtml(row.taxid || "-")}</td>
                <td title="${escapeHtml(buildHostSourceLabel(row))}"${renderMobileCellAttributes(columns[3]?.label || "来源")}>${escapeHtml(truncateText(buildHostSourceLabel(row), 28))}</td>
                <td${renderMobileCellAttributes(columns[4]?.label || "状态")}>
                  ${(() => {
                    const status = getReferenceStatusInfo(row);
                    const detail = getReferenceErrorMessage(row);
                    return status.pending ? `
                      <div class="reference-status-block reference-status-${escapeHtml(status.tone)}">
                        <div class="reference-status-head">
                          <span>${escapeHtml(status.label)}</span>
                          <b>${escapeHtml(`${Math.round(status.percent)}%`)}</b>
                        </div>
                        <div class="queue-progress-track queue-progress-track-subtle" aria-hidden="true">
                          <div class="queue-progress-fill queue-progress-fill-subtle" style="width:${status.percent}%"></div>
                        </div>
                        ${detail ? `<small class="reference-status-detail" title="${escapeHtml(detail)}">${escapeHtml(truncateText(detail, 56))}</small>` : ""}
                      </div>
                    ` : `
                      <div class="reference-status-block reference-status-${escapeHtml(status.tone)}">
                        <span class="mini-chip ${escapeHtml(status.tone)}">${escapeHtml(status.label)}</span>
                        ${detail ? `<small class="reference-status-detail" title="${escapeHtml(detail)}">${escapeHtml(truncateText(detail, 56))}</small>` : ""}
                      </div>
                    `;
                  })()}
                </td>
                <td${renderMobileCellAttributes("操作", "actions")}>
                  <div class="reference-table-actions">
                    ${(() => {
                      const status = getReferenceStatusInfo(row);
                      if (row.__pending && status.pending) {
                        return '<span class="field-note">处理中</span>';
                      }
                      if (row.__pending && status.tone === "failed") {
                        return canManage
                          ? `<button class="user-action-button user-action-danger" type="button" data-reference-job-delete="${escapeHtml(category)}" data-job-id="${escapeHtml(row.job_id || "")}">删除失败记录</button>`
                          : '<span class="field-note">导入失败</span>';
                      }
                      return `
                      <button class="user-action-button" type="button" data-reference-edit="${escapeHtml(category)}" data-host-key="${escapeHtml(row.host_key || "")}">编辑信息</button>
                      <button class="user-action-button" type="button" data-reference-build="${escapeHtml(category)}" data-host-key="${escapeHtml(row.host_key || "")}">构建 Index</button>
                      ${canManage ? `<button class="user-action-button user-action-danger" type="button" data-reference-delete="${escapeHtml(category)}" data-host-key="${escapeHtml(row.host_key || "")}">删除</button>` : ""}
                    `;
                    })()}
                  </div>
                </td>
              </tr>
            `).join("") : `
	              <tr class="database-empty-row">
	                <td colspan="${columns.length + 1 + (showSelection ? 1 : 0)}">
	                  ${renderEmptyState({
	                    title: rows.length ? "当前筛选没有匹配参考记录" : "参考数据库中还没有记录",
	                    reason: rows.length ? "参考记录存在，但当前列筛选条件把它们全部过滤掉了。" : "当前分类下还没有导入宿主或病原参考基因组。",
	                    action: rows.length ? "清空表头筛选，或切换排序后重新查看。" : "可以先本地导入基因组，或通过 NCBI / Ensembl / GTDB 下载后再统一管理。",
	                    className: "queue-empty database-empty-state",
	                  })}
	                </td>
	              </tr>
            `}
          </tbody>
        </table>
      </div>
    </div>
  `;
}

function setRemoteImportProgress(category, percent, title, text, tone = "queued") {
  const map = category === "host" ? {
    panel: elements.hostRemoteProgress,
    title: elements.hostRemoteProgressTitle,
    text: elements.hostRemoteProgressText,
    percent: elements.hostRemoteProgressPercent,
    fill: elements.hostRemoteProgressFill,
  } : {
    panel: elements.pathogenRemoteProgress,
    title: elements.pathogenRemoteProgressTitle,
    text: elements.pathogenRemoteProgressText,
    percent: elements.pathogenRemoteProgressPercent,
    fill: elements.pathogenRemoteProgressFill,
  };
  if (!map.panel) return;
  map.panel.classList.remove("hidden", "queue-progress-queued", "queue-progress-success", "queue-progress-danger");
  map.panel.classList.add(`queue-progress-${tone}`);
  if (map.title) map.title.textContent = title;
  if (map.text) map.text.textContent = text;
  if (map.percent) map.percent.textContent = `${Math.round(percent)}%`;
  if (map.fill) map.fill.style.width = `${Math.max(0, Math.min(100, percent))}%`;
}

function resetRemoteImportProgress(category) {
  const panel = category === "host" ? elements.hostRemoteProgress : elements.pathogenRemoteProgress;
  if (!panel) return;
  panel.classList.add("hidden");
  panel.classList.remove("queue-progress-success", "queue-progress-danger");
  panel.classList.add("queue-progress-queued");
  setRemoteImportProgress(category, 0, "准备提交", "提交后将显示下载与导入进度。", "queued");
  panel.classList.add("hidden");
}

function setRemoteImportBusy(category, busy) {
  const submitButton = category === "host" ? elements.hostRemoteImportSubmit : elements.pathogenRemoteImportSubmit;
  const cancelButton = category === "host" ? elements.cancelHostRemoteImportButton : elements.cancelPathogenRemoteImportButton;
  const closeButton = category === "host" ? elements.closeHostRemoteImportModalButton : elements.closePathogenRemoteImportModalButton;
  if (submitButton) {
    submitButton.disabled = busy;
    submitButton.textContent = busy ? "处理中..." : "下载并导入";
  }
  if (cancelButton) cancelButton.disabled = busy;
  if (closeButton) closeButton.disabled = busy;
}

function startRemoteImportProgressSequence(category) {
  setRemoteImportProgress(category, 10, "准备下载", "正在提交请求并初始化下载任务。", "queued");
  const timers = [];
  timers.push(window.setTimeout(() => {
    setRemoteImportProgress(category, 48, "下载中", "正在从远程来源下载参考基因组。", "queued");
  }, 600));
  timers.push(window.setTimeout(() => {
    setRemoteImportProgress(category, 82, "导入中", "下载完成，正在写入参考基因组数据库。", "queued");
  }, 2200));
  return () => timers.forEach((timerId) => window.clearTimeout(timerId));
}

function commitDatabaseSearch(input = elements.databaseSearch) {
  state.databaseSearch = String(input?.value || "");
  renderDatabaseRecords();
  renderDatabaseMonitoring();
}

function normalizeDatabaseSortValue(row, key) {
  if (String(key).startsWith("meta:")) {
    const fieldKey = String(key).slice(5);
    const metadataValue = fieldKey === "collection_site"
      ? getDatabaseCollectionSiteDisplay(row)
      : getDatabaseMetadataDisplayValue(row, fieldKey);
    return metadataValue.toLowerCase();
  }
  if (key === "metadata_completion_label") {
    const orderMap = { complete: 3, missing_recommended: 2, missing_required: 1 };
    return orderMap[String(row?.metadata_completion_status || "").trim()] || 0;
  }
  const value = row?.[key];
  if (key === "imported_at") {
    return value ? new Date(value).getTime() : 0;
  }
  if (["resistance_count", "virulence_count", "contig_count", "plasmid_count"].includes(key)) {
    const num = Number(value);
    return Number.isFinite(num) ? num : -1;
  }
  return String(value || "").toLowerCase();
}

function getDatabaseColumns() {
  const coreMetadataKeys = new Set(["case_id", "suspected_syndrome", "submitting_unit", "collection_site"]);
  const metadataMap = new Map();
  (state.databaseMetadataTemplates || []).forEach((item, index) => {
    const fieldKey = String(item.key || item.field_key || "").trim();
    if (!fieldKey) return;
    metadataMap.set(fieldKey, {
      key: `meta:${fieldKey}`,
      label: String(item.label || fieldKey).trim(),
      sortable: true,
      always: coreMetadataKeys.has(fieldKey),
      metadata: true,
      position: Number.isFinite(Number(item.position)) ? Number(item.position) : index,
    });
  });
  (state.databaseRecords || []).forEach((row) => {
    parseCustomMetadata(row?.custom_metadata_json).forEach((item) => {
      const fieldKey = String(item?.key || "").trim();
      if (!fieldKey || metadataMap.has(fieldKey)) return;
      metadataMap.set(fieldKey, {
        key: `meta:${fieldKey}`,
        label: String(item?.label || fieldKey).trim(),
        sortable: true,
        always: false,
        metadata: true,
        position: 10_000 + metadataMap.size,
      });
    });
  });
  const metadataColumns = Array.from(metadataMap.values()).sort((left, right) => left.position - right.position);
  return [
    { key: "sample_name", label: "样本名称", sortable: true, always: true },
    { key: "task_name", label: "任务", sortable: true, always: true },
    { key: "owner", label: "归属用户", sortable: true, always: true },
    { key: "metadata_completion_label", label: "主档完整度", sortable: true, always: true },
    { key: "species_name", label: "物种预估", sortable: true, always: true },
    { key: "q_metrics", label: "Q20 / Q30", sortable: false, always: true },
    { key: "completeness", label: "完整性", sortable: false, always: true },
    { key: "contamination", label: "污染率", sortable: false, always: true },
    { key: "contig_count", label: "Contig / 质粒", sortable: true, always: true },
    { key: "sample_alias", label: "样本别名", sortable: true, always: false },
    { key: "genome_id", label: "Genome ID", sortable: true, always: false },
    { key: "taxid", label: "TaxID", sortable: true, always: false },
    { key: "mlst_st", label: "MLST ST", sortable: true, always: false },
    { key: "serotype_result", label: "血清型", sortable: true, always: false },
    { key: "resistance_gene_hits", label: "耐药基因摘要", sortable: true, always: false },
    { key: "virulence_gene_hits", label: "毒力基因摘要", sortable: true, always: false },
    { key: "resistance_mge_hits", label: "耐药基因-MGE", sortable: true, always: false },
    { key: "virulence_mge_hits", label: "毒力基因-MGE", sortable: true, always: false },
    { key: "sample_source", label: "样本来源", sortable: true, always: false },
    { key: "collection_date", label: "采样日期", sortable: true, always: false },
    { key: "country", label: "国家 / 地区", sortable: true, always: false },
    { key: "host_info", label: "宿主 / 背景", sortable: true, always: false },
    { key: "sample_type", label: "输入类型", sortable: true, always: false },
    { key: "sequencing_method", label: "测序 / 组装方法", sortable: true, always: false },
    { key: "resistance_count", label: "耐药 / 毒力", sortable: true, always: false },
    { key: "total_length", label: "总长度", sortable: false, always: false },
    { key: "imported_at", label: "入库时间", sortable: true, always: false },
    { key: "final_fasta_path", label: "Final FASTA", sortable: false, always: false },
    ...metadataColumns.map(({ position, ...column }) => column),
  ];
}

function getVisibleDatabaseColumns() {
  const columns = getDatabaseColumns();
  if (state.databaseTable.view === "all") return columns;
  return columns.filter((column) => column.always);
}

function getFilteredDatabaseRecords(rows) {
  const filters = state.databaseTable.filters || {};
  return rows.filter((row) => {
    return Object.entries(filters).every(([key, rawValue]) => {
      const value = String(rawValue || "").trim().toLowerCase();
      if (!value) return true;
      if (key === "pathogen_type") {
        return inferDatabaseRecordPathogenType(row) === value;
      }
      if (key === "metadata_completion_label") {
        const status = String(row?.metadata_completion_status || "").trim();
        if (value === "__complete__") return status === "complete";
        if (value === "__missing_recommended__") return status === "missing_recommended";
        if (value === "__missing_required__") return status === "missing_required";
      }
      let cell = "";
      if (key === "species_name") {
        cell = [row.species_name, row.mlst_species_name, row.mlst_st, row.serotype_result].join(" ");
      } else if (String(key).startsWith("meta:")) {
        const fieldKey = String(key).slice(5);
        cell = fieldKey === "collection_site"
          ? getDatabaseCollectionSiteDisplay(row)
          : getDatabaseMetadataDisplayValue(row, fieldKey);
      } else {
        cell = String(row?.[key] || "");
      }
      if (matchesNumericFilter(cell, value)) {
        return true;
      }
      return cell.toLowerCase().includes(value);
    });
  });
}

function getDatabaseColumnLabelMap(columns = getDatabaseColumns()) {
  return Object.fromEntries((columns || []).map((column) => [column.key, column.label || column.key]));
}

function getDatabaseActiveFilterChips(columns = getDatabaseColumns()) {
  const labelMap = getDatabaseColumnLabelMap(columns);
  const chips = [];
  const keyword = String(state.databaseSearch || "").trim();
  if (keyword) {
    chips.push({ key: "__search__", label: "全局搜索", value: keyword });
  }
  Object.entries(state.databaseTable.filters || {}).forEach(([key, rawValue]) => {
    const value = String(rawValue || "").trim();
    if (!value) return;
    const label = labelMap[key] || (key.startsWith("meta:") ? key.slice(5) : key);
    const displayValue = key === "metadata_completion_label"
      ? ({
        "__complete__": "主档完整",
        "__missing_recommended__": "缺推荐项",
        "__missing_required__": "缺关键项",
      }[value] || value)
      : value;
    chips.push({ key, label, value: displayValue });
  });
  return chips;
}

function renderDatabaseTableStateBar({ totalRows, visibleRows, selectedCount, selectedInViewCount, columns }) {
  const chips = getDatabaseActiveFilterChips(columns);
  const viewLabel = state.databaseTable.view === "all" ? "完整字段视图" : "关键字段视图";
  const sortColumn = (columns || []).find((column) => column.key === state.databaseTable.sortKey)
    || getDatabaseColumns().find((column) => column.key === state.databaseTable.sortKey);
  const sortLabel = sortColumn?.label || state.databaseTable.sortKey || "默认";
  const scopeLabel = state.databaseLibraryScope === "personal" ? "个人数据库" : "主数据库";
  return `
    <div class="queue-table-statebar database-table-statebar">
      <div class="queue-table-state-toprow">
        <div class="queue-table-state-meta">
          <span class="queue-table-state-pill">范围：${escapeHtml(scopeLabel)}</span>
          <span class="queue-table-state-pill">命中：${escapeHtml(String(visibleRows))} / ${escapeHtml(String(totalRows))}</span>
          <span class="queue-table-state-pill">已选：${escapeHtml(String(selectedCount))}${selectedInViewCount ? `（当前 ${escapeHtml(String(selectedInViewCount))}）` : ""}</span>
          <span class="queue-table-state-pill">视图：${escapeHtml(viewLabel)}</span>
          <span class="queue-table-state-pill">排序：${escapeHtml(sortLabel)} ${state.databaseTable.sortDirection === "asc" ? "↑" : "↓"}</span>
        </div>
        ${(chips.length || selectedCount) ? `
          <button class="ghost-button compact-button database-table-clear-button" type="button" data-database-clear-workbench>
            清空当前工作台
          </button>
        ` : ""}
      </div>
      <div class="queue-table-filter-chip-row database-table-filter-chip-row" aria-label="当前样本列表筛选条件">
        ${chips.length ? chips.map((chip) => `
          <button class="queue-table-filter-chip" type="button" data-database-clear-chip="${escapeHtml(chip.key)}" title="清除该条件">
            <span>${escapeHtml(chip.label)}</span>
            <strong>${escapeHtml(truncateText(chip.value, 28))}</strong>
            <span aria-hidden="true">×</span>
          </button>
        `).join("") : `
          <span class="queue-table-filter-placeholder">未启用筛选，当前显示完整工作范围。</span>
        `}
      </div>
    </div>
  `;
}

function toggleDatabaseSampleSelection(sampleKey, checked) {
  const next = new Set(state.databaseSelectedSamples || []);
  if (checked) {
    next.add(sampleKey);
  } else {
    next.delete(sampleKey);
  }
  state.databaseSelectedSamples = Array.from(next);
}

function toggleDatabaseVisibleSelection(rows, checked) {
  const next = new Set(state.databaseSelectedSamples || []);
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const sampleKey = String(row?.sample_key || "").trim();
    if (!sampleKey) return;
    if (checked) {
      next.add(sampleKey);
    } else {
      next.delete(sampleKey);
    }
  });
  state.databaseSelectedSamples = Array.from(next);
}

function getMetadataRowValue(row) {
  const type = String(row.querySelector(".database-metadata-type")?.value || "text").trim();
  if (type === "location") {
    return {
      province: String(row.querySelector(".database-metadata-location-province")?.value || "").trim(),
      city: String(row.querySelector(".database-metadata-location-city")?.value || "").trim(),
      district: String(row.querySelector(".database-metadata-location-district")?.value || "").trim(),
      detail: String(row.querySelector(".database-metadata-location-detail")?.value || "").trim(),
    };
  }
  if (type === "country") {
    return String(row.querySelector(".database-metadata-country-input")?.value || "").trim();
  }
  if (type === "datetime") {
    return String(row.querySelector(".database-metadata-datetime-input")?.value || "").trim();
  }
  if (type === "select") {
    return String(row.querySelector(".database-metadata-select-input")?.value || "").trim();
  }
  return String(row.querySelector(".database-metadata-text-input")?.value || "").trim();
}

function updateMetadataRowValue(row, value) {
  const type = String(row.querySelector(".database-metadata-type")?.value || "text").trim();
  if (type === "location") {
    const payload = value && typeof value === "object" ? value : {};
    const province = canonicalizeChinaProvinceName(String(payload.province || ""));
    const city = canonicalizeChinaCityName(province, String(payload.city || ""));
    const district = canonicalizeChinaDistrictName(province, city, String(payload.district || ""));
    populateDatabaseMetadataProvinceOptions(row, province);
    populateDatabaseMetadataCityOptions(row, province, city);
    populateDatabaseMetadataDistrictOptions(row, province, city, district);
    const detailInput = row.querySelector(".database-metadata-location-detail");
    if (detailInput) detailInput.value = String(payload.detail || "").trim();
    return;
  }
  if (type === "country") {
    populateCountrySelect(row.querySelector(".database-metadata-country-input"), String(value || "").trim());
    return;
  }
  if (type === "datetime") {
    const input = row.querySelector(".database-metadata-datetime-input");
    if (input) input.value = String(value || "").trim();
    return;
  }
  if (type === "select") {
    const input = row.querySelector(".database-metadata-select-input");
    if (input) input.value = String(value || "").trim();
    return;
  }
  const input = row.querySelector(".database-metadata-text-input");
  if (input) input.value = String(value || "").trim();
}

function findMetadataRowByKey(container, key) {
  if (!(container instanceof HTMLElement) || !key) return null;
  return Array.from(container.querySelectorAll(".database-metadata-row")).find((row) => {
    return String(row.querySelector(".database-metadata-key")?.value || "").trim() === key;
  }) || null;
}

function applyDatabaseArchiveTemplate(presetKey, container) {
  const preset = DATABASE_ARCHIVE_PRESETS[presetKey];
  if (!preset || !(container instanceof HTMLElement)) {
    return;
  }
  Object.entries(preset.values || {}).forEach(([key, value]) => {
    const row = findMetadataRowByKey(container, key);
    if (!row) return;
    updateMetadataRowValue(row, value);
  });
  showToast(`已应用${preset.label}`);
}

function parseComparableNumber(value) {
  const text = String(value ?? "").trim();
  if (!text || text === "--") return null;
  const normalized = text.replace(/,/g, "").replace(/%/g, "");
  const match = normalized.match(/-?\d+(?:\.\d+)?/);
  if (!match) return null;
  const parsed = Number(match[0]);
  return Number.isFinite(parsed) ? parsed : null;
}

function matchesNumericFilter(cellValue, filterValue) {
  const numericValue = parseComparableNumber(cellValue);
  if (numericValue === null) return false;
  const expr = String(filterValue ?? "").trim().replace(/\s+/g, "");
  if (!expr) return true;
  const rangeMatch = expr.match(/^(-?\d+(?:\.\d+)?)\s*(?:-|~)\s*(-?\d+(?:\.\d+)?)$/);
  if (rangeMatch) {
    const min = Number(rangeMatch[1]);
    const max = Number(rangeMatch[2]);
    if (!Number.isFinite(min) || !Number.isFinite(max)) return false;
    return numericValue >= Math.min(min, max) && numericValue <= Math.max(min, max);
  }
  const compareMatch = expr.match(/^(<=|>=|=|<|>)(-?\d+(?:\.\d+)?)$/);
  if (compareMatch) {
    const operator = compareMatch[1];
    const target = Number(compareMatch[2]);
    if (!Number.isFinite(target)) return false;
    if (operator === "<") return numericValue < target;
    if (operator === "<=") return numericValue <= target;
    if (operator === ">") return numericValue > target;
    if (operator === ">=") return numericValue >= target;
    return numericValue === target;
  }
  const exact = Number(expr);
  if (Number.isFinite(exact)) {
    return numericValue === exact;
  }
  return String(cellValue ?? "").toLowerCase().includes(String(filterValue ?? "").trim().toLowerCase());
}

function getDatabaseMetadataMap(row) {
  const items = parseCustomMetadata(row?.custom_metadata_json);
  return items.reduce((accumulator, item) => {
    const fieldKey = String(item?.key || "").trim();
    if (!fieldKey) return accumulator;
    accumulator[fieldKey] = item;
    return accumulator;
  }, {});
}

function getDatabaseMetadataDisplayValue(row, fieldKey) {
  const item = getDatabaseMetadataMap(row)[fieldKey];
  if (!item) return "";
  if (item.type === "location" && item.value && typeof item.value === "object") {
    return [item.value.province, item.value.city, item.value.district, item.value.detail]
      .map((part) => String(part || "").trim())
      .filter(Boolean)
      .join(" / ");
  }
  if (Array.isArray(item.value)) {
    return item.value.join(" / ");
  }
  return String(item.value || "").trim();
}

function getDatabaseCollectionSiteParts(row) {
  const item = getDatabaseMetadataMap(row).collection_site;
  if (item?.type === "location" && item.value && typeof item.value === "object") {
    return {
      region: [item.value.province, item.value.city, item.value.district].map((part) => String(part || "").trim()).filter(Boolean).join(" / "),
      detail: String(item.value.detail || "").trim(),
    };
  }
  const raw = getDatabaseMetadataDisplayValue(row, "collection_site");
  if (!raw) {
    return { region: "", detail: "" };
  }
  const parts = raw.split("/").map((part) => String(part || "").trim()).filter(Boolean);
  if (parts.length <= 1) return { region: raw, detail: "" };
  return {
    region: parts.slice(0, 3).join(" / "),
    detail: parts.slice(3).join(" / "),
  };
}

function getSortedDatabaseRecords(rows) {
  const key = state.databaseTable.sortKey;
  const direction = state.databaseTable.sortDirection === "asc" ? 1 : -1;
  return [...rows].sort((left, right) => {
    const a = normalizeDatabaseSortValue(left, key);
    const b = normalizeDatabaseSortValue(right, key);
    if (typeof a === "number" && typeof b === "number") {
      return (a - b) * direction;
    }
    return String(a).localeCompare(String(b), "zh-CN") * direction;
  });
}

function getDatabaseSortLabel() {
  const labels = {
    sample_name: "样本名称",
    task_name: "任务名称",
    owner: "归属用户",
    metadata_completion_label: "主档完整度",
    species_name: "物种预估",
    imported_at: "入库时间",
    contig_count: "Contig",
    plasmid_count: "质粒",
    resistance_count: "耐药",
    virulence_count: "毒力",
    mlst_st: "MLST ST",
    serotype_result: "血清型",
    resistance_gene_hits: "耐药基因摘要",
    virulence_gene_hits: "毒力基因摘要",
    resistance_mge_hits: "耐药基因-MGE",
    virulence_mge_hits: "毒力基因-MGE",
  };
  return `${labels[state.databaseTable.sortKey] || state.databaseTable.sortKey} · ${state.databaseTable.sortDirection === "asc" ? "升序" : "降序"}`;
}

function splitDatabaseSignalValues(rawValue) {
  return String(rawValue || "")
    .split(/[、,;；/]/)
    .map((item) => String(item || "").trim())
    .filter(Boolean)
    .map((item) => item.replace(/（.*?）|\(.*?\)/g, "").trim())
    .filter(Boolean);
}

function buildDatabaseMgeRiskSummary(rows) {
  const sourceRows = Array.isArray(rows) ? rows : [];
  const flaggedRows = sourceRows.filter((row) => {
    return Boolean(String(row?.resistance_mge_hits || "").trim() || String(row?.virulence_mge_hits || "").trim());
  });
  if (!flaggedRows.length) {
    return {
      flaggedSamples: 0,
      text: "当前样本范围内未见明确的 MGE 相关耐药/毒力基因线索。",
      short: "未见明确 MGE 风险线索",
      resistanceTop: "",
      virulenceTop: "",
    };
  }

  const buildTop = (key) => {
    const counts = new Map();
    flaggedRows.forEach((row) => {
      splitDatabaseSignalValues(row?.[key]).forEach((item) => {
        counts.set(item, (counts.get(item) || 0) + 1);
      });
    });
    const ranked = Array.from(counts.entries()).sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0], "zh-Hans-CN"));
    return ranked.slice(0, 2).map(([label, count]) => `${label}（${count}）`).join("、");
  };

  const resistanceTop = buildTop("resistance_mge_hits");
  const virulenceTop = buildTop("virulence_mge_hits");
  const textParts = [`当前样本范围内共有 ${flaggedRows.length} 份样本带有 MGE 相关基因线索。`];
  if (resistanceTop) {
    textParts.push(`耐药侧以 ${resistanceTop} 为主。`);
  }
  if (virulenceTop) {
    textParts.push(`毒力侧以 ${virulenceTop} 为主。`);
  }
  return {
    flaggedSamples: flaggedRows.length,
    text: textParts.join(""),
    short: resistanceTop || virulenceTop ? `MGE 风险样本 ${flaggedRows.length} 份` : `${flaggedRows.length} 份样本存在 MGE 线索`,
    resistanceTop,
    virulenceTop,
  };
}

function buildDatabaseSignalSummary(rows, key, emptyText, label) {
  const sourceRows = Array.isArray(rows) ? rows : [];
  const hitRows = sourceRows.filter((row) => Boolean(String(row?.[key] || "").trim()));
  if (!hitRows.length) {
    return {
      sampleCount: 0,
      top: "",
      text: emptyText,
      short: emptyText,
      label,
    };
  }
  const counts = new Map();
  hitRows.forEach((row) => {
    splitDatabaseSignalValues(row?.[key]).forEach((item) => {
      counts.set(item, (counts.get(item) || 0) + 1);
    });
  });
  const ranked = Array.from(counts.entries())
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0], "zh-Hans-CN"))
    .slice(0, 3);
  const top = ranked.map(([item, count]) => `${item}（${count}）`).join("、");
  return {
    sampleCount: hitRows.length,
    top,
    text: top ? `当前样本范围内共有 ${hitRows.length} 份样本记录到${label}，以 ${top} 为主。` : emptyText,
    short: top || `${hitRows.length} 份样本存在${label}`,
    label,
    details: top,
  };
}

function getDatabaseReportRowsForIssue(rows, issue) {
  if (!issue?.start || !issue?.end) return [];
  return (Array.isArray(rows) ? rows : []).filter((row) => {
    const date = getDatabaseRecordDate(row);
    if (!date) return false;
    return date >= issue.start && date <= issue.end;
  });
}

function getDatabaseHistoricalBaseline(rows, period, selectedIssue, topicMeta) {
  const issueOptions = getDatabaseReportIssueOptions(rows, period);
  if (!issueOptions.length || !selectedIssue?.value) {
    return {
      available: false,
      periods: [],
      averageSampleCount: 0,
      averageMgeCount: 0,
      averageTopSpeciesCount: 0,
      currentVsAverageRatio: 1,
      sampleDelta: 0,
      mgeDelta: 0,
      supportLevel: "limited",
      summary: "当前历史期次不足，暂未形成稳定历史基线。",
      periodLabel: "历史基线不足",
    };
  }
  const currentIndex = issueOptions.findIndex((item) => item.value === selectedIssue.value);
  const previousIssues = issueOptions.slice(currentIndex + 1, currentIndex + 5);
  if (!previousIssues.length) {
    return {
      available: false,
      periods: [],
      averageSampleCount: 0,
      averageMgeCount: 0,
      averageTopSpeciesCount: 0,
      currentVsAverageRatio: 1,
      sampleDelta: 0,
      mgeDelta: 0,
      supportLevel: "limited",
      summary: "当前仅有单一期次记录，暂未形成可比较的历史基线。",
      periodLabel: "仅当前期次",
    };
  }
  const periods = previousIssues.map((issue) => {
    const issueRows = getDatabaseReportRowsForIssue(rows, issue);
    const monitoringRows = applyDatabaseMonitoringMetadataFilters(getDatabaseMonitoringScopedRows(issueRows));
    const scopedRows = applyDatabaseReportTopicFilter(monitoringRows, topicMeta);
    const speciesSeries = buildDatabaseCountSeries(scopedRows, (item) => item.species_name || item.mlst_species_name, 3);
    const topSpecies = speciesSeries.labels[0] || "";
    const topSpeciesCount = speciesSeries.values[0] || 0;
    const mgeCount = buildDatabaseMgeRiskSummary(scopedRows).flaggedSamples;
    return {
      value: issue.value,
      label: issue.label,
      sampleCount: scopedRows.length,
      mgeCount,
      topSpecies,
      topSpeciesCount,
    };
  });
  const averageSampleCount = periods.reduce((sum, item) => sum + item.sampleCount, 0) / periods.length;
  const averageMgeCount = periods.reduce((sum, item) => sum + item.mgeCount, 0) / periods.length;
  const averageTopSpeciesCount = periods.reduce((sum, item) => sum + item.topSpeciesCount, 0) / periods.length;
  return {
    available: true,
    periods,
    averageSampleCount,
    averageMgeCount,
    averageTopSpeciesCount,
    periodLabel: `近${periods.length}期基线`,
    supportLevel: periods.length >= 3 ? "strong" : "moderate",
    summary: `已基于${periods.map((item) => item.label).join("、")}建立同口径历史基线。`,
  };
}

