function buildDatabaseReportPresetOptionsMarkup() {
  const presetOrder = [
    "general",
    "hai",
    "environment",
    "cluster",
    ...getDatabaseReportSyndromeTemplateDefinitions().map((item) => item.key),
  ];
  const presets = getDatabaseReportPresetDefinitions();
  return presetOrder
    .filter((key) => presets[key])
    .map((key) => `<option value="${escapeHtml(key)}">${escapeHtml(presets[key].title)}</option>`)
    .join("");
}

function buildDatabaseReportSyndromeTopicMeta(label) {
  const normalizedLabel = String(label || "").trim();
  const normalizedLookup = normalizeKnowledgeLookup(normalizedLabel);
  const leadMap = {
    "脑膜炎/脑膜脑炎": "聚焦脑膜炎、脑炎及相关侵袭性感染样本中的重点病原、血清群和 ST 分型信号。",
    "肺炎/呼吸道感染": "聚焦肺炎和呼吸道感染样本中的主导病原、场景分布和阶段变化。",
    "败血症/血流感染": "聚焦败血症和血流感染样本中的侵袭性病原、耐药压力和高风险分型背景。",
    "腹泻/肠道感染": "聚焦腹泻病、胃肠道和肠道传播相关病原的结构分布与血清/分型线索。",
    "皮肤软组织感染": "聚焦皮肤软组织感染样本中的主导病原、场景分布和耐药背景。",
    "泌尿生殖道感染": "聚焦泌尿生殖道感染样本中的主导病原、耐药和重点分型背景。",
    "医院感染监测": "聚焦医院感染监测样本中的重点病原、病区来源和耐药/MGE 风险。",
    "环境异常事件": "聚焦环境异常事件样本中的点位变化、病原构成和异常信号。",
    "不明原因感染": "聚焦不明原因感染样本中的异常病原、少见分型和待解释信号。",
    "其他": "聚焦其他症候群样本中的主导病原和补充性背景线索。",
  };
  return {
    title: `${normalizedLabel}专题`,
    lead: leadMap[normalizedLabel] || `聚焦${normalizedLabel}样本中的主导病原、区域场景和重点分型线索。`,
    knowledgeFocus: `优先解释${normalizedLabel}样本中已命中的主导病原、ST 分型、血清型及相关分子线索。`,
    exportLabel: `专题导出：${normalizedLabel}`,
    sectionOrder: ["method", "overview", "findings", "knowledge", "region", "spectrum", "discussion"],
    matcher: (item) => {
      const syndrome = normalizeKnowledgeLookup(getDatabaseMetadataDisplayValue(item, "suspected_syndrome"));
      return syndrome === normalizedLookup;
    },
  };
}

function inferDatabaseReportPreset(topic) {
  const presets = getDatabaseReportPresetDefinitions();
  const matched = Object.entries(presets).find(([, config]) => config.topic === topic);
  return matched ? matched[0] : "custom";
}

function getCurrentDatabaseReportPresetMeta() {
  const presetKey = String(state.databaseReportPreset || state.databaseReportTopic || "general");
  const presets = getDatabaseReportPresetDefinitions();
  const periodMeta = getDatabaseReportPeriodMeta(state.databaseReportPeriod || "monthly");
  const topicMeta = getDatabaseReportTopicMeta(state.databaseReportTopic || "general");
  if (!presets[presetKey]) {
    return {
      key: "general",
      title: `${topicMeta.title} · ${periodMeta.title}`,
      focus: `当前按“${topicMeta.title} + ${periodMeta.title}”组合生成，适合按专题切换不同报种。`,
      usage: "可继续选择期次和地域范围形成正式统计简报。",
      locked: false,
    };
  }
  const base = presets[presetKey];
  return {
    key: presetKey,
    ...base,
    title: `${base.title} · ${periodMeta.title}`,
    focus: `${base.focus} 当前以${periodMeta.title}口径输出。`,
    usage: base.usage,
    locked: false,
  };
}

function renderDatabaseReportModeSummary(rows) {
  if (!elements.databaseReportModeSummary) return;
  const presetMeta = getCurrentDatabaseReportPresetMeta();
  const selectedIssue = getDatabaseReportSelectedIssue(rows, state.databaseReportPeriod || "monthly");
  const issueLabel = selectedIssue?.label || "暂无可用期次";
  const locationLabel = elements.databaseReportLocation?.selectedOptions?.[0]?.textContent?.trim() || "全部地域";
  const topicMeta = getDatabaseReportTopicMeta(state.databaseReportTopic || "general");
  const periodMeta = getDatabaseReportPeriodMeta(state.databaseReportPeriod || "monthly");
  elements.databaseReportModeSummary.innerHTML = `
    <article class="database-report-mode-card${presetMeta.locked ? "" : " is-custom"}">
      <div class="database-report-mode-head">
        <div>
          <span class="database-report-mode-kicker">报告模式</span>
          <h4>${escapeHtml(presetMeta.title)}</h4>
        </div>
        <span class="database-report-mode-badge">${escapeHtml(periodMeta.title)}</span>
      </div>
      <p class="database-report-mode-focus">${escapeHtml(presetMeta.focus)}</p>
      <div class="database-report-mode-meta">
        <span><strong>专题：</strong>${escapeHtml(topicMeta.title)}</span>
        <span><strong>报种：</strong>${escapeHtml(periodMeta.title)}</span>
        <span><strong>期次：</strong>${escapeHtml(issueLabel)}</span>
        <span><strong>地域：</strong>${escapeHtml(locationLabel)}</span>
      </div>
      <p class="database-report-mode-usage">${escapeHtml(presetMeta.usage)}</p>
    </article>
  `;
}

function exportDatabaseSituationReport() {
  const context = state.databaseReportExportContext;
  const contentHtml = elements.databaseReportContent?.innerHTML || "";
  if (!context || !contentHtml.trim()) {
    showToast("当前报告内容尚未生成，暂时无法导出。");
    return;
  }
  const exportHtml = buildDatabaseReportExportDocument(context, contentHtml);
  const exportBlob = new Blob([exportHtml], { type: "text/html;charset=utf-8" });
  const exportUrl = URL.createObjectURL(exportBlob);
  const exportWindow = window.open(exportUrl, "_blank");
  if (!exportWindow) {
    showToast("导出窗口未能打开，请检查浏览器弹窗设置。");
    URL.revokeObjectURL(exportUrl);
    return;
  }
  exportWindow.addEventListener("beforeunload", () => {
    URL.revokeObjectURL(exportUrl);
  });
}

