function buildKnowledgeBasePathogenIndex() {
  const bundle = state.knowledgeBaseBundle?.collections?.pathogens;
  const index = new Map();
  if (!Array.isArray(bundle)) return index;
  bundle.forEach((item) => {
    if (!item || typeof item !== "object") return;
    const candidates = [
      item.id,
      item.species,
      item.common_name,
      item.taxid,
      item.ncbi_taxonomy?.scientific_name,
      item.ncbi_taxonomy?.classification?.species,
      ...(Array.isArray(item.aliases) ? item.aliases : []),
    ];
    candidates.forEach((value) => {
      const normalized = normalizeKnowledgeLookup(value);
      if (!normalized || index.has(normalized)) return;
      index.set(normalized, item);
    });
  });
  return index;
}

function getKnowledgeBaseCollection(collectionKey) {
  const collections = state.knowledgeBaseBundle?.collections;
  const items = collections?.[collectionKey];
  return Array.isArray(items) ? items : [];
}

function normalizeKnowledgeLookup(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ");
}

function resolveKnowledgePathogenForSpecies(speciesName) {
  const normalized = normalizeKnowledgeLookup(speciesName);
  if (!normalized) return null;
  const index = buildKnowledgeBasePathogenIndex();
  if (index.has(normalized)) return index.get(normalized) || null;
  for (const [key, value] of index.entries()) {
    if (normalized.includes(key) || key.includes(normalized)) return value;
  }
  return null;
}

function getKnowledgePathogenNames(pathogen) {
  if (!pathogen || typeof pathogen !== "object") return [];
  const candidates = [
    pathogen.id,
    pathogen.species,
    pathogen.common_name,
    pathogen.ncbi_taxonomy?.scientific_name,
    ...(Array.isArray(pathogen.aliases) ? pathogen.aliases : []),
  ];
  return candidates
    .map((value) => normalizeKnowledgeLookup(value))
    .filter(Boolean)
    .filter((value, index, array) => array.indexOf(value) === index);
}

function scopeMatchesKnowledgePathogen(scopeValues, pathogen) {
  if (!Array.isArray(scopeValues) || !scopeValues.length || !pathogen) return false;
  const pathogenNames = getKnowledgePathogenNames(pathogen);
  if (!pathogenNames.length) return false;
  return scopeValues.some((value) => {
    const normalized = normalizeKnowledgeLookup(value);
    if (!normalized) return false;
    return pathogenNames.some((name) => normalized === name || normalized.includes(name) || name.includes(normalized));
  });
}

function buildKnowledgeGeneRuleMatches(pathogen) {
  const geneRules = getKnowledgeBaseCollection("gene_rules");
  return geneRules
    .filter((rule) => scopeMatchesKnowledgePathogen(rule?.species_scope, pathogen))
    .sort((left, right) => {
      const leftRisk = String(left?.risk_level || "");
      const rightRisk = String(right?.risk_level || "");
      const riskOrder = { high: 0, medium: 1, low: 2 };
      const riskDelta = (riskOrder[leftRisk] ?? 9) - (riskOrder[rightRisk] ?? 9);
      if (riskDelta !== 0) return riskDelta;
      return String(left?.report_label || left?.gene_name || "").localeCompare(String(right?.report_label || right?.gene_name || ""), "zh-Hans-CN");
    });
}

function buildKnowledgeEventRuleMatches(pathogen) {
  const eventRules = getKnowledgeBaseCollection("event_rules");
  return eventRules
    .filter((rule) => scopeMatchesKnowledgePathogen(rule?.scope?.species, pathogen))
    .sort((left, right) => {
      const leftRisk = String(left?.interpretation?.risk_level || "");
      const rightRisk = String(right?.interpretation?.risk_level || "");
      const riskOrder = { high: 0, medium: 1, low: 2 };
      const riskDelta = (riskOrder[leftRisk] ?? 9) - (riskOrder[rightRisk] ?? 9);
      if (riskDelta !== 0) return riskDelta;
      return String(left?.title || left?.id || "").localeCompare(String(right?.title || right?.id || ""), "zh-Hans-CN");
    });
}

function buildDatabaseTopTypingSummary(rows, key, emptyValue, limit = 2) {
  const counts = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const raw = String(row?.[key] || "").trim();
    if (!raw || raw === "-") return;
    const normalizedParts = raw
      .split(/[;/]/)
      .map((item) => String(item || "").trim())
      .filter(Boolean);
    const parts = normalizedParts.length ? normalizedParts : [raw];
    parts.forEach((part) => {
      counts.set(part, (counts.get(part) || 0) + 1);
    });
  });
  const ranked = Array.from(counts.entries())
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0], "zh-Hans-CN"))
    .slice(0, limit);
  if (!ranked.length) {
    return {
      text: emptyValue,
      leader: "",
      details: "",
      count: 0,
    };
  }
  return {
    text: ranked.map(([label, count]) => `${label}（${count}）`).join("、"),
    leader: ranked[0][0],
    details: ranked.map(([label, count]) => `${label}（${count}）`).join("、"),
    count: ranked[0][1],
  };
}

function summarizeKnowledgeTyping(entry, fallbackValueKey) {
  if (!entry || typeof entry !== "object") return "";
  const title = String(entry[fallbackValueKey] || entry.lineage || entry.serotype || "").trim();
  const virulence = Array.isArray(entry.virulence_associations) ? entry.virulence_associations.filter(Boolean).slice(0, 2).join(" / ") : "";
  const resistance = Array.isArray(entry.resistance_associations) ? entry.resistance_associations.filter(Boolean).slice(0, 2).join(" / ") : "";
  const regional = Array.isArray(entry.regional_distribution) ? entry.regional_distribution.filter(Boolean).slice(0, 2).join(" / ") : "";
  return [title, virulence || resistance || regional ? `：${[virulence, resistance, regional].filter(Boolean).join("；")}` : ""].join("");
}

function joinSummaryParts(parts, fallback = "当前未形成可供归纳的补充证据。") {
  const values = parts.map((item) => String(item || "").trim()).filter(Boolean);
  return values.length ? values.join("") : fallback;
}

function buildDatabaseReportKnowledgeMatches(rows, speciesSeries, topicMeta = getDatabaseReportTopicMeta("general")) {
  const topLabels = Array.isArray(speciesSeries?.labels) ? speciesSeries.labels.slice(0, 3) : [];
  return topLabels.map((label) => {
    const pathogen = resolveKnowledgePathogenForSpecies(label);
    if (!pathogen) return null;
    const rowCount = rows.filter((item) => normalizeKnowledgeLookup(item.species_name || item.mlst_species_name || "") === normalizeKnowledgeLookup(label)).length;
    const scopedRows = rows.filter((item) => normalizeKnowledgeLookup(item.species_name || item.mlst_species_name || "") === normalizeKnowledgeLookup(label));
    const mlstSummary = buildDatabaseTopTypingSummary(scopedRows, "mlst_st", "当前样本范围内尚未形成明确的 ST 分型线索。");
    const serotypeSummary = buildDatabaseTopTypingSummary(scopedRows, "serotype_result", "当前样本范围内尚未形成明确的血清型/血清群线索。");
    const mlstAssociations = Array.isArray(pathogen.mlst_associations) ? pathogen.mlst_associations : [];
    const serotypeAssociations = Array.isArray(pathogen.serotype_associations) ? pathogen.serotype_associations : [];

    const matchedMlstEntries = mlstAssociations.filter((entry) => {
      const entryMlst = String(entry?.mlst || "").trim().toUpperCase();
      if (!entryMlst) return false;
      return mlstSummary.details.split("、").some((item) => String(item || "").toUpperCase().includes(entryMlst));
    }).slice(0, 2);
    const matchedSerotypeEntries = serotypeAssociations.filter((entry) => {
      const candidates = [
        String(entry?.serotype || "").trim(),
        ...(Array.isArray(entry?.serotype_aliases) ? entry.serotype_aliases.map((item) => String(item || "").trim()) : []),
      ].filter(Boolean);
      if (!candidates.length) return false;
      return serotypeSummary.details.split("、").some((hit) => {
        const normalizedHit = normalizeKnowledgeLookup(hit.replace(/（\d+）/g, ""));
        return candidates.some((candidate) => {
          const normalizedCandidate = normalizeKnowledgeLookup(candidate);
          return normalizedHit === normalizedCandidate || normalizedHit.includes(normalizedCandidate) || normalizedCandidate.includes(normalizedHit);
        });
      });
    }).slice(0, 2);

    if (!mlstSummary.leader && !serotypeSummary.leader) {
      return null;
    }

    const sampleSignalParts = [
      `${rowCount} 份样本进入当前统计范围`,
      mlstSummary.leader ? `主导 ST 为 ${mlstSummary.details}` : "",
      serotypeSummary.leader ? `主导血清型为 ${serotypeSummary.details}` : "",
    ].filter(Boolean);
    const evidenceSummary = joinSummaryParts([
      mlstSummary.leader ? `当前样本范围内命中的 ST 分型主要为 ${mlstSummary.details}。` : "",
      serotypeSummary.leader ? `当前样本范围内命中的血清型/血清群主要为 ${serotypeSummary.details}。` : "",
    ], "当前样本范围内尚未形成可归纳的分型证据。");
    const implicationSummary = joinSummaryParts([
      matchedMlstEntries.length
        ? `结合知识库，已命中的 ST 分型可重点参考 ${matchedMlstEntries.map((entry) => summarizeKnowledgeTyping(entry, "mlst")).filter(Boolean).join("；")}。`
        : "",
      matchedSerotypeEntries.length
        ? `结合知识库，已命中的血清型/血清群可重点参考 ${matchedSerotypeEntries.map((entry) => summarizeKnowledgeTyping(entry, "serotype")).filter(Boolean).join("；")}。`
        : "",
    ], "当前知识库中暂无与已命中分型直接对应的补充说明。");
    return {
      title: `${pathogen.common_name || label} / ${pathogen.species || label}`,
      summary: `${label} 在当前${topicMeta?.title || "监测专题"}范围内已形成可归纳的分型线索。`,
      sampleSignals: sampleSignalParts.join("；"),
      evidenceSummary,
      implicationSummary,
      count: rowCount,
    };
  }).filter(Boolean);
}

function formatDatabaseReportIssueLabel(period, latestDateText) {
  const latestDate = latestDateText && latestDateText !== "未记录" ? new Date(`${latestDateText}T00:00:00`) : null;
  if (!latestDate || Number.isNaN(latestDate.getTime())) {
    return period === "weekly"
      ? "监测周报"
      : period === "quarterly"
        ? "监测季报"
        : period === "yearly"
          ? "监测年度综述"
          : "监测月报";
  }
  const year = latestDate.getFullYear();
  const month = latestDate.getMonth() + 1;
  if (period === "weekly") {
    const start = new Date(latestDate);
    start.setDate(latestDate.getDate() - 6);
    const fmt = (d) => `${d.getMonth() + 1}.${d.getDate()}`;
    return `${year}年${fmt(start)}-${fmt(latestDate)}监测周报`;
  }
  if (period === "quarterly") {
    const quarter = Math.floor((month - 1) / 3) + 1;
    return `${year}年第${quarter}季度监测报告`;
  }
  if (period === "yearly") {
    return `${year}年监测年度综述`;
  }
  return `${year}年${month}月监测月报`;
}

function getDatabaseReportWindowLabel(period, latestDateText) {
  const latestDate = latestDateText && latestDateText !== "未记录" ? new Date(`${latestDateText}T00:00:00`) : new Date();
  if (Number.isNaN(latestDate.getTime())) {
    return period === "weekly"
      ? "本周"
      : period === "quarterly"
        ? "本季度"
        : period === "yearly"
          ? "本年度"
          : "本月";
  }
  if (period === "weekly") {
    const weekLabel = getIsoWeekLabel(latestDate);
    return `${weekLabel}（自然周）`;
  }
  if (period === "quarterly") {
    const quarter = Math.floor(latestDate.getMonth() / 3) + 1;
    return `${latestDate.getFullYear()}年第${quarter}季度`;
  }
  if (period === "yearly") {
    return `${latestDate.getFullYear()}年`;
  }
  return `${latestDate.getFullYear()}年${latestDate.getMonth() + 1}月`;
}

function getIsoWeekLabel(date) {
  const info = getIsoWeekInfo(date);
  return `${info.year}年第${info.week}周`;
}

function getIsoWeekInfo(date) {
  const target = new Date(date);
  target.setHours(0, 0, 0, 0);
  const day = target.getDay() || 7;
  target.setDate(target.getDate() + 4 - day);
  const yearStart = new Date(target.getFullYear(), 0, 1);
  const weekNumber = Math.ceil((((target - yearStart) / 86400000) + 1) / 7);
  return {
    year: target.getFullYear(),
    week: weekNumber,
  };
}

function getDatabaseReportIssueDescriptor(date, period) {
  const anchor = new Date(date);
  anchor.setHours(0, 0, 0, 0);
  const start = new Date(anchor);
  const end = new Date(anchor);
  if (period === "weekly") {
    const weekInfo = getIsoWeekInfo(anchor);
    const day = anchor.getDay() || 7;
    start.setDate(anchor.getDate() - (day - 1));
    end.setTime(start.getTime());
    end.setDate(start.getDate() + 6);
    end.setHours(23, 59, 59, 999);
    return {
      value: `${weekInfo.year}-W${String(weekInfo.week).padStart(2, "0")}`,
      label: `${weekInfo.year}年第${weekInfo.week}周`,
      start,
      end,
    };
  }
  if (period === "quarterly") {
    const quarter = Math.floor(anchor.getMonth() / 3) + 1;
    const quarterStartMonth = (quarter - 1) * 3;
    start.setMonth(quarterStartMonth, 1);
    end.setFullYear(start.getFullYear(), quarterStartMonth + 3, 0);
    end.setHours(23, 59, 59, 999);
    return {
      value: `${anchor.getFullYear()}-Q${quarter}`,
      label: `${anchor.getFullYear()}年第${quarter}季度`,
      start,
      end,
    };
  }
  if (period === "yearly") {
    start.setMonth(0, 1);
    end.setFullYear(start.getFullYear(), 11, 31);
    end.setHours(23, 59, 59, 999);
    return {
      value: String(anchor.getFullYear()),
      label: `${anchor.getFullYear()}年`,
      start,
      end,
    };
  }
  start.setDate(1);
  end.setFullYear(start.getFullYear(), start.getMonth() + 1, 0);
  end.setHours(23, 59, 59, 999);
  return {
    value: `${anchor.getFullYear()}-${String(anchor.getMonth() + 1).padStart(2, "0")}`,
    label: `${anchor.getFullYear()}年${anchor.getMonth() + 1}月`,
    start,
    end,
  };
}

function getDatabaseReportIssueOptions(rows, period) {
  const options = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const date = getDatabaseRecordDate(row);
    if (!date) return;
    const descriptor = getDatabaseReportIssueDescriptor(date, period);
    if (!descriptor || !descriptor.value) return;
    const existing = options.get(descriptor.value);
    if (!existing || descriptor.end > existing.end) {
      options.set(descriptor.value, descriptor);
    }
  });
  return Array.from(options.values()).sort((left, right) => right.end - left.end);
}

function getDatabaseReportSelectedIssue(rows, period) {
  const options = getDatabaseReportIssueOptions(rows, period);
  if (!options.length) return null;
  const matched = options.find((item) => item.value === state.databaseReportRange);
  return matched || options[0];
}

