function syncDatabaseReportControls(rows) {
  state.databaseReportPreset = inferDatabaseReportPreset(state.databaseReportTopic);
  if (elements.databaseReportPreset) {
    const presetMarkup = buildDatabaseReportPresetOptionsMarkup();
    if (elements.databaseReportPreset.innerHTML !== presetMarkup) {
      elements.databaseReportPreset.innerHTML = presetMarkup;
    }
  }
  if (elements.databaseReportPreset && elements.databaseReportPreset.value !== state.databaseReportPreset) {
    elements.databaseReportPreset.value = state.databaseReportPreset;
  }
  if (elements.databaseReportPeriod && elements.databaseReportPeriod.value !== state.databaseReportPeriod) {
    elements.databaseReportPeriod.value = state.databaseReportPeriod;
  }
  if (elements.databaseReportTopic && elements.databaseReportTopic.value !== state.databaseReportTopic) {
    elements.databaseReportTopic.value = state.databaseReportTopic;
  }
  const issues = getDatabaseReportIssueOptions(rows, state.databaseReportPeriod || "monthly");
  if (elements.databaseReportRange) {
    elements.databaseReportRange.innerHTML = issues.length
      ? issues.map((item) => `<option value="${escapeHtml(item.value)}">${escapeHtml(item.label)}</option>`).join("")
      : '<option value="">暂无可用期次</option>';
    const matched = issues.some((item) => item.value === state.databaseReportRange);
    state.databaseReportRange = matched ? state.databaseReportRange : (issues[0]?.value || "");
    elements.databaseReportRange.value = state.databaseReportRange;
  }
  const locations = buildDatabaseReportLocationOptions(rows);
  if (elements.databaseReportLocation) {
    elements.databaseReportLocation.innerHTML = [
      '<option value="">全部地域</option>',
      ...locations.map((item) => `<option value="${escapeHtml(item.value)}">${escapeHtml(item.label)}</option>`),
    ].join("");
    const stillExists = locations.some((item) => item.value === state.databaseReportLocation);
    if (!state.databaseReportLocation || stillExists) {
      elements.databaseReportLocation.value = state.databaseReportLocation;
    } else {
      state.databaseReportLocation = "";
      elements.databaseReportLocation.value = "";
    }
  }
  renderDatabaseReportModeSummary(rows);
}

function buildDatabaseReportLocationOptions(rows) {
  const options = new Map();
  rows.forEach((item) => {
    const country = normalizeCountryForMap(item.country || "");
    const location = parseLocationJson(item.location_json);
    const province = canonicalizeChinaProvinceName(location.province || "");
    if (isChinaCountry(country) && province) {
      options.set(`province:${province}`, { value: `province:${province}`, label: `中国 · ${province}` });
      return;
    }
    if (country) {
      options.set(`country:${country}`, { value: `country:${country}`, label: country === "China" ? "中国" : country });
    }
  });
  return Array.from(options.values()).sort((left, right) => left.label.localeCompare(right.label, "zh-Hans-CN"));
}

function buildDatabaseEvolutionSpeciesOptions(rows) {
  const counts = new Map();
  (Array.isArray(rows) ? rows : []).forEach((item) => {
    const species = String(item?.species_name || item?.mlst_species_name || "").trim();
    if (!species) return;
    counts.set(species, (counts.get(species) || 0) + 1);
  });
  return Array.from(counts.entries())
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0], "zh-Hans-CN"))
    .map(([value, count]) => ({ value, label: `${value}（${count}）` }));
}

function syncDatabaseReportEvolutionControls(rows) {
  const speciesOptions = buildDatabaseEvolutionSpeciesOptions(rows);
  const hasSelectedSpecies = speciesOptions.some((item) => item.value === state.databaseReportEvolutionSpecies);
  state.databaseReportEvolutionSpecies = hasSelectedSpecies ? state.databaseReportEvolutionSpecies : "";
  const typingRows = state.databaseReportEvolutionSpecies
    ? (Array.isArray(rows) ? rows.filter((item) => String(item?.species_name || item?.mlst_species_name || "").trim() === state.databaseReportEvolutionSpecies) : [])
    : [];
  const hasMlst = typingRows.some((item) => String(item?.mlst_st || "").trim());
  const hasSerotype = typingRows.some((item) => String(item?.serotype_result || "").trim());
  if (!state.databaseReportEvolutionSpecies) {
    state.databaseReportEvolutionDimension = "species";
  } else if (state.databaseReportEvolutionDimension === "mlst" && !hasMlst) {
    state.databaseReportEvolutionDimension = hasSerotype ? "serotype" : "species";
  } else if (state.databaseReportEvolutionDimension === "serotype" && !hasSerotype) {
    state.databaseReportEvolutionDimension = hasMlst ? "mlst" : "species";
  }
  return {
    speciesOptions,
    selectedSpecies: state.databaseReportEvolutionSpecies,
    selectedDimension: state.databaseReportEvolutionDimension,
    hasMlst,
    hasSerotype,
  };
}

function getDatabaseReportScopedRows(rows, selectedIssue = null) {
  const withDates = rows
    .map((row) => ({ row, date: getDatabaseRecordDate(row) }))
    .filter((item) => item.date);
  let filteredRows = rows;
  if (withDates.length) {
    const issue = selectedIssue || getDatabaseReportSelectedIssue(rows, state.databaseReportPeriod || "monthly");
    if (issue) {
      filteredRows = withDates.filter((item) => item.date >= issue.start && item.date <= issue.end).map((item) => item.row);
    }
  }
  if (!state.databaseReportLocation) return filteredRows;
  if (state.databaseReportLocation.startsWith("province:")) {
    const provinceName = state.databaseReportLocation.slice("province:".length);
    return filteredRows.filter((item) => canonicalizeChinaProvinceName(parseLocationJson(item.location_json).province || "") === provinceName);
  }
  if (state.databaseReportLocation.startsWith("country:")) {
    const countryName = state.databaseReportLocation.slice("country:".length);
    return filteredRows.filter((item) => normalizeCountryForMap(item.country || "") === countryName);
  }
  return filteredRows;
}

function renderDatabaseSurveillanceBrief(
  rows,
  speciesSeries,
  timelineSeries,
  syndromeSeries,
  surveillanceSourceSeries,
  clusterStatusSeries,
  collectionSiteSeries
) {
  if (!elements.databaseSurveillanceBrief) return;
  if (!rows.length) {
    elements.databaseSurveillanceBrief.innerHTML = `
      <section class="surveillance-brief-main">
        <p class="surveillance-brief-kicker">监测摘要</p>
        <h4>当前筛选范围内暂无样本，无法形成监测结论。</h4>
        <p>请返回样本列表放宽筛选条件，或先导入样本后再查看监测统计。</p>
      </section>
    `;
    return;
  }

  const topSpecies = speciesSeries.labels[0]
    ? { name: speciesSeries.labels[0], count: speciesSeries.values[0] || 0 }
    : { name: "未形成主导病原", count: 0 };
  const areaScope = rows.some((item) => isChinaCountry(item.country || "") && String(parseLocationJson(item.location_json).province || "").trim())
    ? "china"
    : "world";
  const mapCounts = buildDatabaseMapCounts(rows, areaScope);
  const topAreaEntry = Array.from(mapCounts.entries()).sort((left, right) => right[1] - left[1])[0] || ["未形成热点区域", 0];
  const latestDate = getDatabaseMonitoringLatestDate(rows) || "未记录";
  const trendState = describeDatabaseTimelineTrend(timelineSeries.values);
  const sampleTypeSummary = buildDatabaseBriefDistribution(rows, (item) => item.sample_type);
  const mlstSummary = buildDatabaseTopTypingSummary(rows, "mlst_st", "未形成主导 ST 分型");
  const serotypeSummary = buildDatabaseTopTypingSummary(rows, "serotype_result", "未形成主导血清型");
  const mgeRiskSummary = buildDatabaseMgeRiskSummary(rows);
  const syndromeSummary = buildDatabaseSeriesSummary(syndromeSeries, "未形成症候群结构", "疑似症候群字段仍需补全");
  const surveillanceSourceSummary = buildDatabaseSeriesSummary(surveillanceSourceSeries, "未形成监测来源结构", "监测来源字段仍需补全");
  const clusterStatusSummary = buildDatabaseSeriesSummary(clusterStatusSeries, "未形成聚集状态结构", "聚集性状态字段仍需补全");
  const collectionSiteSummary = buildDatabaseSeriesSummary(collectionSiteSeries, "未形成采样地点结构", "采样地点字段仍需补全");
  const pathogenScopeLabel = DATABASE_PATHOGEN_TYPE_LABELS[state.databaseFilterPathogenType] || "全部病原";

  const headline = topSpecies.count
    ? `当前主导病原为 ${topSpecies.name}，监测背景以 ${syndromeSummary.value} 和 ${surveillanceSourceSummary.value} 为主。`
    : `当前样本已入库 ${rows.length} 条，但尚未形成稳定的病原分布结论。`;
  const support = [
    `${pathogenScopeLabel}视角`,
    `${formatNumber(rows.length)} 份样本进入当前监测视图`,
    `${timelineSeries.title || "时间趋势"}表现为${trendState.label}`,
    mlstSummary.leader ? `主导 ST 为 ${mlstSummary.leader}` : "",
    serotypeSummary.leader ? `主导血清型为 ${serotypeSummary.leader}` : "",
    mgeRiskSummary.flaggedSamples ? mgeRiskSummary.short : "",
    `热点区域为 ${topAreaEntry[0]}`,
    `最近活跃日期为 ${latestDate}`,
  ].join(" · ");
  const keyNotes = [
    {
      label: "监测范围",
      value: `${formatNumber(rows.length)} 份样本，${formatNumber(new Set(rows.map((item) => String(item.species_name || item.mlst_species_name || "").trim()).filter(Boolean)).size)} 类病原`,
    },
    {
      label: "时间态势",
      value: `${trendState.title}，${trendState.note}`,
    },
    {
      label: "区域重点",
      value: collectionSiteSeries.labels.length
        ? `${topAreaEntry[0]}；采样地点以 ${collectionSiteSummary.value} 最常见`
        : `${topAreaEntry[0]} 为当前最集中区域`,
    },
  ];

  const cards = [
    {
      label: "主导病原",
      value: topSpecies.name,
      note: topSpecies.count ? `${topSpecies.count} 条检出` : "未形成明确主导病原",
      tone: "primary",
    },
    {
      label: "时间信号",
      value: trendState.title,
      note: latestDate !== "未记录" ? `最近活跃日 ${latestDate}` : trendState.note,
      tone: trendState.tone,
    },
    {
      label: "监测场景",
      value: syndromeSummary.value,
      note: `${surveillanceSourceSummary.value} · ${clusterStatusSummary.value}`,
      tone: "calm",
    },
    {
      label: "分型线索",
      value: mlstSummary.leader || serotypeSummary.leader || "待补录",
      note: [mlstSummary.leader ? `ST：${mlstSummary.details}` : "", serotypeSummary.leader ? `血清型：${serotypeSummary.details}` : ""].filter(Boolean).join(" · ") || "当前样本未形成稳定分型线索",
      tone: "neutral",
    },
    {
      label: "MGE 风险",
      value: mgeRiskSummary.flaggedSamples ? `${mgeRiskSummary.flaggedSamples} 份样本` : "未见明确线索",
      note: [mgeRiskSummary.resistanceTop ? `耐药：${mgeRiskSummary.resistanceTop}` : "", mgeRiskSummary.virulenceTop ? `毒力：${mgeRiskSummary.virulenceTop}` : ""].filter(Boolean).join(" · ") || "当前样本未记录 MGE 相关基因命中",
      tone: mgeRiskSummary.flaggedSamples ? "alert" : "neutral",
    },
    {
      label: "热点区域",
      value: topAreaEntry[0],
      note: collectionSiteSeries.labels.length
        ? `采样点 ${collectionSiteSummary.value}`
        : topAreaEntry[1] ? `${topAreaEntry[1]} 条样本` : "当前未形成区域热点",
      tone: "neutral",
    },
  ];

  elements.databaseSurveillanceBrief.innerHTML = `
    <section class="surveillance-brief-main">
      <p class="surveillance-brief-kicker">监测摘要</p>
      <h4>${escapeHtml(headline)}</h4>
      <p>${escapeHtml(support)}</p>
      <div class="surveillance-brief-main-notes">
        ${keyNotes.map((item) => `
          <article class="surveillance-brief-main-note">
            <span class="surveillance-brief-main-note-label">${escapeHtml(item.label)}</span>
            <strong class="surveillance-brief-main-note-value">${escapeHtml(item.value)}</strong>
          </article>
        `).join("")}
      </div>
      <div class="surveillance-brief-actions">
        <button class="ghost-button" type="button" data-monitor-open-samples>查看当前统计样本</button>
        <button class="primary-button" type="button" data-monitor-open-report>生成当前统计报告</button>
      </div>
    </section>
    <div class="surveillance-brief-cards">
      ${cards.map((card) => `
        <article class="surveillance-brief-card surveillance-brief-card-${card.tone}">
          <span class="surveillance-brief-label">${escapeHtml(card.label)}</span>
          <strong class="surveillance-brief-value">${escapeHtml(card.value)}</strong>
          <p class="surveillance-brief-note">${escapeHtml(card.note)}</p>
        </article>
      `).join("")}
    </div>
  `;
}

function buildDatabaseBriefDistribution(rows, getter) {
  const counts = new Map();
  rows.forEach((row) => {
    const value = String(getter(row) || "").trim();
    if (!value) return;
    counts.set(value, (counts.get(value) || 0) + 1);
  });
  if (!counts.size) {
    return { value: "未形成结构", note: "当前样本未填写足够的结构化字段" };
  }
  const ordered = Array.from(counts.entries()).sort((left, right) => right[1] - left[1]);
  const total = ordered.reduce((sum, item) => sum + item[1], 0);
  const primary = ordered[0];
  return {
    value: primary[0],
    note: `${Math.round((primary[1] / Math.max(1, total)) * 100)}% 样本属于该类型`,
  };
}

function applyMonitoringStateToDatabaseList(extraFilters = {}) {
  state.databaseTable.filters.species_name = String(extraFilters.species_name ?? state.databaseTimelineSpecies ?? "");
  state.databaseTable.filters.pathogen_type = String(extraFilters.pathogen_type ?? state.databaseFilterPathogenType ?? "");
  state.databaseTable.filters["meta:suspected_syndrome"] = String(extraFilters["meta:suspected_syndrome"] ?? state.databaseFilterSyndrome ?? "");
  state.databaseTable.filters["meta:surveillance_source"] = String(extraFilters["meta:surveillance_source"] ?? state.databaseFilterSource ?? "");
  state.databaseTable.filters["meta:cluster_status"] = String(extraFilters["meta:cluster_status"] ?? state.databaseFilterCluster ?? "");
  state.databaseTable.filters["meta:collection_site"] = String(extraFilters["meta:collection_site"] ?? state.databaseFilterSite ?? "");

  if (extraFilters.country !== undefined) {
    state.databaseTable.filters.country = String(extraFilters.country || "");
  } else if (state.databaseMapScope === "china") {
    state.databaseTable.filters.country = "China";
  } else if (state.databaseMapFocusLevel === "country" && state.databaseMapFocusName) {
    state.databaseTable.filters.country = String(state.databaseMapFocusName || "");
  } else {
    state.databaseTable.filters.country = "";
  }

  if (state.databaseMapScope === "china" && state.databaseMapFocusName) {
    const siteFilter = String(state.databaseTable.filters["meta:collection_site"] || "");
    if (!siteFilter) {
      state.databaseTable.filters["meta:collection_site"] = String(state.databaseMapFocusName || "");
    }
  }
}

function syncReportScopeFromMonitoring() {
  state.databaseReportRange = String(state.databaseTimelineRange || state.databaseReportRange || "30");
  if (state.databaseMapScope === "china" && state.databaseMapFocusLevel === "province" && state.databaseMapFocusName) {
    state.databaseReportLocation = `province:${state.databaseMapFocusName}`;
    return;
  }
  if (state.databaseMapScope === "world" && state.databaseMapFocusLevel === "country" && state.databaseMapFocusName) {
    state.databaseReportLocation = `country:${state.databaseMapFocusName}`;
    return;
  }
  state.databaseReportLocation = "";
}

function openDatabaseSamplesFromMonitoring(extraFilters = {}) {
  applyMonitoringStateToDatabaseList(extraFilters);
  setActiveDatabaseSection("database-samples-panel");
  renderDatabaseRecords();
}

function openDatabaseReportFromMonitoring() {
  syncReportScopeFromMonitoring();
  setActiveDatabaseSection("database-report-panel");
  renderDatabaseReport();
}

function syncDatabaseMonitoringMetadataFilters(rows) {
  if (elements.databaseFilterPathogenType) {
    const counts = { virus: 0, bacteria: 0 };
    rows.forEach((item) => {
      counts[inferDatabaseRecordPathogenType(item)] += 1;
    });
    elements.databaseFilterPathogenType.innerHTML = [
      '<option value="">全部病原类型</option>',
      ...Object.entries(DATABASE_PATHOGEN_TYPE_LABELS)
        .filter(([key]) => counts[key] > 0)
        .map(([key, label]) => `<option value="${escapeHtml(key)}">${escapeHtml(label)} (${counts[key]})</option>`),
    ].join("");
    if (state.databaseFilterPathogenType && counts[state.databaseFilterPathogenType] > 0) {
      elements.databaseFilterPathogenType.value = state.databaseFilterPathogenType;
    } else {
      state.databaseFilterPathogenType = "";
      elements.databaseFilterPathogenType.value = "";
    }
  }
  syncDatabaseMonitoringMetadataSelect(
    elements.databaseFilterSyndrome,
    rows,
    (item) => getDatabaseMetadataDisplayValue(item, "suspected_syndrome"),
    state.databaseFilterSyndrome,
    "全部疑似症候群",
    (value) => { state.databaseFilterSyndrome = value; }
  );
  syncDatabaseMonitoringMetadataSelect(
    elements.databaseFilterSource,
    rows,
    (item) => getDatabaseMetadataDisplayValue(item, "surveillance_source"),
    state.databaseFilterSource,
    "全部监测来源",
    (value) => { state.databaseFilterSource = value; }
  );
  syncDatabaseMonitoringMetadataSelect(
    elements.databaseFilterSite,
    rows,
    (item) => getDatabaseCollectionSiteDisplay(item),
    state.databaseFilterSite,
    "全部采样地点",
    (value) => { state.databaseFilterSite = value; }
  );
  syncDatabaseMonitoringMetadataSelect(
    elements.databaseFilterCluster,
    rows,
    (item) => getDatabaseMetadataDisplayValue(item, "cluster_status"),
    state.databaseFilterCluster,
    "全部聚集性状态",
    (value) => { state.databaseFilterCluster = value; }
  );
}

function syncDatabaseMonitoringMetadataSelect(selectNode, rows, getter, currentValue, emptyLabel, onReset) {
  if (!selectNode) return;
  const ordered = buildDatabaseCountSeries(rows, getter, 100);
  selectNode.innerHTML = [
    `<option value="">${escapeHtml(emptyLabel)}</option>`,
    ...ordered.labels.map((label, index) => `<option value="${escapeHtml(label)}">${escapeHtml(label)} (${ordered.values[index]})</option>`),
  ].join("");
  if (currentValue && ordered.labels.includes(currentValue)) {
    selectNode.value = currentValue;
  } else {
    onReset("");
    selectNode.value = "";
  }
}

function applyDatabaseMonitoringMetadataFilters(rows) {
  return rows.filter((item) => {
    if (state.databaseFilterPathogenType) {
      if (inferDatabaseRecordPathogenType(item) !== state.databaseFilterPathogenType) return false;
    }
    if (state.databaseFilterSyndrome) {
      const value = getDatabaseMetadataDisplayValue(item, "suspected_syndrome");
      if (value !== state.databaseFilterSyndrome) return false;
    }
    if (state.databaseFilterSource) {
      const value = getDatabaseMetadataDisplayValue(item, "surveillance_source");
      if (value !== state.databaseFilterSource) return false;
    }
    if (state.databaseFilterSite) {
      const value = getDatabaseCollectionSiteDisplay(item);
      if (value !== state.databaseFilterSite) return false;
    }
    if (state.databaseFilterCluster) {
      const value = getDatabaseMetadataDisplayValue(item, "cluster_status");
      if (value !== state.databaseFilterCluster) return false;
    }
    return true;
  });
}

function buildDatabaseSeriesSummary(series, emptyValue, emptyNote) {
  if (!series?.labels?.length) {
    return { value: emptyValue, note: emptyNote };
  }
  const total = Array.isArray(series.values) ? series.values.reduce((sum, value) => sum + Number(value || 0), 0) : 0;
  const primaryLabel = series.labels[0] || emptyValue;
  const primaryValue = Number(series.values?.[0] || 0);
  return {
    value: primaryLabel,
    note: total > 0 ? `${Math.round((primaryValue / total) * 100)}% 样本属于该类` : emptyNote,
  };
}

function getDatabaseCollectionSiteDisplay(row) {
  const metadataValue = getDatabaseMetadataDisplayValue(row, "collection_site");
  if (metadataValue) return metadataValue;
  const location = parseLocationJson(row?.location_json);
  const parts = [location.province, location.city, location.district, location.detail]
    .map((part) => String(part || "").trim())
    .filter(Boolean);
  return parts.join(" / ");
}

function describeDatabaseTimelineTrend(values) {
  if (!values.length) {
    return { title: "暂无趋势", label: "暂无趋势", note: "当前时间窗口内暂无可比较的日期点", tone: "neutral" };
  }
  if (values.length === 1) {
    return { title: "单点观察", label: "单点观察", note: "当前时间窗口仅有单个采样日期", tone: "neutral" };
  }
  const splitIndex = Math.max(1, Math.floor(values.length / 2));
  const first = values.slice(0, splitIndex);
  const second = values.slice(splitIndex);
  const firstAvg = first.reduce((sum, value) => sum + value, 0) / Math.max(1, first.length);
  const secondAvg = second.reduce((sum, value) => sum + value, 0) / Math.max(1, second.length);
  const delta = secondAvg - firstAvg;
  const base = Math.max(1, firstAvg);
  const ratio = delta / base;
  if (ratio >= 0.25) {
    return { title: "近期抬升", label: "近期抬升", note: "后半段检出水平较前半段明显升高，建议重点关注。", tone: "alert" };
  }
  if (ratio <= -0.25) {
    return { title: "近期回落", label: "近期回落", note: "后半段检出水平较前半段明显下降。", tone: "neutral" };
  }
  return { title: "整体平稳", label: "整体平稳", note: "时间窗口内未见明显波动。", tone: "calm" };
}

function parseLocationJson(rawValue) {
  if (!rawValue) return {};
  if (typeof rawValue === "object") return rawValue;
  try {
    const parsed = JSON.parse(String(rawValue));
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (_error) {
    return {};
  }
}

function normalizeCountryForMap(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (text === "中国" || text === "中华人民共和国") return "China";
  if (text === "美国") return "United States";
  if (text === "英国") return "United Kingdom";
  if (text === "韩国") return "South Korea";
  if (text === "俄罗斯" || text === "俄罗斯联邦") return "Russia";
  return text;
}

function canonicalizeChinaProvinceName(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const compact = raw.replace(/\s+/g, "");
  const provinces = Object.keys(CHINA_REGION_TREE);
  if (provinces.includes(compact)) return compact;
  const matched = provinces.find((name) => {
    const normalized = name.replace(/\s+/g, "");
    if (normalized === compact) return true;
    return normalized.replace(/(省|市|自治区|壮族自治区|回族自治区|维吾尔自治区|特别行政区)$/u, "") === compact;
  });
  return matched || raw;
}

function canonicalizeChinaCityName(province, value) {
  const canonicalProvince = canonicalizeChinaProvinceName(province);
  const raw = String(value || "").trim();
  if (!canonicalProvince || !raw || !CHINA_REGION_TREE[canonicalProvince]) return raw;
  const compact = raw.replace(/\s+/g, "");
  const cities = Object.keys(CHINA_REGION_TREE[canonicalProvince]);
  if (cities.includes(compact)) return compact;
  const matched = cities.find((name) => {
    const normalized = name.replace(/\s+/g, "");
    if (normalized === compact) return true;
    return normalized.replace(/(市|地区|盟|自治州|自治县)$/u, "") === compact;
  });
  return matched || raw;
}

function canonicalizeChinaDistrictName(province, city, value) {
  const canonicalProvince = canonicalizeChinaProvinceName(province);
  const canonicalCity = canonicalizeChinaCityName(canonicalProvince, city);
  const raw = String(value || "").trim();
  if (!canonicalProvince || !canonicalCity || !raw || !CHINA_REGION_TREE[canonicalProvince]?.[canonicalCity]) return raw;
  const compact = raw.replace(/\s+/g, "");
  const districts = CHINA_REGION_TREE[canonicalProvince][canonicalCity];
  if (districts.includes(compact)) return compact;
  const matched = districts.find((name) => {
    const normalized = name.replace(/\s+/g, "");
    if (normalized === compact) return true;
    return normalized.replace(/(区|县|市)$/u, "") === compact;
  });
  return matched || raw;
}

function buildDatabaseMapCounts(rows, scope) {
  const counts = new Map();
  rows.forEach((item) => {
    if (scope === "china") {
      const location = parseLocationJson(item.location_json);
      const province = canonicalizeChinaProvinceName(location.province).replace(/\s+/g, "");
      const city = canonicalizeChinaCityName(province, location.city).replace(/\s+/g, "");
      const district = canonicalizeChinaDistrictName(province, city, location.district).replace(/\s+/g, "");
      if (state.databaseMapDrilldownCode) {
        if (state.databaseMapDrilldownLevel === "city") {
          if (!province || !city || province !== state.databaseMapParentName || city !== state.databaseMapDrilldownName || !district) return;
          counts.set(district, (counts.get(district) || 0) + 1);
        } else {
          if (!province || province !== state.databaseMapDrilldownName || !city) return;
          counts.set(city, (counts.get(city) || 0) + 1);
        }
      } else {
        if (!province) return;
        counts.set(province, (counts.get(province) || 0) + 1);
      }
      return;
    }
    const country = normalizeCountryForMap(item.country || "");
    if (!country) return;
    counts.set(country, (counts.get(country) || 0) + 1);
  });
  return counts;
}

function getDatabaseMonitoringScopedRows(rows) {
  if (!state.databaseMapFocusName) return rows;
  if (state.databaseMapScope === "china") {
    return rows.filter((item) => {
      const location = parseLocationJson(item.location_json);
      const province = canonicalizeChinaProvinceName(location.province).replace(/\s+/g, "");
      const city = canonicalizeChinaCityName(province, location.city).replace(/\s+/g, "");
      const district = canonicalizeChinaDistrictName(province, city, location.district).replace(/\s+/g, "");
      if (state.databaseMapFocusLevel === "province") return province === state.databaseMapFocusName;
      if (state.databaseMapFocusLevel === "city") return province === state.databaseMapParentName && city === state.databaseMapFocusName;
      if (state.databaseMapFocusLevel === "district") {
        return province === state.databaseMapParentName && city === state.databaseMapDrilldownName && district === state.databaseMapFocusName;
      }
      return true;
    });
  }
  return rows.filter((item) => normalizeCountryForMap(item.country || "") === state.databaseMapFocusName);
}

function buildDatabaseMapLegend(max) {
  if (!max) {
    return '<div class="field-note">当前筛选样本尚未形成可绘制的地域分布。</div>';
  }
  const bins = [
    { sample: max * 0.15, label: "较少" },
    { sample: max * 0.35, label: "中等" },
    { sample: max * 0.6, label: "较多" },
    { sample: max, label: "最高" },
  ];
  return bins.map((bin) => `
    <div class="viz-legend-item">
      <span class="viz-dot" style="background:${databaseMapHeatColor(bin.sample, max)}"></span>
      ${escapeHtml(bin.label)}
    </div>
  `).join("");
}

function databaseMapHeatColor(value, max) {
  if (!value || !max) return "rgba(176, 194, 214, 0.18)";
  const ratio = Math.min(1, value / max);
  if (ratio > 0.8) return "#2d5b8c";
  if (ratio > 0.55) return "#4f7dae";
  if (ratio > 0.3) return "#7ea6cf";
  return "#b8cde2";
}

function getDatabaseFeatureAreaName(feature, scope) {
  const properties = feature?.properties || {};
  if (scope === "china") {
    return String(properties.name || "").trim().replace(/\s+/g, "");
  }
  return String(properties.name || properties.ADMIN || properties.admin || "").trim();
}

function destroyDatabaseMonitoringMap() {
  if (!databaseMonitoringLeafletMap) return;
  databaseMonitoringLeafletMap.remove();
  databaseMonitoringLeafletMap = null;
}

async function getDatabaseChinaGeoJson() {
  return getDatabaseChinaGeoJsonByCode(state.databaseMapDrilldownCode);
}

async function getDatabaseChinaGeoJsonByCode(code) {
  if (!code) return CHINA_GEOJSON;
  if (DATABASE_CHINA_DRILLDOWN_CACHE.has(code)) {
    return DATABASE_CHINA_DRILLDOWN_CACHE.get(code);
  }
  try {
    const localPaths = [
      `/static/data/china_drilldown/${encodeURIComponent(code)}.geojson`,
      `/static/data/china_drilldown/cities/${encodeURIComponent(code)}.geojson`,
    ];
    for (const path of localPaths) {
      try {
        const geojson = await requestJson(path);
        DATABASE_CHINA_DRILLDOWN_CACHE.set(code, geojson);
        return geojson;
      } catch (_error) {
        continue;
      }
    }
    const remoteGeojson = await requestJson(`https://geo.datav.aliyun.com/areas_v3/bound/${encodeURIComponent(code)}_full.json`);
    DATABASE_CHINA_DRILLDOWN_CACHE.set(code, remoteGeojson);
    return remoteGeojson;
  } catch (error) {
    console.error("Failed to load China drilldown boundary", code, error);
    return null;
  }
}

async function renderDatabaseMonitoringMap(rows) {
  if (!elements.databaseSurveillanceCountry) return;
  elements.databaseMapChinaButton?.classList.toggle("active", state.databaseMapScope === "china");
  elements.databaseMapWorldButton?.classList.toggle("active", state.databaseMapScope === "world");
  elements.databaseMapBackButton?.classList.toggle("hidden", !(state.databaseMapScope === "china" && state.databaseMapDrilldownCode));
  const scope = state.databaseMapScope;
  const geojson = scope === "china" ? await getDatabaseChinaGeoJson() : WORLD_GEOJSON;
  const counts = buildDatabaseMapCounts(rows, scope);
  const max = Math.max(...counts.values(), 0);
  if (!geojson) {
    destroyDatabaseMonitoringMap();
    elements.databaseSurveillanceCountry.innerHTML = '<div class="viz-map-empty">地图边界数据未加载。</div>';
    return;
  }
  elements.databaseSurveillanceCountry.innerHTML = `
    <div class="viz-shell">
      <h4>${scope === "china" ? (
        state.databaseMapDrilldownLevel === "city"
          ? `${escapeHtml(state.databaseMapDrilldownName)}区县分布`
          : state.databaseMapDrilldownCode
            ? `${escapeHtml(state.databaseMapDrilldownName)}城市分布`
            : "中国省级分布"
      ) : "全球国家分布"}</h4>
      <div class="viz-map-layout">
        <div id="database-monitoring-map" class="viz-geo-map"></div>
      </div>
      <div class="viz-legend viz-legend-inline">${buildDatabaseMapLegend(max)}</div>
      ${state.databaseMapNotice ? `<div class="field-note viz-map-note">${escapeHtml(state.databaseMapNotice)}</div>` : ""}
    </div>
  `;
  const container = document.getElementById("database-monitoring-map");
  if (!container || !window.L) return;
  destroyDatabaseMonitoringMap();
  databaseMonitoringLeafletMap = window.L.map(container, {
    zoomControl: true,
    attributionControl: false,
    dragging: true,
    scrollWheelZoom: true,
    doubleClickZoom: true,
    boxZoom: false,
    keyboard: false,
    tap: false,
    zoomSnap: 0.25,
  });
  const layer = window.L.geoJSON(geojson, {
    style: (feature) => {
      const areaName = getDatabaseFeatureAreaName(feature, scope);
      const value = counts.get(areaName) || 0;
      return {
        color: value ? "#4d6570" : "#b7c2c8",
        weight: value ? 1.1 : 0.7,
        fillColor: databaseMapHeatColor(value, max),
        fillOpacity: value ? 0.92 : 0.12,
      };
    },
    onEachFeature: (feature, featureLayer) => {
      const areaName = getDatabaseFeatureAreaName(feature, scope);
      const value = counts.get(areaName) || 0;
      featureLayer.bindTooltip(`${areaName || "Unknown"}：${value} 个样本`, {
        sticky: true,
        className: "database-map-tooltip",
      });
      featureLayer.on("mouseover", () => {
        featureLayer.setStyle({ weight: 1.4, color: "#284b63" });
      });
      featureLayer.on("mouseout", () => {
        featureLayer.setStyle({
          color: value ? "#4d6570" : "#b7c2c8",
          weight: value ? 1.1 : 0.7,
        });
      });
      if (scope === "china" && feature?.properties?.adcode) {
        featureLayer.on("click", async () => {
          if (!state.databaseMapDrilldownCode) {
            state.databaseMapFocusName = areaName;
            state.databaseMapFocusLevel = "province";
            state.databaseMapDrilldownCode = String(feature.properties.adcode || "");
            state.databaseMapDrilldownName = areaName;
            state.databaseMapDrilldownLevel = "province";
            state.databaseMapParentCode = "";
            state.databaseMapParentName = "";
            await renderDatabaseMonitoring();
            return;
          }
          if (state.databaseMapDrilldownLevel === "province") {
            const nextCode = String(feature.properties.adcode || "");
            if (!nextCode) return;
            const nextGeojson = await getDatabaseChinaGeoJsonByCode(nextCode);
            if (!nextGeojson) {
              state.databaseMapNotice = `${areaName} 暂无区县边界数据，当前只能浏览到市级。`;
              await renderDatabaseMonitoring();
              return;
            }
            state.databaseMapFocusName = areaName;
            state.databaseMapFocusLevel = "city";
            state.databaseMapParentCode = state.databaseMapDrilldownCode;
            state.databaseMapParentName = state.databaseMapDrilldownName;
            state.databaseMapDrilldownCode = nextCode;
            state.databaseMapDrilldownName = areaName;
            state.databaseMapDrilldownLevel = "city";
            state.databaseMapNotice = "";
            await renderDatabaseMonitoring();
            return;
          }
          if (state.databaseMapDrilldownLevel === "city") {
            state.databaseMapFocusName = areaName;
            state.databaseMapFocusLevel = "district";
            await renderDatabaseMonitoring();
          }
        });
      } else if (scope === "world") {
        featureLayer.on("click", async () => {
          state.databaseMapFocusName = areaName;
          state.databaseMapFocusLevel = "country";
          await renderDatabaseMonitoring();
        });
      }
    },
  }).addTo(databaseMonitoringLeafletMap);
  const bounds = layer.getBounds();
  if (bounds.isValid()) {
    databaseMonitoringLeafletMap.fitBounds(bounds.pad(0.03));
  }
  window.setTimeout(() => databaseMonitoringLeafletMap?.invalidateSize(), 0);
}

function buildDatabaseCountSeries(rows, getter, limit = 8) {
  const counts = new Map();
  rows.forEach((row) => {
    const value = String(getter(row) || "").trim();
    if (!value) return;
    counts.set(value, (counts.get(value) || 0) + 1);
  });
  const ordered = Array.from(counts.entries())
    .sort((left, right) => right[1] - left[1])
    .slice(0, limit);
  return {
    labels: ordered.map((item) => item[0]),
    values: ordered.map((item) => item[1]),
  };
}

function syncDatabaseTimelineSpeciesOptions(speciesNames) {
  if (!elements.databaseTimelineSpecies) return;
  const current = state.databaseTimelineSpecies || "";
  const options = ['<option value="">全部物种</option>']
    .concat(speciesNames.map((name) => `<option value="${escapeHtml(name)}">${escapeHtml(name)}</option>`));
  elements.databaseTimelineSpecies.innerHTML = options.join("");
  if (current && speciesNames.includes(current)) {
    elements.databaseTimelineSpecies.value = current;
  } else {
    state.databaseTimelineSpecies = "";
    elements.databaseTimelineSpecies.value = "";
  }
}

function getDatabaseRecordDate(row) {
  const raw = row.collection_date || row.imported_at || "";
  const date = new Date(raw);
  return Number.isNaN(date.getTime()) ? null : date;
}

function buildDatabaseTimelineSeries(rows, options = {}) {
  const days = Math.max(1, Number(options.days || 30));
  const speciesName = String(options.species || "").trim();
  const datedRows = rows
    .map((row) => ({ row, date: getDatabaseRecordDate(row) }))
    .filter((item) => item.date);
  if (!datedRows.length) {
    return { labels: [], values: [], points: [], title: "采样时间" };
  }
  const latest = datedRows.reduce((current, item) => (item.date > current ? item.date : current), datedRows[0].date);
  const start = new Date(latest);
  start.setHours(0, 0, 0, 0);
  start.setDate(start.getDate() - (days - 1));
  const filteredRows = datedRows.filter((item) => item.date >= start && item.date <= latest);
  const counts = new Map();
  filteredRows.forEach(({ row, date }) => {
    const label = date.toISOString().slice(0, 10);
    if (!counts.has(label)) {
      counts.set(label, speciesName ? 0 : new Set());
    }
    if (speciesName) {
      const rowSpecies = String(row.species_name || row.mlst_species_name || "").trim();
      if (rowSpecies === speciesName) {
        counts.set(label, Number(counts.get(label) || 0) + 1);
      }
    } else {
      const rowSpecies = String(row.species_name || row.mlst_species_name || "").trim();
      if (rowSpecies) {
        counts.get(label).add(rowSpecies);
      }
    }
  });
  const labels = [];
  const values = [];
  const points = [];
  for (let cursor = new Date(start); cursor <= latest; cursor.setDate(cursor.getDate() + 1)) {
    const label = cursor.toISOString().slice(0, 10);
    const rawValue = counts.get(label);
    const value = speciesName ? Number(rawValue || 0) : (rawValue instanceof Set ? rawValue.size : 0);
    labels.push(label);
    values.push(value);
    if (value > 0) {
      points.push({ label, value });
    }
  }
  return {
    labels,
    values,
    points,
    title: speciesName ? `${speciesName} 检出样本数` : "采样时间与检出物种数量",
  };
}

function getDatabaseMonitoringLatestDate(rows) {
  const latest = rows
    .map((item) => item.collection_date || item.imported_at || "")
    .map((value) => new Date(value))
    .filter((date) => !Number.isNaN(date.getTime()))
    .sort((left, right) => right.getTime() - left.getTime())[0];
  return latest ? latest.toISOString().slice(0, 10) : "";
}

function renderDatabaseMonitoringRecent(rows) {
  if (!elements.databaseSurveillanceRecent) return;
  const recent = [...rows]
    .sort((left, right) => {
      const leftTime = new Date(left.imported_at || left.collection_date || 0).getTime();
      const rightTime = new Date(right.imported_at || right.collection_date || 0).getTime();
      return rightTime - leftTime;
    })
    .slice(0, 8);
  if (!recent.length) {
    elements.databaseSurveillanceRecent.innerHTML = '<div class="empty-state">暂无最近入库样本。</div>';
    return;
  }
  elements.databaseSurveillanceRecent.innerHTML = `
    <table class="surveillance-table">
      <thead>
        <tr>
          <th>样本</th>
          <th>物种</th>
          <th>疑似症候群</th>
          <th>监测来源</th>
          <th>采样地点</th>
          <th>聚集性状态</th>
          <th>时间</th>
        </tr>
      </thead>
      <tbody>
        ${recent.map((item) => `
          <tr>
            <td>${escapeHtml(item.sample_name || "-")}</td>
            <td>${escapeHtml(truncateText(item.species_name || item.mlst_species_name || "-", 30))}</td>
            <td>${escapeHtml(truncateText(getDatabaseMetadataDisplayValue(item, "suspected_syndrome") || "-", 24))}</td>
            <td>${escapeHtml(truncateText(getDatabaseMetadataDisplayValue(item, "surveillance_source") || "-", 24))}</td>
            <td>${escapeHtml(truncateText(getDatabaseCollectionSiteDisplay(item) || "-", 30))}</td>
            <td>${escapeHtml(truncateText(getDatabaseMetadataDisplayValue(item, "cluster_status") || "-", 18))}</td>
            <td>${escapeHtml(formatDate(item.collection_date || item.imported_at || "") || "-")}</td>
          </tr>
        `).join("")}
      </tbody>
    </table>
  `;
}

function renderDatabaseInteractiveBarChartShell(title, note) {
  return `
    <div class="viz-shell">
      <h4>${escapeHtml(title)}</h4>
      <p class="viz-subnote">${escapeHtml(note)}</p>
      <div class="database-bar-chart-shell">
        <canvas class="database-bar-canvas" aria-label="${escapeHtml(title)}"></canvas>
        <div class="database-chart-tooltip hidden"></div>
      </div>
    </div>
  `;
}

function renderDatabaseInteractiveDonutShell(title, note) {
  return `
    <div class="viz-shell">
      <h4>${escapeHtml(title)}</h4>
      <p class="viz-subnote">${escapeHtml(note)}</p>
      <div class="database-donut-layout">
        <div class="database-donut-shell">
          <canvas class="database-donut-canvas" aria-label="${escapeHtml(title)}"></canvas>
          <div class="database-chart-tooltip hidden"></div>
        </div>
        <div class="viz-legend database-donut-legend"></div>
      </div>
    </div>
  `;
}

function renderDatabaseSiteRankingShell(title, note) {
  return `
    <div class="viz-shell">
      <h4>${escapeHtml(title)}</h4>
      <p class="viz-subnote">${escapeHtml(note)}</p>
      <div class="database-site-ranking" data-site-ranking></div>
    </div>
  `;
}

function renderDatabaseLineChart(series, title) {
  const max = Math.max(...series.values, 1);
  const points = series.values.map((value, index) => {
    const x = series.values.length === 1 ? 10 : (index / (series.values.length - 1)) * 100;
    const y = 90 - (value / max) * 70;
    return `${x},${y}`;
  }).join(" ");
  const markers = series.values.map((value, index) => {
    const x = series.values.length === 1 ? 10 : (index / (series.values.length - 1)) * 100;
    const y = 90 - (value / max) * 70;
    return `<circle cx="${x}" cy="${y}" r="2.8" fill="${databaseChartColor(0)}"></circle>`;
  }).join("");
  const axisLabels = series.labels.map((label, index) => {
    const x = series.values.length === 1 ? 10 : (index / (series.values.length - 1)) * 100;
    return `<text x="${x}" y="98" text-anchor="middle">${escapeHtml(shortenDatabaseLabel(label, 8))}</text>`;
  }).join("");
  return `<div class="viz-shell"><h4>${escapeHtml(title)}</h4><svg viewBox="0 0 100 100" class="viz-line-chart"><polyline fill="none" stroke="${databaseChartColor(0)}" stroke-width="2.2" points="${points}"></polyline>${markers}<g class="viz-axis-labels">${axisLabels}</g></svg></div>`;
}

function renderDatabaseInteractiveTimelineShell(title, yAxisLabel) {
  return `
    <div class="viz-shell">
      <h4>${escapeHtml(title)}</h4>
      <div class="database-timeline-chart-shell">
        <canvas class="database-timeline-canvas" aria-label="${escapeHtml(title)}"></canvas>
        <div class="database-timeline-tooltip hidden" role="status" aria-live="polite"></div>
      </div>
      <div class="database-timeline-axis-notes">
        <span>X 轴：采样日期</span>
        <span>Y 轴：${escapeHtml(yAxisLabel)}</span>
      </div>
    </div>
  `;
}

function initializeDatabaseBarChart(container, series, title, onSelect = null) {
  if (!container) return;
  const canvas = container.querySelector(".database-bar-canvas");
  const tooltip = container.querySelector(".database-chart-tooltip");
  if (!(canvas instanceof HTMLCanvasElement) || !(tooltip instanceof HTMLElement)) return;
  const host = canvas.parentElement;
  if (!host) return;
  const max = Math.max(...series.values, 1);
  const colors = series.labels.map((_, index) => databaseChartColor(index));

  const draw = () => {
    const width = Math.max(320, host.clientWidth);
    const rowHeight = 34;
    const height = Math.max(172, series.labels.length * rowHeight + 18);
    const dpr = window.devicePixelRatio || 1;
    canvas.width = Math.floor(width * dpr);
    canvas.height = Math.floor(height * dpr);
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;
    const ctx = canvas.getContext("2d");
    if (!ctx) return [];
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, width, height);
    const left = 154;
    const right = 34;
    const barWidth = Math.max(80, width - left - right);
    const bars = [];
    series.labels.forEach((label, index) => {
      const y = 14 + index * rowHeight;
      const value = series.values[index];
      const fillWidth = (value / max) * barWidth;
      roundRect(ctx, left, y + 9, barWidth, 11, 999);
      ctx.fillStyle = "rgba(255,255,255,0.1)";
      ctx.fill();
      roundRect(ctx, left, y + 9, Math.max(8, fillWidth), 11, 999);
      ctx.fillStyle = colors[index];
      ctx.fill();
      ctx.fillStyle = "#27483d";
      ctx.font = '14px "Source Sans 3", "PingFang SC", "Noto Sans CJK SC", sans-serif';
      ctx.textAlign = "left";
      ctx.textBaseline = "middle";
      ctx.fillText(shortenDatabaseLabel(label, 22), 0, y + 15);
      ctx.textAlign = "right";
      ctx.fillText(String(value), width, y + 15);
      bars.push({ x: left, y: y + 9, width: barWidth, height: 11, label, value });
    });
    return bars;
  };

  let bars = draw();
  canvas.onmousemove = (event) => {
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const hit = bars.find((bar) => x >= bar.x && x <= bar.x + bar.width && y >= bar.y - 6 && y <= bar.y + bar.height + 6);
    if (!hit) {
      tooltip.classList.add("hidden");
      return;
    }
    tooltip.innerHTML = `<strong>${escapeHtml(hit.label)}</strong><span>${escapeHtml(title)}：${hit.value}</span>`;
    tooltip.style.left = `${Math.min(rect.width - 12, Math.max(12, x + 16))}px`;
    tooltip.style.top = `${Math.max(14, y)}px`;
    tooltip.classList.remove("hidden");
  };
  canvas.onmouseleave = () => tooltip.classList.add("hidden");
  canvas.onclick = (event) => {
    if (typeof onSelect !== "function") return;
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const hit = bars.find((bar) => x >= bar.x && x <= bar.x + bar.width && y >= bar.y - 6 && y <= bar.y + bar.height + 6);
    if (hit) onSelect(hit);
  };
  if (typeof ResizeObserver !== "undefined") {
    const observer = new ResizeObserver(() => {
      bars = draw();
      tooltip.classList.add("hidden");
    });
    observer.observe(host);
    canvas._databaseResizeObserver = observer;
  }
}

function initializeDatabaseDonutChart(container, series, title, onSelect = null) {
  if (!container) return;
  const canvas = container.querySelector(".database-donut-canvas");
  const tooltip = container.querySelector(".database-chart-tooltip");
  const legend = container.querySelector(".database-donut-legend");
  if (!(canvas instanceof HTMLCanvasElement) || !(tooltip instanceof HTMLElement) || !(legend instanceof HTMLElement)) return;
  const host = canvas.parentElement;
  if (!host) return;
  const total = series.values.reduce((sum, value) => sum + value, 0) || 1;
  const compactDonut = !!container.closest(".queue-analytics-card-focus");
  const colors = series.labels.map((_, index) => compactDonut ? queueAnalyticsDonutColor(index) : databaseChartColor(index));

  const draw = () => {
    const compact = compactDonut;
    const size = compact
      ? Math.max(156, Math.min(host.clientWidth, 180))
      : Math.max(196, Math.min(host.clientWidth, 252));
    const dpr = window.devicePixelRatio || 1;
    canvas.width = Math.floor(size * dpr);
    canvas.height = Math.floor(size * dpr);
    canvas.style.width = `${size}px`;
    canvas.style.height = `${size}px`;
    const ctx = canvas.getContext("2d");
    if (!ctx) return { slices: [], cx: 0, cy: 0, outer: 0, inner: 0 };
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, size, size);
    const cx = size / 2;
    const cy = size / 2;
    const outer = size * (compact ? 0.42 : 0.43);
    const inner = size * (compact ? 0.255 : 0.265);
    const radius = (outer + inner) / 2;
    const visibleTotal = Math.PI * 1.66;
    const startBase = -Math.PI * 0.78;
    const gap = series.values.length > 1 ? (compact ? 0.11 : 0.1) : 0;
    const available = Math.max(Math.PI * 0.4, visibleTotal - gap * Math.max(0, series.values.length - 1));
    let start = startBase;
    const slices = [];
    const largestIndex = series.values.reduce((best, value, index) => value > series.values[best] ? index : best, 0);

    series.values.forEach((value, index) => {
      const delta = (value / total) * available;
      if (delta <= 0) return;
      const end = start + delta;
      ctx.beginPath();
      ctx.arc(cx, cy, outer, start, end);
      ctx.arc(cx, cy, inner, end, start, true);
      ctx.closePath();
      ctx.fillStyle = colors[index];
      ctx.fill();
      slices.push({ start, end, label: series.labels[index], value, color: colors[index], index });
      start = end + gap;
    });

    slices.forEach((slice) => {
      const angle = (slice.start + slice.end) / 2;
      const labelRadius = radius;
      const x = cx + Math.cos(angle) * labelRadius;
      const y = cy + Math.sin(angle) * labelRadius;
      const isLargest = slice.index === largestIndex;
      const canLabel = isLargest || (slice.end - slice.start > 0.52 && size >= 176);
      if (!canLabel) return;
      const text = String(slice.value);
      ctx.font = `${isLargest ? 14 : 12}px "Source Sans 3", "PingFang SC", "Noto Sans CJK SC", sans-serif`;
      const metrics = ctx.measureText(text);
      const pillWidth = metrics.width + (isLargest ? 18 : 12);
      const pillHeight = isLargest ? 24 : 20;
      roundRect(ctx, x - pillWidth / 2, y - pillHeight / 2, pillWidth, pillHeight, isLargest ? 7 : 999);
      ctx.fillStyle = isLargest ? "rgba(17, 24, 39, 0.94)" : "rgba(255, 255, 255, 0.82)";
      ctx.fill();
      ctx.fillStyle = isLargest ? "#ffffff" : "rgba(17, 24, 39, 0.88)";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(text, x, y + 0.5);
    });

    return { slices, cx, cy, outer, inner };
  };

  legend.innerHTML = series.labels.map((label, index) => `
    <div class="viz-legend-item">
      <span class="viz-dot" style="background:${colors[index]}"></span>
      <span>${escapeHtml(shortenDatabaseLabel(label, 18))}</span>
      <strong>${Math.round((series.values[index] / total) * 100)}%</strong>
    </div>
  `).join("");

  let current = draw();
  const findSliceFromEvent = (event) => {
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const dx = x - current.cx;
    const dy = y - current.cy;
    const distance = Math.hypot(dx, dy);
    if (distance < current.inner || distance > current.outer) {
      return null;
    }
    let angle = Math.atan2(dy, dx);
    if (angle < -Math.PI / 2) angle += Math.PI * 2;
    return current.slices.find((slice) => angle >= slice.start && angle <= slice.end) || null;
  };
  canvas.onmousemove = (event) => {
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const hit = findSliceFromEvent(event);
    if (!hit) {
      tooltip.classList.add("hidden");
      return;
    }
    tooltip.innerHTML = `<strong>${escapeHtml(hit.label)}</strong><span>${escapeHtml(title)}：${hit.value}</span>`;
    tooltip.style.left = `${Math.min(rect.width - 12, Math.max(12, x + 16))}px`;
    tooltip.style.top = `${Math.max(14, y)}px`;
    tooltip.classList.remove("hidden");
  };
  canvas.onmouseleave = () => tooltip.classList.add("hidden");
  canvas.onclick = (event) => {
    if (typeof onSelect !== "function") return;
    const hit = findSliceFromEvent(event);
    if (hit) onSelect(hit);
  };
  if (typeof ResizeObserver !== "undefined") {
    const observer = new ResizeObserver(() => {
      current = draw();
      tooltip.classList.add("hidden");
    });
    observer.observe(host);
    canvas._databaseResizeObserver = observer;
  }
}

function initializeDatabaseSiteRanking(container, series, title, onSelect = null) {
  if (!container) return;
  const host = container.querySelector("[data-site-ranking]");
  if (!(host instanceof HTMLElement)) return;
  const max = Math.max(...series.values, 1);
  host.innerHTML = series.labels.map((label, index) => {
    const value = series.values[index];
    const width = Math.max(8, Math.round((value / max) * 100));
    return `
      <article class="database-site-ranking-item" ${typeof onSelect === "function" ? `data-site-ranking-label="${escapeHtml(label)}" data-site-ranking-value="${escapeHtml(String(value))}" tabindex="0" role="button"` : ""}>
        <div class="database-site-ranking-head">
          <span class="database-site-ranking-rank">#${index + 1}</span>
          <strong class="database-site-ranking-name">${escapeHtml(label)}</strong>
          <span class="database-site-ranking-value">${escapeHtml(title)}：${value}</span>
        </div>
        <div class="database-site-ranking-track">
          <span class="database-site-ranking-fill" style="width:${width}%"></span>
        </div>
      </article>
    `;
  }).join("");
  if (typeof onSelect === "function") {
    host.querySelectorAll("[data-site-ranking-label]").forEach((node) => {
      const fire = () => onSelect({
        label: String(node.getAttribute("data-site-ranking-label") || ""),
        value: Number(node.getAttribute("data-site-ranking-value") || 0),
      });
      node.addEventListener("click", fire);
      node.addEventListener("keydown", (event) => {
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault();
          fire();
        }
      });
    });
  }
}

function roundRect(ctx, x, y, width, height, radius) {
  const r = Math.min(radius, width / 2, height / 2);
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + width, y, x + width, y + height, r);
  ctx.arcTo(x + width, y + height, x, y + height, r);
  ctx.arcTo(x, y + height, x, y, r);
  ctx.arcTo(x, y, x + width, y, r);
  ctx.closePath();
}

function initializeDatabaseTimelineChart(container, series, yAxisLabel) {
  if (!container) return;
  const canvas = container.querySelector(".database-timeline-canvas");
  const tooltip = container.querySelector(".database-timeline-tooltip");
  if (!(canvas instanceof HTMLCanvasElement) || !(tooltip instanceof HTMLElement)) return;
  const host = canvas.parentElement;
  if (!host) return;

  const draw = () => {
    const width = Math.max(320, host.clientWidth);
    const height = 150;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = Math.floor(width * dpr);
    canvas.height = Math.floor(height * dpr);
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;
    const ctx = canvas.getContext("2d");
    if (!ctx) return { points: [] };
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, width, height);

    const padding = { top: 12, right: 14, bottom: 30, left: 42 };
    const plotWidth = Math.max(40, width - padding.left - padding.right);
    const plotHeight = Math.max(40, height - padding.top - padding.bottom);
    const max = Math.max(...series.values, 1);
    const pointCount = series.values.length;
    const points = series.values.map((value, index) => {
      const x = pointCount === 1 ? padding.left + plotWidth / 2 : padding.left + (index / Math.max(1, pointCount - 1)) * plotWidth;
      const y = padding.top + plotHeight - (value / max) * plotHeight;
      return { x, y, value, label: series.labels[index] };
    });

    ctx.strokeStyle = "rgba(235, 242, 249, 0.12)";
    ctx.lineWidth = 1;
    [0, 0.25, 0.5, 0.75, 1].forEach((ratio) => {
      const y = padding.top + plotHeight - ratio * plotHeight;
      ctx.beginPath();
      ctx.moveTo(padding.left, y);
      ctx.lineTo(width - padding.right, y);
      ctx.stroke();
    });

    if (points.length) {
      const areaGradient = ctx.createLinearGradient(0, padding.top, 0, padding.top + plotHeight);
      areaGradient.addColorStop(0, "rgba(116, 169, 148, 0.26)");
      areaGradient.addColorStop(1, "rgba(116, 169, 148, 0.03)");
      ctx.beginPath();
      ctx.moveTo(points[0].x, padding.top + plotHeight);
      points.forEach((point) => ctx.lineTo(point.x, point.y));
      ctx.lineTo(points[points.length - 1].x, padding.top + plotHeight);
      ctx.closePath();
      ctx.fillStyle = areaGradient;
      ctx.fill();

      ctx.beginPath();
      points.forEach((point, index) => {
        if (index === 0) ctx.moveTo(point.x, point.y);
        else ctx.lineTo(point.x, point.y);
      });
      ctx.strokeStyle = "rgba(88, 131, 165, 0.96)";
      ctx.lineWidth = 2;
      ctx.lineJoin = "round";
      ctx.lineCap = "round";
      ctx.stroke();

      points.forEach((point) => {
        if (point.value <= 0) return;
        ctx.beginPath();
        ctx.arc(point.x, point.y, 3.2, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(252, 253, 255, 0.96)";
        ctx.fill();
        ctx.lineWidth = 1.25;
        ctx.strokeStyle = "rgba(88, 131, 165, 0.98)";
        ctx.stroke();
      });
    }

    ctx.fillStyle = "rgba(57, 88, 77, 0.82)";
    ctx.font = '12px "Source Sans 3", "PingFang SC", "Noto Sans CJK SC", sans-serif';
    ctx.textAlign = "end";
    ctx.textBaseline = "middle";
    [0, 0.5, 1].forEach((ratio) => {
      const y = padding.top + plotHeight - ratio * plotHeight;
      const value = Math.round(max * ratio);
      ctx.fillText(String(value), padding.left - 8, y);
    });

    const xTickIndexes = [0, Math.floor((pointCount - 1) / 2), Math.max(0, pointCount - 1)]
      .filter((value, index, array) => array.indexOf(value) === index);
    ctx.textAlign = "center";
    ctx.textBaseline = "top";
    xTickIndexes.forEach((index) => {
      const x = pointCount === 1 ? padding.left + plotWidth / 2 : padding.left + (index / Math.max(1, pointCount - 1)) * plotWidth;
      ctx.fillText(shortenDatabaseLabel(series.labels[index], 10), x, padding.top + plotHeight + 8);
    });

    ctx.save();
    ctx.translate(12, padding.top + plotHeight / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillStyle = "rgba(57, 88, 77, 0.82)";
    ctx.fillText(yAxisLabel, 0, 0);
    ctx.restore();

    return { points };
  };

  let current = draw();

  const onMove = (event) => {
    if (!current.points.length) return;
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    let nearest = null;
    let nearestDistance = Infinity;
    current.points.forEach((point) => {
      const distance = Math.hypot(point.x - x, point.y - y);
      if (distance < nearestDistance) {
        nearestDistance = distance;
        nearest = point;
      }
    });
    if (!nearest || nearestDistance > 22) {
      tooltip.classList.add("hidden");
      return;
    }
    tooltip.innerHTML = `<strong>${escapeHtml(nearest.label)}</strong><span>${escapeHtml(yAxisLabel)}：${nearest.value}</span>`;
    tooltip.style.left = `${Math.min(rect.width - 12, Math.max(12, nearest.x + 12))}px`;
    tooltip.style.top = `${Math.max(8, nearest.y - 10)}px`;
    tooltip.classList.remove("hidden");
  };

  const onLeave = () => tooltip.classList.add("hidden");
  canvas.onmousemove = onMove;
  canvas.onmouseleave = onLeave;

  if (typeof ResizeObserver !== "undefined") {
    const resizeObserver = new ResizeObserver(() => {
      current = draw();
      tooltip.classList.add("hidden");
    });
    resizeObserver.observe(host);
    canvas._databaseResizeObserver = resizeObserver;
  }
}

function describeDatabaseArcSlice(cx, cy, r, startAngle, endAngle) {
  const start = polarToDatabaseCartesian(cx, cy, r, endAngle);
  const end = polarToDatabaseCartesian(cx, cy, r, startAngle);
  const largeArcFlag = endAngle - startAngle <= Math.PI ? "0" : "1";
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArcFlag} 0 ${end.x} ${end.y} Z`;
}

function polarToDatabaseCartesian(cx, cy, r, angle) {
  return { x: cx + Math.cos(angle) * r, y: cy + Math.sin(angle) * r };
}

function databaseChartColor(index) {
  const colors = ["#5b7da6", "#8fa7c4", "#6a95c7", "#7b8ca8", "#91a2ba", "#4f6b91", "#8b9fbc", "#a9b7cc"];
  return colors[index % colors.length];
}

function queueAnalyticsDonutColor(index) {
  const colors = ["#5f7898", "#8fa2b8", "#a9a7ba", "#c3cad6", "#7488a4", "#9bb1c3", "#b7bcc8", "#d4d9e2"];
  return colors[index % colors.length];
}

function shortenDatabaseLabel(value, maxLength) {
  const text = String(value || "");
  return text.length > maxLength ? `${text.slice(0, Math.max(1, maxLength - 1))}…` : text;
}

async function openDatabaseSampleModal(sampleKey, options = {}) {
  if (!state.databaseMetadataTemplates.length) {
    await loadDatabaseMetadataTemplates();
  }
  const record = await requestJson(`/api/database/samples/${encodeURIComponent(sampleKey)}`);
  state.currentDatabaseSample = record;
  const editable = !!record.can_edit;
  elements.databaseSampleName.value = record.sample_name || "";
  elements.databaseGenomeId.value = record.genome_id || "";
  elements.databaseSampleAlias.value = record.sample_alias || "";
  if (elements.databasePathogenType) {
    elements.databasePathogenType.value = String(record.pathogen_type || "").trim();
  }
  elements.databaseTaxid.value = record.taxid || "";
  elements.databaseDescription.value = record.description || "";
  elements.databaseSampleSource.value = record.sample_source || "";
  elements.databaseCollectionDate.value = record.collection_date || "";
  elements.databaseGender.value = record.gender || "";
  populateDatabaseCountryOptions(record.country || "");
  if (elements.databaseVisibilityScope) {
    const visibility = String(record.visibility_scope || "group").trim() || "group";
    elements.databaseVisibilityScope.value = visibility === "public" ? "public" : "group";
    elements.databaseVisibilityScope.disabled = !(editable && String(record.library_scope || "") === "main" && state.currentUser?.role === "admin");
  }
  elements.databaseHostInfo.value = record.host_info || "";
  setDatabaseLocationFields(record.location_json || "", record.country || "");
  elements.databaseSampleType.value = record.sample_type || "";
  elements.databaseSequencingMethod.value = record.sequencing_method || "";
  elements.databaseGenomeLength.value = record.genome_length || "";
  elements.databaseMlstSt.value = record.mlst_st || "";
  elements.databaseSerotypeResult.value = record.serotype_result || "";
  elements.databaseResistanceGeneHits.value = record.resistance_gene_hits || "";
  elements.databaseVirulenceGeneHits.value = record.virulence_gene_hits || "";
  elements.databaseResistanceMgeHits.value = record.resistance_mge_hits || "";
  elements.databaseVirulenceMgeHits.value = record.virulence_mge_hits || "";
  elements.databaseNote.value = record.note || "";
  renderDatabaseMetadataEditor(record.custom_metadata_json, state.databaseMetadataTemplates);
  if (elements.databaseArchiveTemplate) {
    elements.databaseArchiveTemplate.value = "";
  }
  Array.from(elements.databaseSampleForm?.querySelectorAll("input, textarea, select, button[data-metadata-action]") || []).forEach((node) => {
    if (node.id === "cancel-database-sample" || node.id === "close-database-sample-modal") return;
    if (node.type === "submit") return;
    node.disabled = !editable;
  });
  if (elements.databaseSampleForm?.querySelector('button[type="submit"]')) {
    const submitButton = elements.databaseSampleForm.querySelector('button[type="submit"]');
    submitButton.disabled = !editable;
    submitButton.textContent = editable ? "保存样本信息" : "只读查看";
  }
  elements.databaseSampleStatic.innerHTML = `
    <article><span>任务</span><strong>${escapeHtml(record.task_name || "-")}</strong></article>
    <article><span>物种预估</span><strong>${escapeHtml(record.species_name || record.mlst_species_name || "--")}</strong></article>
    <article><span>MLST ST</span><strong>${escapeHtml(record.mlst_st || "--")}</strong></article>
    <article><span>血清型</span><strong>${escapeHtml(record.serotype_result || "--")}</strong></article>
    <article><span>耐药基因摘要</span><strong title="${escapeHtml(record.resistance_gene_hits || "")}">${escapeHtml(truncateText(record.resistance_gene_hits || "--", 56))}</strong></article>
    <article><span>毒力基因摘要</span><strong title="${escapeHtml(record.virulence_gene_hits || "")}">${escapeHtml(truncateText(record.virulence_gene_hits || "--", 56))}</strong></article>
    <article><span>耐药基因-MGE</span><strong title="${escapeHtml(record.resistance_mge_hits || "")}">${escapeHtml(truncateText(record.resistance_mge_hits || "--", 56))}</strong></article>
    <article><span>毒力基因-MGE</span><strong title="${escapeHtml(record.virulence_mge_hits || "")}">${escapeHtml(truncateText(record.virulence_mge_hits || "--", 56))}</strong></article>
    <article><span>完整性</span><strong>${escapeHtml(record.completeness || "--")}</strong></article>
    <article><span>污染率</span><strong>${escapeHtml(record.contamination || "--")}</strong></article>
    <article><span>Q20</span><strong>${escapeHtml(record.q20_rate || "--")}</strong></article>
    <article><span>Q30</span><strong>${escapeHtml(record.q30_rate || "--")}</strong></article>
    <article><span>Contig 数</span><strong>${escapeHtml(record.contig_count || "--")}</strong></article>
    <article><span>质粒数</span><strong>${escapeHtml(record.plasmid_count || "--")}</strong></article>
    <article><span>最终 fasta</span><strong title="${escapeHtml(record.final_fasta_path || "")}">${escapeHtml(truncateText(record.final_fasta_path || "-", 56))}</strong></article>
    <article><span>导入时间</span><strong>${escapeHtml(record.imported_at ? formatDate(record.imported_at) : "-")}</strong></article>
    <article><span>更新时间</span><strong>${escapeHtml(record.updated_at ? formatDate(record.updated_at) : "-")}</strong></article>
    <article><span>报告目录</span><strong title="${escapeHtml(record.report_dir || "")}">${escapeHtml(truncateText(record.report_dir || "-", 56))}</strong></article>
  `;
  elements.databaseSampleModal?.classList.remove("hidden");
  elements.databaseSampleModal?.setAttribute("aria-hidden", "false");
  if (options.focusMetadata) {
    window.requestAnimationFrame(() => {
      const target = elements.databaseMetadataRows?.closest(".database-metadata-section");
      target?.scrollIntoView({ block: "start", behavior: "smooth" });
      const firstInput = elements.databaseMetadataRows?.querySelector("input:not([disabled]), select:not([disabled]), textarea:not([disabled])");
      if (firstInput instanceof HTMLElement) {
        firstInput.focus({ preventScroll: true });
      }
    });
  }
}

async function openDatabaseBatchEditModal() {
  if (!state.databaseSelectedSamples.length) {
    showToast("请先在样本列表中勾选需要批量补录的样本。", "warning");
    return;
  }
  if (!state.databaseMetadataTemplates.length) {
    await loadDatabaseMetadataTemplates();
  }
  if (elements.databaseBatchEditSummary) {
    const names = (state.databaseRecords || [])
      .filter((row) => state.databaseSelectedSamples.includes(String(row.sample_key || "")))
      .map((row) => row.sample_name || row.sample_key)
      .slice(0, 4);
    const remainder = Math.max(0, state.databaseSelectedSamples.length - names.length);
    elements.databaseBatchEditSummary.textContent = remainder
      ? `已选择 ${state.databaseSelectedSamples.length} 个样本：${names.join("、")} 等 ${remainder} 个。`
      : `已选择 ${state.databaseSelectedSamples.length} 个样本：${names.join("、")}。`;
  }
  renderDatabaseMetadataEditor("[]", state.databaseMetadataTemplates, elements.databaseBatchEditRows, { includeCustom: false });
  elements.databaseBatchEditModal?.classList.remove("hidden");
  elements.databaseBatchEditModal?.setAttribute("aria-hidden", "false");
}

