async function onSubmitDatabaseRelease(event) {
  event.preventDefault();
  const versionLabel = String(elements.databaseReleaseVersionLabel?.value || "").trim();
  const note = String(elements.databaseReleaseNote?.value || "").trim();
  if (!versionLabel) {
    showToast("请先填写版本名称。", "warning");
    elements.databaseReleaseVersionLabel?.focus();
    return;
  }
  const submitButton = event.currentTarget?.querySelector?.('button[type="submit"]');
  await withSubmittingState(submitButton, "发布中...", async () => {
    await requestJson("/api/database/releases", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ version_label: versionLabel, note }),
    });
    closeDatabaseReleaseModal();
    showToast("已发布新的主数据库命名版本");
    renderOperationResult(elements.databaseOperationResult, {
      title: "主数据库版本已发布",
      message: "当前主数据库快照已经形成命名版本，可用于后续追溯与版本对比。",
      metrics: [{ label: "版本名称", value: versionLabel }],
      details: note ? [`发布说明：${note}`] : [],
    });
    await loadDatabaseRecords();
  });
}

