    if (elements.hostLocalImportSubmit) elements.hostLocalImportSubmit.textContent = "保存宿主信息";
    if (elements.hostLocalName) elements.hostLocalName.value = String(record.host_name || "");
    if (elements.hostLocalGenomeName) elements.hostLocalGenomeName.value = String(record.genome_name || record.host_name || "");
    if (elements.hostLocalTaxid) elements.hostLocalTaxid.value = String(record.taxid || "");
    if (elements.hostLocalAccession) elements.hostLocalAccession.value = String(record.source_accession || "");
    if (elements.hostLocalSourceLabel) elements.hostLocalSourceLabel.value = String(record.source_label || "");
