function parseCustomMetadata(rawValue) {
  if (Array.isArray(rawValue)) return rawValue.map(normalizeDatabaseMetadataItem).filter(Boolean);
  const rawText = String(rawValue || "").trim();
  if (!rawText) return [];
  try {
    const parsed = JSON.parse(rawText);
    if (!Array.isArray(parsed)) return [];
    return parsed.map(normalizeDatabaseMetadataItem).filter(Boolean);
  } catch (_error) {
    return [];
  }
}

function mergeDatabaseMetadataTemplates(templates, values) {
  const valueMap = new Map((Array.isArray(values) ? values : []).map((item) => [String(item.key || "").trim(), item]));
  const merged = [];
  (Array.isArray(templates) ? templates : []).forEach((template) => {
    const key = String(template.key || "").trim();
    if (!key) return;
    const existing = valueMap.get(key);
    merged.push({
      key,
      label: existing?.label || template.label || key,
      type: existing?.type || template.type || "text",
      options: existing?.options || template.options || [],
      value: existing?.value ?? "",
      group: existing?.group || template.group || "",
      requirement: existing?.requirement || template.requirement || "",
      placeholder: existing?.placeholder || template.placeholder || "",
      help_text: existing?.help_text || template.help_text || "",
      dictionary_name: existing?.dictionary_name || template.dictionary_name || "",
    });
    valueMap.delete(key);
  });
  valueMap.forEach((item) => {
    merged.push(item);
  });
  return merged;
}

function normalizeDatabaseMetadataItem(item) {
  if (!item || typeof item !== "object") return null;
  const key = String(item.key || "").trim();
  const label = String(item.label || key || "").trim();
  const type = ["text", "country", "select", "datetime", "location"].includes(String(item.type || "").trim())
    ? String(item.type || "").trim()
    : "text";
  const options = Array.isArray(item.options) ? item.options.map((part) => String(part || "").trim()).filter(Boolean) : [];
  const value = type === "location"
    ? {
        province: String(item.value?.province || "").trim(),
        city: String(item.value?.city || "").trim(),
        district: String(item.value?.district || "").trim(),
        detail: String(item.value?.detail || "").trim(),
      }
    : String(item.value || "").trim();
  if (!key && !label && !value && !options.length) return null;
  return {
    key,
    label,
    type,
    options,
    value,
    group: String(item.group || "").trim(),
    requirement: String(item.requirement || "").trim(),
    placeholder: String(item.placeholder || "").trim(),
    help_text: String(item.help_text || "").trim(),
    dictionary_name: String(item.dictionary_name || "").trim(),
  };
}

function populateDatabaseCountryOptions(selectedValue) {
  populateCountrySelect(elements.databaseCountry, selectedValue);
}

function populateDatabaseLocalCountryOptions(selectedValue) {
  populateCountrySelect(elements.databaseLocalCountry, selectedValue);
}

function populateCountrySelect(selectNode, selectedValue) {
  if (!selectNode) return;
  const values = COUNTRY_OPTIONS.map((item) => item.value);
  const optionMarkup = COUNTRY_OPTIONS.map(
    (item) => `<option value="${escapeHtml(item.value)}">${escapeHtml(item.label || item.value)}</option>`
  );
  if (selectedValue && !values.includes(selectedValue)) {
    optionMarkup.push(`<option value="${escapeHtml(selectedValue)}">${escapeHtml(selectedValue)}</option>`);
  }
  selectNode.innerHTML = ['<option value="">选择国家</option>'].concat(optionMarkup).join("");
  selectNode.value = selectedValue || "";
}

function isChinaCountry(value) {
  const text = String(value || "").trim().toLowerCase();
  return ["china", "中国", "people's republic of china", "pr china", "cn"].includes(text);
}

function syncDatabaseLocationField(options = {}) {
  const preserveValue = options.preserveValue ?? false;
  const countryValue = elements.databaseCountry?.value.trim() || "";
  const isChina = isChinaCountry(countryValue);
  const provinceSelect = elements.databaseLocationProvince;
  const citySelect = elements.databaseLocationCity;
  const districtSelect = elements.databaseLocationDistrict;
  const detailInput = elements.databaseLocationDetail;
  const note = elements.databaseLocationNote;
  if (!provinceSelect || !citySelect || !districtSelect || !detailInput || !note) return;

  provinceSelect.disabled = !isChina;
  citySelect.disabled = !isChina;
  districtSelect.disabled = !isChina;
  detailInput.disabled = !isChina;
  note.textContent = isChina
    ? "已选择中国：启用省 / 市 / 区县联动。"
    : "仅当国家选择中国时启用省市区联动；其他国家不填写地区联动信息。";

  if (!isChina) {
    provinceSelect.innerHTML = '<option value="">省 / Province</option>';
    citySelect.innerHTML = '<option value="">市 / City</option>';
    districtSelect.innerHTML = '<option value="">区县 / District</option>';
    provinceSelect.value = "";
    citySelect.value = "";
    districtSelect.value = "";
    detailInput.value = "";
    return;
  }

  const provinceValue = preserveValue ? provinceSelect.value : "";
  const cityValue = preserveValue ? citySelect.value : "";
  const districtValue = preserveValue ? districtSelect.value : "";
  populateDatabaseProvinceOptions(provinceValue);
  populateDatabaseCityOptions(provinceSelect.value, cityValue);
  populateDatabaseDistrictOptions(provinceSelect.value, citySelect.value, districtValue);
}

function populateDatabaseProvinceOptions(selectedValue) {
  if (!elements.databaseLocationProvince) return;
  const provinces = Object.keys(CHINA_REGION_TREE);
  elements.databaseLocationProvince.innerHTML = ['<option value="">省 / Province</option>']
    .concat(provinces.map((province) => `<option value="${escapeHtml(province)}">${escapeHtml(province)}</option>`))
    .join("");
  elements.databaseLocationProvince.value = provinces.includes(selectedValue) ? selectedValue : "";
}

function populateDatabaseCityOptions(province, selectedValue) {
  if (!elements.databaseLocationCity) return;
  const cities = province && CHINA_REGION_TREE[province] ? Object.keys(CHINA_REGION_TREE[province]) : [];
  elements.databaseLocationCity.innerHTML = ['<option value="">市 / City</option>']
    .concat(cities.map((city) => `<option value="${escapeHtml(city)}">${escapeHtml(city)}</option>`))
    .join("");
  elements.databaseLocationCity.value = cities.includes(selectedValue) ? selectedValue : "";
}

function populateDatabaseDistrictOptions(province, city, selectedValue) {
  if (!elements.databaseLocationDistrict) return;
  const districts = province && city && CHINA_REGION_TREE[province]?.[city] ? CHINA_REGION_TREE[province][city] : [];
  elements.databaseLocationDistrict.innerHTML = ['<option value="">区县 / District</option>']
    .concat(districts.map((district) => `<option value="${escapeHtml(district)}">${escapeHtml(district)}</option>`))
    .join("");
  elements.databaseLocationDistrict.value = districts.includes(selectedValue) ? selectedValue : "";
}

function parseDatabaseLocation(rawValue) {
  const rawText = String(rawValue || "").trim();
  if (!rawText) return { province: "", city: "", district: "", detail: "" };
  try {
    const parsed = JSON.parse(rawText);
    return {
      province: String(parsed?.province || "").trim(),
      city: String(parsed?.city || "").trim(),
      district: String(parsed?.district || "").trim(),
      detail: String(parsed?.detail || "").trim(),
    };
  } catch (_error) {
    return { province: "", city: "", district: "", detail: rawText };
  }
}

function resolveDatabaseCountryWithLocation(countryValue, rawLocation) {
  const normalizedCountry = String(countryValue || "").trim();
  if (normalizedCountry) return normalizedCountry;
  const location = parseDatabaseLocation(rawLocation);
  if (location.province || location.city || location.district) {
    return "中国";
  }
  return "";
}

function setDatabaseLocationFields(rawValue, countryValue) {
  const resolvedCountry = resolveDatabaseCountryWithLocation(countryValue, rawValue);
  const location = parseDatabaseLocation(rawValue);
  const province = canonicalizeChinaProvinceName(location.province);
  const city = canonicalizeChinaCityName(province, location.city);
  const district = canonicalizeChinaDistrictName(province, city, location.district);
  if (elements.databaseCountry && elements.databaseCountry.value !== resolvedCountry) {
    populateDatabaseCountryOptions(resolvedCountry);
  }
  syncDatabaseLocationField();
  if (!isChinaCountry(resolvedCountry)) return;
  populateDatabaseProvinceOptions(province);
  populateDatabaseCityOptions(province, city);
  populateDatabaseDistrictOptions(province, city, district);
  if (elements.databaseLocationDetail) {
    elements.databaseLocationDetail.value = location.detail;
  }
}

