async function onSubmitPathogenRemoteImport(event) {
  event.preventDefault();
  clearScopedValidation(elements.pathogenRemoteImportForm);
  const submitButton = event.currentTarget?.querySelector?.('button[type="submit"]');
  const ncbiMode = elements.pathogenRemoteNcbiMode?.value.trim() || "datasets";
  const query = String(elements.pathogenRemoteQuery?.value || "").trim();
  if (!query) {
    markFieldInvalid(elements.pathogenRemoteQuery, "pathogen_remote_query", ncbiMode === "taxid_refs" ? "请填写 TaxID。" : "请填写 NCBI accession 或下载链接。");
    renderOperationError(elements.referenceOperationResult, {
      title: "病原基因组下载缺少查询条件",
      error: ncbiMode === "taxid_refs" ? "请填写用于精选参考下载的 TaxID。" : "请填写 NCBI accession 或可访问的下载链接。",
      recovery: [ncbiMode === "taxid_refs" ? "TaxID 模式只能填写数字，例如 573。" : "例如填写 GCF/GCA accession，或填写可直接下载 FASTA 的 URL。"],
    });
    showToast("请填写病原基因组下载查询条件。", "warning");
    elements.pathogenRemoteQuery?.focus();
    return;
  }
  if (ncbiMode === "taxid_refs" && !/^\d+$/.test(query)) {
    markFieldInvalid(elements.pathogenRemoteQuery, "pathogen_remote_query", "TaxID 只能填写数字。");
    renderOperationError(elements.referenceOperationResult, {
      title: "TaxID 格式不正确",
      error: "TaxID 模式只接受数字。",
      recovery: ["请填写 NCBI Taxonomy ID，例如 Klebsiella pneumoniae 可使用 573。"],
      metrics: [{ label: "当前输入", value: query }],
    });
    showToast("TaxID 格式不正确，请填写数字。", "warning");
    elements.pathogenRemoteQuery?.focus();
    return;
  }
  return withSubmittingState(submitButton, "提交中...", async () => {
  const maxGenomes = Math.max(1, Math.min(200, Number(elements.pathogenRemoteTaxidMaxGenomes?.value || 20) || 20));
  const payload = {
    provider: elements.pathogenRemoteProvider?.value.trim() || "ncbi",
    ncbi_mode: ncbiMode,
    genome_name: elements.pathogenRemoteName?.value.trim() || "",
    query,
    max_genomes: maxGenomes,
    source_label: elements.pathogenRemoteSourceLabel?.value.trim() || "",
    description: elements.pathogenRemoteDescription?.value.trim() || "",
  };
  closePathogenRemoteImportModal();
  try {
    await requestJson("/api/pathogen-database/remote-import", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    showToast(`已提交病原参考基因组下载任务：${payload.genome_name || payload.query}`);
    renderOperationResult(elements.referenceOperationResult, {
      title: "病原基因组下载任务已提交",
      message: "下载与导入会在后台执行，完成后刷新参考库即可查看记录。",
      metrics: [
        { label: "来源平台", value: payload.provider },
        { label: "下载对象", value: payload.genome_name || payload.query || "-" },
      ],
    });
    await loadDatabaseRecords();
  } catch (error) {
    throw error;
  }
  });
}

async function onSubmitReferenceBatchImport(event) {
  event.preventDefault();
  const upload = elements.referenceBatchImportFile?.files?.[0];
  if (!validateImportFile(upload, {
    allowedExtensions: SPREADSHEET_IMPORT_EXTENSIONS,
    label: "参考基因组批量导入文件",
    target: elements.referenceOperationResult,
    recovery: ["建议下载当前页面的模板后重新填写。"],
  })) {
    showToast("请先选择批量导入文件", "warning");
    return;
  }
  const category = state.currentReferenceBatchCategory === "pathogen" ? "pathogen" : "host";
  if (!state.referenceBatchImportPrecheckId) {
    setButtonEnabled(elements.submitReferenceBatchImportButton, false);
    renderOperationError(elements.referenceBatchImportPrecheck, {
      title: "参考基因组批量导入被拦截",
      error: "当前文件没有通过后端预检，不能开始正式导入。",
      recovery: ["请修正预检报告中的问题后重新选择文件。", "只有后端预检通过并生成预检快照后，按钮才会放行。"],
      metrics: [
        { label: "导入文件", value: upload.name },
        { label: "导入类型", value: category === "host" ? "宿主基因组" : "病原基因组" },
      ],
    });
    showToast("预检未通过，已拦截批量导入", "warning");
    return;
  }
  const formData = new FormData();
  formData.append("file", upload);
  if (state.referenceBatchImportPrecheckId) {
    formData.append("precheck_id", state.referenceBatchImportPrecheckId);
  }
  const endpoint = category === "host" ? "/api/host-database/batch-import" : "/api/pathogen-database/batch-import";
  const submitButton = event.currentTarget?.querySelector?.('button[type="submit"]');
  await withSubmittingState(submitButton, "导入中...", () => withOperationRecovery(
    elements.referenceOperationResult,
    {
      title: "参考基因组批量导入失败",
      recovery: [
        "请使用当前页面下载的最新模板，避免字段名或说明行被破坏。",
        "确认 FASTA 路径存在，或确认上传文件格式为 xlsx、csv、tsv。",
        "如果提示重复记录，可先在列表中搜索并编辑已有记录。",
      ],
      metrics: [
        { label: "导入文件", value: upload.name },
        { label: "导入类型", value: category === "host" ? "宿主基因组" : "病原基因组" },
      ],
    },
    async () => {
    const data = await requestJson(endpoint, {
      method: "POST",
      body: formData,
    });
    const importedCount = Number(data.imported_count || 0);
    const skippedCount = Number(data.skipped_count || 0);
    const subject = category === "host" ? "宿主基因组" : "病原基因组";
    showToast(`批量导入${subject}完成：成功 ${importedCount} 条，跳过 ${skippedCount} 条`);
    renderOperationResult(elements.referenceOperationResult, {
      title: `批量导入${subject}完成`,
      status: skippedCount ? "warning" : "success",
      message: skippedCount ? "部分参考记录被跳过，请检查模板字段或重复记录。" : "参考基因组记录已写入对应数据库。",
      metrics: [
        { label: "成功导入", value: importedCount },
        { label: "跳过记录", value: skippedCount },
        { label: "导入类型", value: subject },
      ],
    });
    closeReferenceBatchImportModal();
    await loadDatabaseRecords();
    }
  ));
}

async function onBuildPathogenDatabaseIndex(event) {
  const selectedHostKeys = Object.entries(state.pathogenReferenceSelection || {})
    .filter(([, selected]) => Boolean(selected))
    .map(([key]) => key);
  const button = event?.currentTarget || elements.buildPathogenIndexButton;
  await withSubmittingState(button, "构建中...", () => withOperationRecovery(
    elements.referenceOperationResult,
    {
      title: "病原数据库 Index 构建失败",
      recovery: [
        "确认选中或全部病原 FASTA 文件存在，并且没有空路径记录。",
        "检查后台管理中的脚本路径、Conda 环境和数据库根目录。",
        "如果只是一条记录失败，可以先编辑或删除该记录后再重新构建。",
      ],
      metrics: [{ label: "构建对象", value: selectedHostKeys.length || "全部" }],
    },
    async () => {
    const result = await requestJson("/api/pathogen-database/build-index", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(selectedHostKeys.length ? { host_keys: selectedHostKeys } : {}),
    });
    state.pathogenDatabaseRecords = result.items || [];
    if (selectedHostKeys.length) {
      state.pathogenReferenceSelection = {};
    }
    renderPathogenDatabaseRecords();
    showToast(result.message || (selectedHostKeys.length ? "已完成选中病原参考的 Index 构建" : "病原基因组数据库索引构建完成"));
    renderOperationResult(elements.referenceOperationResult, {
      title: selectedHostKeys.length ? "选中病原参考 Index 构建完成" : "病原数据库 Index 构建完成",
      message: result.message || "病原参考基因组索引已更新，可用于后续比对和溯源分析。",
      metrics: [
        { label: "构建对象", value: selectedHostKeys.length || "全部" },
        { label: "病原记录", value: state.pathogenDatabaseRecords.length },
      ],
    });
    }
  ));
}

