async function onSubmitDatabaseBatchImport(event) {
  event.preventDefault();
  const upload = elements.databaseBatchImportFile?.files?.[0];
  if (!validateImportFile(upload, {
    allowedExtensions: SPREADSHEET_IMPORT_EXTENSIONS,
    label: "样本批量导入文件",
    target: elements.databaseOperationResult,
    recovery: ["建议下载当前页面的样本导入模板，确认字段名和说明页没有被改写。"],
  })) {
    showToast("请先选择批量导入文件", "warning");
    return;
  }
  if (!state.databaseBatchImportPrecheckId) {
    setButtonEnabled(elements.submitDatabaseBatchImportButton, false);
    renderOperationError(elements.databaseBatchImportPrecheck, {
      title: "样本批量导入被拦截",
      error: "当前文件没有通过后端预检，不能开始正式导入。",
      recovery: ["请修正预检报告中的问题后重新选择文件。", "只有后端预检通过并生成预检快照后，按钮才会放行。"],
      metrics: [{ label: "导入文件", value: upload.name }],
    });
    showToast("预检未通过，已拦截批量导入", "warning");
    return;
  }
  const formData = new FormData();
  formData.append("file", upload);
  if (state.databaseBatchImportPrecheckId) {
    formData.append("precheck_id", state.databaseBatchImportPrecheckId);
  }
  formData.append("library_scope", state.databaseLibraryScope);
  const submitButton = event.currentTarget?.querySelector?.('button[type="submit"]');
  return withSubmittingState(submitButton, "导入中...", () => withOperationRecovery(
    elements.databaseOperationResult,
    {
      title: "批量样本导入失败",
      recovery: [
        "优先下载最新导入模板，确认字段名没有被改写。",
        "检查 sample_name、final_fasta_path 和主档必填字段是否完整。",
        "如果是路径问题，请确认服务器进程能访问表格中的文件路径。",
      ],
      metrics: [
        { label: "导入文件", value: upload.name },
        { label: "库范围", value: state.databaseLibraryScope === "personal" ? "个人数据库" : "主数据库" },
      ],
    },
    async () => {
    const data = await requestJson("/api/database/batch-import", {
      method: "POST",
      body: formData,
    });
    const importedCount = Number(data.imported_count || 0);
    const skippedCount = Number(data.skipped_count || 0);
    showToast(`批量导入完成：成功 ${importedCount} 条，跳过 ${skippedCount} 条`);
    renderOperationResult(elements.databaseOperationResult, {
      title: "批量样本导入完成",
      status: skippedCount ? "warning" : "success",
      message: skippedCount ? "部分记录被跳过，请根据导入文件和后端提示复核字段。" : "所有可导入记录已写入样本数据库。",
      metrics: [
        { label: "成功导入", value: importedCount },
        { label: "跳过记录", value: skippedCount },
        { label: "库范围", value: state.databaseLibraryScope === "personal" ? "个人数据库" : "主数据库" },
      ],
      dismissible: true,
      dismissLabel: "关闭",
    });
    closeDatabaseBatchImportModal();
    await loadDatabaseRecords();
    return data;
    }
  ));
}

