function renderUsageMetric(label, percent, detail) {
  const normalized = Number.isFinite(Number(percent)) ? Math.max(0, Math.min(100, Number(percent))) : 0;
  const severity = getUsageSeverity(percent);
  return `
    <div class="usage-metric-card usage-metric-${severity.tone}">
      <div class="usage-metric-head">
        <span>${escapeHtml(label)}</span>
        <b class="usage-metric-badge usage-metric-badge-${severity.tone}">${escapeHtml(severity.label)}</b>
      </div>
      <strong>${escapeHtml(formatPercent(percent))}</strong>
      <div class="usage-meter" aria-hidden="true">
        <div class="usage-meter-fill usage-meter-fill-${severity.tone}" style="width:${normalized}%"></div>
      </div>
      <small>${escapeHtml(detail || "-")}</small>
    </div>
  `;
}

function renderServerSummaryStat(label, value, note) {
  return `
    <article>
      <span>${escapeHtml(label)}</span>
      <strong>${escapeHtml(value || "-")}</strong>
      <small>${escapeHtml(note || "-")}</small>
    </article>
  `;
}

function renderServerDetailItem(label, value, isLong = false) {
  return `
    <div>
      <span>${escapeHtml(label)}</span>
      <strong class="${isLong ? "server-detail-value server-detail-value-long" : "server-detail-value"}">${escapeHtml(value || "-")}</strong>
    </div>
  `;
}

function getUsageSeverity(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return { tone: "neutral", label: "未知", rank: 0 };
  }
  if (numeric >= 85) return { tone: "critical", label: "偏高", rank: 3 };
  if (numeric >= 65) return { tone: "warning", label: "关注", rank: 2 };
  return { tone: "healthy", label: "平稳", rank: 1 };
}

function formatPercent(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return "-";
  return `${numeric.toFixed(1)}%`;
}

function formatCompactPercent(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return "0%";
  return `${numeric.toFixed(numeric >= 100 || Number.isInteger(numeric) ? 0 : 1)}%`;
}

function truncateText(value, maxLength) {
  const text = String(value || "").trim();
  if (!text) return "";
  return text.length > maxLength ? `${text.slice(0, maxLength)}...` : text;
}

function renderMobileCellAttributes(label, role = "") {
  const labelAttr = label ? ` data-label="${escapeHtml(label)}"` : "";
  const roleAttr = role ? ` data-cell-role="${escapeHtml(role)}"` : "";
  return `${labelAttr}${roleAttr}`;
}

function buildRoleLabel(role) {
  if (role === "admin") return "管理员";
  if (role === "group_admin") return "group 管理";
  return "普通用户";
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function statusClassName(status) {
  return String(status || "").toLowerCase();
}

function statusLabel(status) {
  const map = {
    QUEUED: "排队中",
    RUNNING: "运行中",
    PAUSED: "已暂停",
    SUCCEEDED: "已完成",
    FAILED: "失败",
    STOPPED: "已停止",
  };
  return map[String(status || "").toUpperCase()] || String(status || "未知");
}

function normalizeToastVariant(variant = "success") {
  if (variant === true || variant === "error" || variant === "danger") return "error";
  if (variant === "warning" || variant === "warn") return "warning";
  if (variant === "info" || variant === "neutral") return "info";
  return "success";
}

function getToastTitle(variant) {
  const titles = {
    success: "已完成",
    warning: "需要确认",
    error: "未完成",
    info: "提示",
  };
  return titles[variant] || titles.success;
}

function showToast(message, variant = "success") {
  if (!elements.toast) return;
  const tone = normalizeToastVariant(variant);
  elements.toast.className = `toast toast-${tone}`;
  elements.toast.innerHTML = `
    <strong>${escapeHtml(getToastTitle(tone))}</strong>
    <span>${escapeHtml(message)}</span>
  `;
  elements.toast.classList.remove("hidden");
  window.clearTimeout(showToast.timer);
  showToast.timer = window.setTimeout(() => elements.toast.classList.add("hidden"), 2600);
}

function setTextContentById(id, value) {
  const node = document.getElementById(id);
  if (node) node.textContent = String(value || "");
}

function closeConfirmActionModal(result = false) {
  const modal = document.getElementById("confirm-action-modal");
  if (!modal) return;
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
  document.body.classList.remove("modal-scroll-locked");
  if (typeof closeConfirmActionModal.resolve === "function") {
    const resolve = closeConfirmActionModal.resolve;
    closeConfirmActionModal.resolve = null;
    resolve(Boolean(result));
  }
}

function confirmDangerAction({
  title = "确认操作",
  message = "请确认是否继续。",
  impact = "继续后将执行当前操作",
  detail = "该操作可能影响当前数据，请确认后再继续。",
  confirmLabel = "确认继续",
  cancelLabel = "取消",
  tone = "danger",
} = {}) {
  const modal = document.getElementById("confirm-action-modal");
  if (!modal) {
    showToast("确认弹窗未能加载，当前操作已取消。", "error");
    return Promise.resolve(false);
  }
  if (typeof closeConfirmActionModal.resolve === "function") {
    closeConfirmActionModal(false);
  }
  const panel = modal.querySelector(".confirm-action-panel");
  panel?.classList.toggle("is-warning", tone === "warning");
  setTextContentById("confirm-action-kicker", tone === "warning" ? "Confirm" : "Danger Zone");
  setTextContentById("confirm-action-title", title);
  setTextContentById("confirm-action-message", message);
  setTextContentById("confirm-action-level", tone === "warning" ? "覆盖操作" : "危险操作");
  setTextContentById("confirm-action-impact", impact);
  setTextContentById("confirm-action-detail", detail);
  setTextContentById("confirm-action-confirm", confirmLabel);
  setTextContentById("confirm-action-cancel", cancelLabel);
  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-scroll-locked");
  document.getElementById("confirm-action-confirm")?.focus({ preventScroll: true });
  return new Promise((resolve) => {
    closeConfirmActionModal.resolve = resolve;
  });
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function rectWidth(node) {
  return node.getBoundingClientRect().width || node.offsetWidth || 0;
}

function rectHeight(node) {
  return node.getBoundingClientRect().height || node.offsetHeight || 0;
}

