function setAdminPipelinePython(absolutePath) {
  if (elements.adminPipelinePython) {
    elements.adminPipelinePython.value = absolutePath || "";
  }
  rememberPathBrowserLocation("pipeline_python", getParentDirectory(absolutePath) || absolutePath || "");
}

function setAdminScriptPath(absolutePath) {
  const workspaceRoot = elements.adminWorkspaceRoot.value.trim();
  if (!workspaceRoot) {
    showToast("请先选择部署基准目录。", "warning");
    return;
  }
  if (!absolutePath.startsWith(workspaceRoot)) {
    showToast("脚本文件必须位于部署基准目录内。", "warning");
    return;
  }
  const relative = absolutePath.slice(workspaceRoot.length).replace(/^[/\\\\]+/, "");
  elements.adminPipelineScript.value = relative || "";
  rememberPathBrowserLocation("script_file", getParentDirectory(absolutePath) || absolutePath || "");
}

function collectAdminCondaEnvValues() {
  return Object.fromEntries(
    ADMIN_CONDA_ENV_FIELDS.map((key) => [key, elements.adminCondaEnvInputs?.[key]?.value?.trim() || ""])
  );
}

function buildCondaEnvOptions(currentValue = "", { preserveCustom = true } = {}) {
  const detected = Array.isArray(state.detectedCondaEnvs) ? state.detectedCondaEnvs.filter(Boolean) : [];
  const normalizedCurrent = String(currentValue || "").trim();
  const options = [...detected];
  if (preserveCustom && normalizedCurrent && !options.includes(normalizedCurrent)) {
    options.unshift(normalizedCurrent);
  }
  return { detected, options, currentValue: normalizedCurrent };
}

function renderCondaEnvOptions(select, currentValue = "", { preserveCustom = true } = {}) {
  if (!(select instanceof HTMLSelectElement)) return;
  const envOptions = buildCondaEnvOptions(currentValue || select.value || "", { preserveCustom });
  const { detected, options, currentValue: normalizedCurrent } = envOptions;
  if (!options.length) {
    select.innerHTML = `<option value="">未识别到环境</option>`;
    select.disabled = true;
    return;
  }
  select.disabled = false;
  select.innerHTML = options
    .map((item, index) => {
      const custom = normalizedCurrent && index === 0 && item === normalizedCurrent && !detected.includes(normalizedCurrent);
      const label = custom ? `${item}（当前值）` : item;
      return `<option value="${escapeHtml(item)}">${escapeHtml(label)}</option>`;
    })
    .join("");
  select.value = options.includes(normalizedCurrent) ? normalizedCurrent : (options[0] || "");
}

function rebuildAdminPipelineEnvSelectOptions(currentValue = "") {
  renderCondaEnvOptions(elements.adminPipelinePython, currentValue, { preserveCustom: false });
}

function rebuildAdminCondaEnvSelectOptions(currentValues = {}) {
  ADMIN_CONDA_ENV_FIELDS.forEach((key) => {
    const select = elements.adminCondaEnvInputs?.[key];
    const currentValue = String(currentValues[key] || select.value || "").trim();
    renderCondaEnvOptions(select, currentValue);
  });
}

function applyAdminCondaEnvValues(values = {}) {
  rebuildAdminCondaEnvSelectOptions(values);
  ADMIN_CONDA_ENV_FIELDS.forEach((key) => {
    const input = elements.adminCondaEnvInputs?.[key];
    if (!input) return;
    const value = String(values[key] || "");
    if (value) {
      input.value = value;
    }
  });
}

function renderAdminDetectedCondaEnvs() {
  rebuildAdminPipelineEnvSelectOptions(elements.adminPipelinePython?.value || "");
  rebuildAdminCondaEnvSelectOptions(collectAdminCondaEnvValues());
}

async function refreshAdminCondaEnvsForRoot({ announce = false } = {}) {
  const root = String(elements.adminCondaRoot?.value || "").trim();
  if (!root) {
    showToast("请先选择 Conda 安装路径。", "warning");
    return;
  }
  const currentPipelineEnv = elements.adminPipelinePython?.value || "";
  const currentMappedEnvs = collectAdminCondaEnvValues();
  const params = new URLSearchParams({ root });
  const data = await requestJson(`/api/admin/conda-envs?${params.toString()}`);
  if (elements.adminCondaRoot && data.conda_root) {
    elements.adminCondaRoot.value = data.conda_root;
  }
  state.detectedCondaEnvs = Array.isArray(data.detected_conda_envs) ? data.detected_conda_envs : [];
  rebuildAdminPipelineEnvSelectOptions(currentPipelineEnv);
  applyAdminCondaEnvValues(currentMappedEnvs);
  renderAdminDetectedCondaEnvs();
  if (announce) {
    showToast(state.detectedCondaEnvs.length ? `已识别 ${state.detectedCondaEnvs.length} 个 Conda 环境` : "未识别到 Conda 环境", state.detectedCondaEnvs.length ? "success" : "warning");
  }
}

function syncAdminMonitorModuleState() {
  elements.adminMonitorModuleInputs.forEach((input) => {
    const key = String(input.dataset.monitorModule || "");
    const card = document.querySelector(`[data-monitor-module-card="${key}"]`);
    const checked = input instanceof HTMLInputElement ? input.checked : false;
    card?.classList.toggle("is-selected", checked);
  });
}

function getAdminMonitorPresetDefaults(moduleKey = "", presetKey = "") {
  const modulePresets = ADMIN_MONITOR_PRESET_VALUES[String(moduleKey || "").trim()] || {};
  const preset = modulePresets[String(presetKey || "").trim()] || {};
  return { ...preset };
}

function getAdminMonitorVirusGroupSelect() {
  const field = document.getElementById("admin-monitor-virus-group-select");
  return field instanceof HTMLSelectElement ? field : null;
}

function getAdminMonitorVirusGroupBySpecies(speciesValue = "") {
  const speciesField = document.querySelector('[data-monitor-module-key="virus"][data-monitor-param="species"]');
  if (!(speciesField instanceof HTMLSelectElement)) return "all";
  const normalizedSpecies = String(speciesValue || "").trim();
  if (!normalizedSpecies) return "all";
  const option = Array.from(speciesField.options).find((item) => String(item.value || "").trim() === normalizedSpecies);
  const group = option?.parentElement instanceof HTMLOptGroupElement ? String(option.parentElement.dataset.monitorVirusOptionGroup || "").trim() : "";
  return group || "all";
}

function syncAdminMonitorVirusGroupFilter(activeGroup = null) {
  const editor = document.querySelector('[data-monitor-preset-editor="virus"]');
  const speciesField = document.querySelector('[data-monitor-module-key="virus"][data-monitor-param="species"]');
  const groupField = getAdminMonitorVirusGroupSelect();
  if (!(editor instanceof HTMLElement) || !(speciesField instanceof HTMLSelectElement)) return;
  const normalizedGroup = String(activeGroup || groupField?.value || editor.dataset.activeVirusGroup || "all").trim() || "all";
  editor.dataset.activeVirusGroup = normalizedGroup;
  if (groupField && groupField.value !== normalizedGroup) {
    groupField.value = normalizedGroup;
  }
  const optionGroups = Array.from(speciesField.querySelectorAll("optgroup[data-monitor-virus-option-group]"));
  let selectedVisible = false;
  optionGroups.forEach((group) => {
    const groupKey = String(group.dataset.monitorVirusOptionGroup || "").trim();
    const visible = normalizedGroup === "all" || groupKey === normalizedGroup;
    group.disabled = !visible;
    group.hidden = !visible;
    Array.from(group.querySelectorAll("option")).forEach((option) => {
      option.disabled = !visible;
      option.hidden = !visible;
      if (visible && option.selected) {
        selectedVisible = true;
      }
    });
  });
  const blankOption = speciesField.querySelector('option[value=""]');
  if (blankOption instanceof HTMLOptionElement) {
    blankOption.hidden = false;
    blankOption.disabled = false;
  }
  if (!selectedVisible && String(speciesField.value || "").trim()) {
    speciesField.value = "";
  }
}

function syncAdminMonitorVirusGroupBySpecies() {
  const speciesField = document.querySelector('[data-monitor-module-key="virus"][data-monitor-param="species"]');
  const groupField = getAdminMonitorVirusGroupSelect();
  if (!(speciesField instanceof HTMLSelectElement) || !(groupField instanceof HTMLSelectElement)) return;
  const nextGroup = getAdminMonitorVirusGroupBySpecies(speciesField.value || "");
  if (groupField.value !== nextGroup) {
    groupField.value = nextGroup;
  }
  syncAdminMonitorVirusGroupFilter(nextGroup);
}

function syncAdminMonitorPresetConfig(moduleKey = "", force = false) {
  const normalizedKey = String(moduleKey || "").trim();
  if (!normalizedKey) return;
  const presetSelect = document.querySelector(`[data-monitor-preset="${normalizedKey}"]`);
  const editor = document.querySelector(`[data-monitor-preset-editor="${normalizedKey}"]`);
  if (!(presetSelect instanceof HTMLSelectElement) || !(editor instanceof HTMLElement)) return;
  const config = getAdminMonitorPresetDefaults(normalizedKey, presetSelect.value || "");
  editor.querySelectorAll("[data-monitor-param]").forEach((field) => {
    if (!(field instanceof HTMLInputElement || field instanceof HTMLSelectElement)) return;
    const paramKey = String(field.dataset.monitorParam || "").trim();
    if (!paramKey) return;
    const hasConfigValue = Object.prototype.hasOwnProperty.call(config, paramKey);
    const fallbackValue = paramKey === "thread" ? 10 : "";
    const nextValue = hasConfigValue ? config[paramKey] : fallbackValue;
    if (force || field.dataset.userEdited !== "1") {
      field.value = nextValue === undefined || nextValue === null ? "" : String(nextValue);
      field.dataset.userEdited = "0";
    }
    const row = field.closest(".admin-monitor-field");
    if (row instanceof HTMLElement && paramKey === "runflow") {
      row.classList.toggle("hidden", !hasConfigValue && !String(field.value || "").trim());
    }
  });
  if (normalizedKey === "virus") {
    syncAdminMonitorVirusGroupFilter();
  }
}

function collectAdminMonitorModules() {
  return elements.adminMonitorModuleInputs
    .filter((input) => input instanceof HTMLInputElement && input.checked)
    .map((input) => {
      const key = String(input.dataset.monitorModule || "");
      const preset = document.querySelector(`[data-monitor-preset="${key}"]`);
      const presetFields = Array.from(document.querySelectorAll(`[data-monitor-module-key="${key}"][data-monitor-param]`));
      const moduleInput = document.getElementById(`admin-monitor-input-dir-${key}`);
      const moduleOutput = document.getElementById(`admin-monitor-output-root-${key}`);
      let presetOverrides = {};
      presetFields.forEach((field) => {
        if (!(field instanceof HTMLInputElement || field instanceof HTMLSelectElement)) return;
        const paramKey = String(field.dataset.monitorParam || "").trim();
        if (!paramKey) return;
        if (field instanceof HTMLInputElement && field.type === "number") {
          const value = String(field.value || "").trim();
          if (!value) return;
          presetOverrides[paramKey] = Number(value);
          return;
        }
        presetOverrides[paramKey] = String(field.value || "");
      });
      return {
        key,
        preset: preset instanceof HTMLSelectElement ? String(preset.value || "").trim() : "",
        preset_overrides: presetOverrides,
        input_path: moduleInput instanceof HTMLInputElement ? String(moduleInput.value || "").trim() : "",
        output_root: moduleOutput instanceof HTMLInputElement ? String(moduleOutput.value || "").trim() : "",
      };
    })
    .filter((item) => item.key);
}

function validateAdminMonitorModules(modules) {
  const virusModule = modules.find((item) => String(item?.key || "").trim() === "virus");
  if (!virusModule) return;
  const species = String(virusModule?.preset_overrides?.species || "").trim();
  if (!species) {
    throw new Error("请先为病毒分析选择目标病毒。");
  }
}

function renderAdminMonitorResult(result, isError = false) {
  if (!elements.adminMonitorResult) return;
	  if (!result) {
	    elements.adminMonitorResult.className = "admin-monitor-result empty-state";
	    elements.adminMonitorResult.innerHTML = renderEmptyState({
	      title: "尚未创建实时监控任务",
	      reason: "当前还没有提交目录监听配置。",
	      action: "选择测序目录、输出目录和分析模块后，点击创建即可生成监听任务。",
	    });
	    return;
	  }
  const items = Array.isArray(result.items) ? result.items : [];
  elements.adminMonitorResult.className = `admin-monitor-result${isError ? " error" : " success"}`;
  if (isError) {
    elements.adminMonitorResult.innerHTML = `<strong>创建失败</strong><p>${escapeHtml(result.message || "实时监控任务创建失败。")}</p>`;
    return;
  }
  elements.adminMonitorResult.innerHTML = `
    <strong>已创建 ${items.length} 个实时监控任务</strong>
    <div class="admin-monitor-result-list">
      ${items.map((item) => {
        const moduleLabel = WORKSTATION_LABELS[String(item.workstation_key || "").trim()] || String(item.workstation_key || "").trim() || "分析任务";
        return `
          <article>
            <span>${escapeHtml(moduleLabel)}</span>
            <strong>${escapeHtml(item.name || item.id || "未命名任务")}</strong>
            <p>${escapeHtml(String(item.watch_label || "监听中 · 等待测序数据写入"))}</p>
          </article>
        `;
      }).join("")}
    </div>
  `;
}

function renderAdminMonitorTaskList() {
  if (!elements.adminMonitorTaskList) return;
  const watchTasks = (Array.isArray(state.tasks) ? state.tasks : [])
    .filter((task) => {
      const watchModeEnabled = String(task.params?.watch_mode || "0") === "1";
      const watch = task.watch && typeof task.watch === "object" ? task.watch : null;
      const hasActiveWatchState = Boolean(
        watch?.enabled
        || String(watch?.state || "").trim()
        || String(watch?.input_dir || "").trim()
        || String(task.params?.watch_input_path || "").trim(),
      );
      return watchModeEnabled || hasActiveWatchState;
    })
    .sort((left, right) => String(right.created_at || "").localeCompare(String(left.created_at || "")));
	  if (!watchTasks.length) {
	    elements.adminMonitorTaskList.innerHTML = renderEmptyState({
	      title: "当前没有实时监控任务",
	      reason: "任务队列中还没有启用目录监听的分析任务。",
	      action: "在上方选择测序目录和分析模块后，系统会在这里展示监听状态、稳定时长和已识别样本数。",
	    });
	    return;
	  }
  elements.adminMonitorTaskList.innerHTML = watchTasks.map((task) => {
    const watch = task.watch || {};
    const moduleKey = String(task.params?.workstation_key || "").trim();
    const moduleLabel = WORKSTATION_LABELS[moduleKey] || moduleKey || "分析任务";
    const statusClass = String(task.status || "").toLowerCase();
    const stableMinutes = Number(watch.stable_minutes || task.params?.watch_stable_minutes || 0);
    const sampleCount = Number(watch.sample_count || 0);
    const preview = Array.isArray(watch.sample_preview) ? watch.sample_preview.filter(Boolean).slice(0, 4) : [];
    return `
      <article class="admin-monitor-task-card">
        <div class="admin-monitor-task-head">
          <div>
            <span>${escapeHtml(moduleLabel)}</span>
            <strong>${escapeHtml(task.name || task.id || "未命名任务")}</strong>
          </div>
          <span class="status-chip ${escapeHtml(statusClass || "queued")}">${escapeHtml(task.status || "QUEUED")}</span>
        </div>
        <div class="admin-monitor-task-grid">
          <div>
            <span>监听状态</span>
            <strong>${escapeHtml(String(watch.label || "监听中 · 等待测序数据写入"))}</strong>
            <p>${escapeHtml(String(watch.message || "系统会在目录稳定后自动生成批量输入并开始分析。"))}</p>
          </div>
          <div>
            <span>稳定判定</span>
            <strong>${escapeHtml(stableMinutes ? `${stableMinutes} 分钟` : "-")}</strong>
            <p>${escapeHtml(`轮询间隔 ${task.params?.watch_poll_minutes || watch.poll_minutes || "-"} 分钟`)}</p>
          </div>
          <div>
            <span>已识别样本</span>
            <strong>${escapeHtml(String(sampleCount || 0))}</strong>
            <p>${preview.length ? escapeHtml(preview.join("、")) : "尚未识别到样本"}</p>
          </div>
        </div>
      </article>
    `;
  }).join("");
}

function splitAdminTriggerTextarea(value) {
  return String(value || "")
    .split(/\r?\n/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function collectAdminPathosourceTriggerRules() {
  return {
    enabled: Boolean(elements.adminPathosourceTriggerEnabled?.checked),
    priority_only: Boolean(elements.adminPathosourceTriggerPriorityOnly?.checked),
    auto_start: Boolean(elements.adminPathosourceTriggerAutoStart?.checked),
    min_abundance_percent: Number(elements.adminPathosourceTriggerMinAbundance?.value || 0),
    min_support_reads: Number(elements.adminPathosourceTriggerMinReads?.value || 0),
    min_coverage_percent: Number(elements.adminPathosourceTriggerMinCoverage?.value || 0),
    max_reference_genomes: Number(elements.adminPathosourceTriggerMaxGenomes?.value || 1),
    msa_method: String(elements.adminPathosourceTriggerMsaMethod?.value || "snippy"),
    tree_method: String(elements.adminPathosourceTriggerTreeMethod?.value || "ML"),
    allowed_sample_sources: splitAdminTriggerTextarea(elements.adminPathosourceTriggerSampleSources?.value || ""),
    priority_species: splitAdminTriggerTextarea(elements.adminPathosourceTriggerPrioritySpecies?.value || ""),
    excluded_species: splitAdminTriggerTextarea(elements.adminPathosourceTriggerExcludedSpecies?.value || ""),
  };
}

function renderAdminPathosourceTriggerSummary(rules) {
  if (!elements.adminPathosourceTriggerSummary) return;
  const enabled = Boolean(rules?.enabled);
  const priorityOnly = Boolean(rules?.priority_only);
  const sampleSources = Array.isArray(rules?.allowed_sample_sources) ? rules.allowed_sample_sources : [];
  const prioritySpecies = Array.isArray(rules?.priority_species) ? rules.priority_species : [];
  elements.adminPathosourceTriggerSummary.innerHTML = `
    <span>当前状态</span>
    <strong>${enabled ? "已启用自动溯源" : "未启用自动溯源"}</strong>
    <p>${enabled
      ? `触发阈值为丰度 ${Number(rules?.min_abundance_percent || 0).toFixed(1)}%、支持 reads ${Number(rules?.min_support_reads || 0)}、覆盖度 ${Number(rules?.min_coverage_percent || 0).toFixed(1)}%。`
      : "当前只保存配置，不会从宏基因组任务自动派生溯源子任务。"}</p>
    <p>${priorityOnly
      ? `仅对 ${prioritySpecies.length || 0} 个重点病原启用自动触发。`
      : `样本来源${sampleSources.length ? `限定为 ${sampleSources.slice(0, 3).join("、")}${sampleSources.length > 3 ? " 等" : ""}` : "不限"}。`}</p>
  `;
}

function renderAdminPathosourceTriggerResult(message, isError = false) {
  if (!elements.adminPathosourceTriggerResult) return;
  elements.adminPathosourceTriggerResult.className = `admin-monitor-result${isError ? " error" : " success"}`;
  elements.adminPathosourceTriggerResult.innerHTML = `
    <strong>${isError ? "保存失败" : "规则已保存"}</strong>
    <p>${escapeHtml(message || (isError ? "自动溯源触发规则保存失败。" : "新的自动溯源触发规则已写入服务端。"))}</p>
  `;
}

function applyAdminPathosourceTriggerRules(rawRules) {
  const rules = {
    ...ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS,
    ...(rawRules || {}),
  };
  if (elements.adminPathosourceTriggerEnabled) {
    elements.adminPathosourceTriggerEnabled.checked = Boolean(rules.enabled);
  }
  if (elements.adminPathosourceTriggerPriorityOnly) {
    elements.adminPathosourceTriggerPriorityOnly.checked = Boolean(rules.priority_only);
  }
  if (elements.adminPathosourceTriggerAutoStart) {
    elements.adminPathosourceTriggerAutoStart.checked = Boolean(rules.auto_start);
  }
  if (elements.adminPathosourceTriggerMinAbundance) {
    elements.adminPathosourceTriggerMinAbundance.value = String(rules.min_abundance_percent ?? ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.min_abundance_percent);
  }
  if (elements.adminPathosourceTriggerMinReads) {
    elements.adminPathosourceTriggerMinReads.value = String(rules.min_support_reads ?? ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.min_support_reads);
  }
  if (elements.adminPathosourceTriggerMinCoverage) {
    elements.adminPathosourceTriggerMinCoverage.value = String(rules.min_coverage_percent ?? ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.min_coverage_percent);
  }
  if (elements.adminPathosourceTriggerMaxGenomes) {
    elements.adminPathosourceTriggerMaxGenomes.value = String(rules.max_reference_genomes ?? ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.max_reference_genomes);
  }
  if (elements.adminPathosourceTriggerMsaMethod) {
    elements.adminPathosourceTriggerMsaMethod.value = String(rules.msa_method || ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.msa_method);
  }
  if (elements.adminPathosourceTriggerTreeMethod) {
    elements.adminPathosourceTriggerTreeMethod.value = String(rules.tree_method || ADMIN_PATHOSOURCE_TRIGGER_DEFAULTS.tree_method);
  }
  if (elements.adminPathosourceTriggerSampleSources) {
    elements.adminPathosourceTriggerSampleSources.value = (Array.isArray(rules.allowed_sample_sources) ? rules.allowed_sample_sources : []).join("\n");
  }
  if (elements.adminPathosourceTriggerPrioritySpecies) {
    elements.adminPathosourceTriggerPrioritySpecies.value = (Array.isArray(rules.priority_species) ? rules.priority_species : []).join("\n");
  }
  if (elements.adminPathosourceTriggerExcludedSpecies) {
    elements.adminPathosourceTriggerExcludedSpecies.value = (Array.isArray(rules.excluded_species) ? rules.excluded_species : []).join("\n");
  }
  state.adminPathosourceTriggerSnapshot = JSON.stringify(collectAdminPathosourceTriggerRules());
  renderAdminPathosourceTriggerSummary(rules);
}

async function onSaveAdminPathosourceTriggerRules(event) {
  event.preventDefault();
  const payload = collectAdminPathosourceTriggerRules();
  const submitButton = event.currentTarget?.querySelector?.('button[type="submit"]');
  await withSubmittingState(submitButton, "保存中...", async () => {
    const data = await requestJson("/api/admin/pathosource-trigger-rules", {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    applyAdminPathosourceTriggerRules(data || payload);
    renderAdminPathosourceTriggerResult("后续自动溯源流程会按这套阈值和名单执行。");
    showToast("自动溯源触发规则已保存");
  });
}

function getAdminSettingsDraft() {
  return {
    workspace_root: elements.adminWorkspaceRoot?.value?.trim() || "",
    pipeline_script: elements.adminPipelineScript?.value?.trim() || "",
    pipeline_python: elements.adminPipelinePython?.value?.trim() || "",
    conda_root: elements.adminCondaRoot?.value?.trim() || "",
    database_root: elements.adminDatabaseRoot?.value?.trim() || "",
    max_concurrent_tasks: elements.adminMaxConcurrentTasks?.value?.trim() || "2",
    ...Object.fromEntries(
      Object.entries(collectAdminCondaEnvValues()).map(([key, value]) => [`conda_env_${key}`, value])
    ),
  };
}

function isAdminSettingsDirty() {
  if (!state.adminSettingsSnapshot) return false;
  const current = getAdminSettingsDraft();
  return Object.keys(state.adminSettingsSnapshot).some((key) => current[key] !== state.adminSettingsSnapshot[key]);
}

function renderBrowserBreadcrumbs() {
  elements.browserBreadcrumbs.replaceChildren();
  const currentPath = state.pathBrowser.currentPath || state.pathBrowser.root || "/";
  const normalized = String(currentPath || "/");
  const parts = normalized.split("/").filter(Boolean);
  const crumbs = [];

  if (state.pathBrowser.mode === "project") {
    let current = normalized.startsWith("/") ? "/" : "";
    crumbs.push({ label: "/", value: "/" });
    parts.forEach((part) => {
      current = current === "/" ? `/${part}` : current ? `${current}/${part}` : part;
      const isProjectRoot = current === state.pathBrowser.root;
      crumbs.push({ label: isProjectRoot ? "项目根目录" : part, value: current });
    });
  } else {
    let current = normalized.startsWith("/") ? "/" : "";
    crumbs.push({ label: normalized.startsWith("/") ? "/" : "根目录", value: normalized.startsWith("/") ? "/" : state.pathBrowser.root || "" });
    parts.forEach((part) => {
      current = current === "/" ? `/${part}` : current ? `${current}/${part}` : part;
      crumbs.push({ label: part, value: current });
    });
  }

  crumbs.forEach((crumb, index) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "browser-crumb";
    button.textContent = crumb.label;
    button.addEventListener("click", async () => {
      await loadBrowserDirectory(crumb.value);
    });
    elements.browserBreadcrumbs.appendChild(button);
    if (index < crumbs.length - 1) {
      const divider = document.createElement("span");
      divider.className = "browser-crumb-divider";
      divider.textContent = "/";
      elements.browserBreadcrumbs.appendChild(divider);
    }
  });
}

async function openBrowserShortcut(type) {
  if (type === "project") {
    state.pathBrowser.mode = "project";
    state.pathBrowser.root = "";
    await loadBrowserDirectory("");
    return;
  }
  if (type === "workspace") {
    const workspaceRoot = elements.adminWorkspaceRoot.value.trim();
    if (!workspaceRoot) {
      showToast("当前还没有部署基准目录。", "warning");
      return;
    }
    state.pathBrowser.mode = "admin";
    state.pathBrowser.root = workspaceRoot;
    await loadBrowserDirectory(workspaceRoot);
    return;
  }
  if (type === "home") {
    const homePath = state.pathBrowser.homePath || "/";
    state.pathBrowser.mode = "admin";
    state.pathBrowser.root = "/";
    await loadBrowserDirectory(homePath);
    return;
  }
  if (type === "desktop") {
    const desktopPath = state.pathBrowser.desktopPath || state.pathBrowser.homePath || "/";
    state.pathBrowser.mode = "admin";
    state.pathBrowser.root = "/";
    await loadBrowserDirectory(desktopPath);
  }
}

function syncBrowserShortcuts() {
  const current = state.pathBrowser.currentPath || state.pathBrowser.relativePath || "";
  const shortcuts = [
    [elements.browserShortcutProject, state.pathBrowser.mode === "project" && current === state.pathBrowser.root],
    [elements.browserShortcutWorkspace, elements.adminWorkspaceRoot.value.trim() && state.pathBrowser.mode === "admin" && current === elements.adminWorkspaceRoot.value.trim()],
    [elements.browserShortcutHome, state.pathBrowser.mode === "admin" && state.pathBrowser.homePath && current === state.pathBrowser.homePath],
    [elements.browserShortcutDesktop, state.pathBrowser.mode === "admin" && state.pathBrowser.desktopPath && current === state.pathBrowser.desktopPath],
  ];
  shortcuts.forEach(([node, active]) => {
    if (!node) return;
    node.classList.toggle("active", Boolean(active));
  });
}
